INSERT INTO public.pestel_factors (id, code, name, category, selection_reasoning, likelihood, likelihood_reasoning, impact, impact_reasoning, origin_date, trend, time_horizon, segment_relevance, affected_pillars, source_ids, is_active, last_refreshed, created_at, updated_at, is_foundational, verification_verdict, verification_source, verification_evidence, financial_context, key_dates, citations, first_seen_date, last_confirmed_date, confirmation_count) VALUES (166, 'legacy_oems_gaining_ev_2w_share_â€”_ola_electric_sli', 'Legacy OEMs Gaining EV 2W Share â€” Ola Electric Slips', 'E', 'Ather Energy''s market share rising to 19.4% (from 15%) while Ola Electric slips signals a structural shift in the 2W EV supply chain toward legacy-aligned Tier-1 suppliers. This reshapes component sourcing patterns for BMS, motors, and body electronics as established OEMs (TVS, Hero, Bajaj) scale EV platforms with known Tier-1 partners rather than vertically integrated startups.', 8, 'Ather recorded 35,736 registrations in March 2026 vs 13,332 in April 2025 â€” a 168% unit surge â€” while Ola''s share declined, per ET Auto April 2026. Hero MotoCorp scooter dispatches surged 53.18% in March 2026, confirming legacy OEM momentum.', 5, 'Tier-1 suppliers embedded with legacy OEMs gain volume as EV platforms scale; suppliers to Ola face revenue concentration risk. The 2W EV segment at ~6% penetration (Vahan CY2025) represents a growing but still sub-scale opportunity, limiting immediate financial impact but with strong medium-term implications.', NULL, 'escalating', 'short', '{"2W": "H", "3W": "L", "HCV": "L", "LCV": "L", "4W_PV": "L", "Tractor": "L"}', '["Infotainment", "Services", "Energy"]', '{}', true, '2026-04-03 11:14:00.65269+05:30', '2026-04-03 11:14:00.65269+05:30', '2026-04-03 11:14:00.65269+05:30', false, 'UNVERIFIED', '', '', '{"market_opportunity": "Estimate based on: 2W EV at ~6% of 1.96 Cr units = ~1.18L units; at â‚¹8,000â€“12,000 EV-specific component content per unit = â‚¹940â€“1,400 Cr addressable annually", "industry_investment": "Ather IPO proceeds + legacy OEM EV capex (TVS â‚¹1,000 Cr+ EV program)", "subsidy_or_incentive": "FAME III / PM E-Drive incentives for 2W EV buyers", "government_investment": "N/A", "cost_impact_per_vehicle": "N/A"}', '{"announced": "2026-04", "effective": "2026-04", "completion": ""}', '[{"url": "https://auto.economictimes.indiatimes.com/news/two-wheelers/legacy-players-gain-ground-in-ev-two-wheelers-as-ola-electric-slips/129992631", "claim": "Ather Energy recorded 35,736 registrations in March 2026, translating to 19.4% market share, up from 13,332 units and 15% share in April 2025", "source": "ET Auto, 03 Apr 2026"}, {"url": "https://auto.economictimes.indiatimes.com/news/two-wheelers/hero-motocorp-march-dispatches-rise-9-to-5-98-lakh-units/129965603", "claim": "Hero MotoCorp scooter dispatches surged 53.18% to 65,815 units in March 2026 vs 42,963 units in March 2025", "source": "ET Auto, 02 Apr 2026"}]', '2026-04-03 11:14:00.65269+05:30', '2026-04-03 11:14:00.65269+05:30', 1); ON CONFLICT DO NOTHING;
INSERT INTO public.pestel_factors (id, code, name, category, selection_reasoning, likelihood, likelihood_reasoning, impact, impact_reasoning, origin_date, trend, time_horizon, segment_relevance, affected_pillars, source_ids, is_active, last_refreshed, created_at, updated_at, is_foundational, verification_verdict, verification_source, verification_evidence, financial_context, key_dates, citations, first_seen_date, last_confirmed_date, confirmation_count) VALUES (136, 'hero_honda_2w_volume_war_â€”_oem_consolidation_signa', 'Hero-Honda 2W Volume War â€” OEM Consolidation Signal', 'E', 'Hero MotoCorp (5.5M) and Honda (5.2M) together dominate India''s 2W market in FY26, with Honda closing the gap aggressively and planning a dedicated EV facility by 2028. This duopoly dynamic intensifies price pressure on component suppliers while simultaneously signalling massive future EV platform investment. Bosch''s Powertrain Solutions, EV Powertrain, and Vehicle Diagnostics pillars are directly exposed to both OEMs'' sourcing decisions.', 9, 'Honda''s 5.2M unit dispatch in 11 months of FY26 is verified data from ET Auto (March 2026), and Honda has publicly committed to an EV-exclusive facility by 2028. The competitive trajectory is confirmed and accelerating.', 7, 'Combined, these two OEMs represent ~55% of India''s 2W market (196L units FY25). Winning or losing preferred supplier status with either OEM has â‚¹500â€“800 Cr revenue implications for Bosch''s 2W component business. Honda''s 2028 EV facility creates a medium-term EV powertrain sourcing window.', NULL, 'escalating', 'short', '{"2W": "H", "3W": "L", "HCV": "L", "LCV": "L", "4W_PV": "L", "Tractor": "L"}', '["Powertrain Solutions", "EV Powertrain", "Vehicle Diagnostics", "Body Electronics"]', '{}', false, '2026-03-26 11:22:14.095204+05:30', '2026-03-26 11:22:14.095204+05:30', '2026-03-26 11:22:14.095204+05:30', false, 'UNVERIFIED', NULL, NULL, '{}', '{}', '[]', '2026-03-26 11:22:14.095204+05:30', '2026-03-26 11:22:14.095204+05:30', 1); ON CONFLICT DO NOTHING;
INSERT INTO public.pestel_factors (id, code, name, category, selection_reasoning, likelihood, likelihood_reasoning, impact, impact_reasoning, origin_date, trend, time_horizon, segment_relevance, affected_pillars, source_ids, is_active, last_refreshed, created_at, updated_at, is_foundational, verification_verdict, verification_source, verification_evidence, financial_context, key_dates, citations, first_seen_date, last_confirmed_date, confirmation_count) VALUES (82, 'global_oil_price_surge_â€”_ice_powertrain_demand_res', 'Global oil price surge â€” ICE powertrain demand resilience in price-sensitive segments', 'En', 'Rising global oil prices create a dual dynamic: they accelerate EV adoption in cost-sensitive fleet segments (3W, LCV) while simultaneously making ethanol blending and CNG alternatives more attractive in 2W and entry-level 4W segments where EV upfront costs remain prohibitive. This sustains Bosch''s ICE powertrain and fuel systems business in volume segments while creating urgency for EV solutions in fleet-operated segments.', 8, 'ET Auto (March 2026) explicitly references global energy market volatility as a sustained condition. Geopolitical factors (Middle East, Russia-Ukraine) driving oil price uncertainty are structural, not cyclical. India''s import dependence (~85% of crude) makes domestic fuel price transmission near-certain.', 6, 'Higher fuel costs accelerate fleet operator TCO calculations favouring EVs in 3W and LCV segments (where Bosch''s EV content opportunity is growing), while sustaining ICE powertrain volumes in 2W and entry 4W (protecting existing Bosch revenue). The net effect is a faster bifurcation of the market, requiring Bosch to manage dual technology portfolios simultaneously â€” increasing R&D and inventory complexity.', NULL, 'escalating', 'immediate', '{"2W": "H", "3W": "H", "HCV": "M", "LCV": "H", "4W_PV": "M", "Tractor": "M"}', '["Motion", "Energy", "Energy", "Services"]', '{}', false, '2026-03-16 23:47:58.163502+05:30', '2026-03-16 23:47:58.163502+05:30', '2026-03-16 23:47:58.163502+05:30', false, 'UNVERIFIED', NULL, NULL, '{}', '{}', '[]', '2026-03-16 23:47:58.163502+05:30', '2026-03-16 23:47:58.163502+05:30', 1); ON CONFLICT DO NOTHING;
INSERT INTO public.pestel_factors (id, code, name, category, selection_reasoning, likelihood, likelihood_reasoning, impact, impact_reasoning, origin_date, trend, time_horizon, segment_relevance, affected_pillars, source_ids, is_active, last_refreshed, created_at, updated_at, is_foundational, verification_verdict, verification_source, verification_evidence, financial_context, key_dates, citations, first_seen_date, last_confirmed_date, confirmation_count) VALUES (150, 'maruti_it/technology_leadership_consolidation_â€”_di', 'Maruti IT/Technology Leadership Consolidation â€” Digital Procurement Signal', 'P', 'Maruti Suzuki''s management reshuffle placing Dr. Tapan Sahoo (existing senior executive) in additional charge of IT signals a deliberate consolidation of technology and digital decision-making at the C-suite level ahead of FY27. For Bosch, this is relevant because integrated IT/technology leadership at Maruti accelerates decisions on connected car platforms, OTA software, and supplier digital integration â€” all areas where Bosch competes.', 8, 'The reshuffle is confirmed (ET Auto, March 2026) and described as preparation for the new financial year. Senior executive consolidation of IT with existing portfolios is a common pre-digital-transformation move at Indian OEMs.', 3, 'This is a directional signal rather than a direct revenue driver. It suggests Maruti is accelerating its software-defined vehicle and connected car agenda, which could compress Bosch''s window to establish preferred supplier status for Software & Services and Infotainment & Connectivity content. Impact is moderate â€” dependent on subsequent procurement decisions.', NULL, 'new', 'short', '{"2W": "L", "3W": "L", "HCV": "L", "LCV": "L", "4W_PV": "H", "Tractor": "L"}', '["Infotainment", "OS"]', '{}', false, '2026-03-26 11:21:49.304861+05:30', '2026-03-26 11:21:49.304861+05:30', '2026-03-26 11:21:49.304861+05:30', false, 'UNVERIFIED', NULL, NULL, '{}', '{}', '[]', '2026-03-26 11:21:49.304861+05:30', '2026-03-26 11:21:49.304861+05:30', 1); ON CONFLICT DO NOTHING;
INSERT INTO public.pestel_factors (id, code, name, category, selection_reasoning, likelihood, likelihood_reasoning, impact, impact_reasoning, origin_date, trend, time_horizon, segment_relevance, affected_pillars, source_ids, is_active, last_refreshed, created_at, updated_at, is_foundational, verification_verdict, verification_source, verification_evidence, financial_context, key_dates, citations, first_seen_date, last_confirmed_date, confirmation_count) VALUES (9, 'fame_iii_charging', 'FAME III â€” â‚¹2,671 Cr for EV charging (FY2025-27)', 'P', 'FAME III directly funds 10,000 DC fast charger installations by FY2027 â€” the largest single demand driver for Bosch''s Energy & Charging pillar. Creates immediate capital deployment opportunity.', 9, 'Score 9: FAME III scheme notified and â‚¹2,671 Cr approved. Disbursement track record from FAME II is mixed (delays), hence 9 not 10.', 5, 'Score 7: 10,000 DC chargers at ~â‚¹20-25 Lakh each = â‚¹2,000-2,500 Cr market for power electronics and connectors. Bosch competes directly for this with Delta, ABB.', NULL, 'new', 'short', '{"2W": "H", "3W": "H", "HCV": "L", "LCV": "M", "4W_PV": "M", "Tractor": "L"}', '["Energy", "OS", "Solutions"]', '{16}', true, '2026-03-16 22:45:46.381831+05:30', '2026-03-16 22:45:46.381831+05:30', '2026-03-16 22:48:13.097302+05:30', true, 'UNVERIFIED', NULL, NULL, '{}', '{}', '[]', '2026-03-16 22:45:46.381831+05:30', '2026-03-16 22:45:46.381831+05:30', 1); ON CONFLICT DO NOTHING;
INSERT INTO public.pestel_factors (id, code, name, category, selection_reasoning, likelihood, likelihood_reasoning, impact, impact_reasoning, origin_date, trend, time_horizon, segment_relevance, affected_pillars, source_ids, is_active, last_refreshed, created_at, updated_at, is_foundational, verification_verdict, verification_source, verification_evidence, financial_context, key_dates, citations, first_seen_date, last_confirmed_date, confirmation_count) VALUES (176, 'cafe_iii_2027', 'CAFE III norms (FY2027): 91 g CO2/km fleet average', 'L', 'India CAFE Phase III mandates 91 g CO2/km fleet average for PVs from FY2027, down from 130 g Phase I. OEMs must electrify or hybridize >=20% of volumes. Non-compliance penalty: Rs.25,000/km excess per vehicle. Hyundai, Maruti, Tata Motors most exposed.', 8, 'CAFE Phase III is gazetted law effective April 2027; auto industry compliance tracking is well-documented.', 7, 'Forces significant BOM changes including 48V mild hybrid, BEV integration; affects entire PV fleet.', NULL, 'escalating', 'medium', '{"2W": "L", "3W": "L", "HCV": "L", "LCV": "H", "4W_PV": "H", "Tractor": "L"}', '["Energy", "ADAS", "Motion"]', '{}', true, '2026-04-06 17:46:26.063279+05:30', '2026-04-06 17:46:26.063279+05:30', '2026-04-06 17:46:26.063279+05:30', false, 'UNVERIFIED', NULL, NULL, '{}', '{}', '[]', '2026-04-06 17:46:26.063279+05:30', '2026-04-06 17:46:26.063279+05:30', 1); ON CONFLICT DO NOTHING;
INSERT INTO public.pestel_factors (id, code, name, category, selection_reasoning, likelihood, likelihood_reasoning, impact, impact_reasoning, origin_date, trend, time_horizon, segment_relevance, affected_pillars, source_ids, is_active, last_refreshed, created_at, updated_at, is_foundational, verification_verdict, verification_source, verification_evidence, financial_context, key_dates, citations, first_seen_date, last_confirmed_date, confirmation_count) VALUES (92, 'jlr_cyberattack_â€”_oem_supply_chain_vulnerability_s', 'JLR Cyberattack â€” OEM Supply Chain Vulnerability Signal', 'T', 'JLR''s 2025 cyberattack caused a five-week production shutdown and material financial losses for Tata Motors, directly signalling systemic cybersecurity risk across OEM supply chains. For Bosch, this validates the criticality of its Safety & Security pillar (cybersecurity, UN R155 compliance) and Software & Services (OTA, vehicle OS hardening). It also creates a direct sales opportunity for Bosch''s vehicle cybersecurity solutions to Indian OEMs who now have a high-profile domestic case study to justify investment.', 9, 'Cyberattacks on automotive OEMs are escalating globally â€” Volkswagen, Toyota, and now JLR have all suffered major incidents. The JLR event is confirmed and documented (ET Auto, March 2026). The likelihood of further incidents affecting Indian OEM operations or their Tier-1 suppliers is high given increasing vehicle connectivity.', 3, 'A five-week shutdown at a major OEM translates to thousands of crores in lost production and supply chain disruption for Tier-1 suppliers. For Bosch, this creates both a risk (supply disruption to Tata-affiliated entities) and a significant commercial opportunity â€” OEMs will accelerate cybersecurity procurement post-incident. The India ADAS and connected vehicle market ($1.15B, growing at 18.12% CAGR) amplifies the attack surface.', NULL, 'escalating', 'immediate', '{"2W": "L", "3W": "L", "HCV": "L", "LCV": "L", "4W_PV": "H", "Tractor": "L"}', '["ADAS", "Infotainment", "OS"]', '{}', true, '2026-03-17 16:31:52.361522+05:30', '2026-03-17 16:31:52.361522+05:30', '2026-03-17 16:31:52.361522+05:30', false, 'UNVERIFIED', NULL, NULL, '{}', '{}', '[]', '2026-03-17 16:31:52.361522+05:30', '2026-03-17 16:31:52.361522+05:30', 1); ON CONFLICT DO NOTHING;
INSERT INTO public.pestel_factors (id, code, name, category, selection_reasoning, likelihood, likelihood_reasoning, impact, impact_reasoning, origin_date, trend, time_horizon, segment_relevance, affected_pillars, source_ids, is_active, last_refreshed, created_at, updated_at, is_foundational, verification_verdict, verification_source, verification_evidence, financial_context, key_dates, citations, first_seen_date, last_confirmed_date, confirmation_count) VALUES (132, 'euler_motors_â‚¹437.5_cr_raise_â€”_e_cv_segment_accele', 'Euler Motors â‚¹437.5 Cr Raise â€” e-CV Segment Acceleration', 'E', 'Euler Motors, backed by Hero MotoCorp, is targeting 100% revenue growth over FY25''s â‚¹191 Cr base, with fresh capital for EV manufacturing and R&D (ET Auto, March 2026). This signals accelerating electrification in the LCV/small commercial vehicle segment, creating demand for Bosch EV powertrain, BMS, telematics, and fleet diagnostics. New EV-native OEMs typically source from Tier-1 specialists rather than building in-house.', 8, 'Funding is confirmed (â‚¹437.5 Cr secured), Hero MotoCorp backing provides strategic credibility and distribution access. The e-CV segment is growing rapidly driven by last-mile logistics electrification and gig economy fleet operators.', 6, 'Euler''s current scale (â‚¹191 Cr FY25 revenue, ~2,000â€“3,000 units estimated) is small relative to total LCV market (5.2L units). However, as an early-stage EV-native OEM, winning Euler as a platform customer establishes Bosch''s EV component reference in the e-CV segment. Revenue impact is modest near-term but strategically significant for platform positioning.', NULL, 'escalating', 'short', '{"2W": "L", "3W": "M", "HCV": "L", "LCV": "H", "4W_PV": "L", "Tractor": "L"}', '["EV Powertrain", "Vehicle Diagnostics", "Infotainment & Connectivity", "Thermal Management"]', '{}', false, '2026-03-26 11:21:49.300728+05:30', '2026-03-26 11:21:49.300728+05:30', '2026-03-26 11:21:49.304861+05:30', false, 'UNVERIFIED', NULL, NULL, '{}', '{}', '[]', '2026-03-26 11:21:49.300728+05:30', '2026-03-26 11:21:49.300728+05:30', 1); ON CONFLICT DO NOTHING;
INSERT INTO public.pestel_factors (id, code, name, category, selection_reasoning, likelihood, likelihood_reasoning, impact, impact_reasoning, origin_date, trend, time_horizon, segment_relevance, affected_pillars, source_ids, is_active, last_refreshed, created_at, updated_at, is_foundational, verification_verdict, verification_source, verification_evidence, financial_context, key_dates, citations, first_seen_date, last_confirmed_date, confirmation_count) VALUES (38, 'hcv_safety_norms_aebs', 'AEBS mandatory for all new HCV from April 2025', 'L', 'Advanced Emergency Braking System (AEBS) is mandatory for all new HCV (>3.5T GVW) from April 2025. India''s HCV market (~4.4 Lakh units/year) now requires collision warning radar â€” a direct, quantified demand signal for Bosch''s Vehicle Motion pillar.', 10, 'Score 10: MoRTH notification issued. All new HCV models from April 2025 must have AEBS. Confirmed implemented regulation.', 5, 'Score 7: 4.4 Lakh HCV units/year Ã— â‚¹25,000-35,000 AEBS unit cost = â‚¹1,100-1,540 Cr annual market. Bosch is well-positioned in radar-based AEBS for commercial vehicles.', NULL, 'stable', 'immediate', '{"2W": "L", "3W": "L", "HCV": "H", "LCV": "H", "4W_PV": "L", "Tractor": "L"}', '["Actuators", "ADAS", "ECUs", "Motion"]', '{15}', true, '2026-03-16 22:45:46.381831+05:30', '2026-03-16 22:45:46.381831+05:30', '2026-03-16 22:48:13.097302+05:30', true, 'UNVERIFIED', NULL, NULL, '{}', '{}', '[]', '2026-03-16 22:45:46.381831+05:30', '2026-03-16 22:45:46.381831+05:30', 1); ON CONFLICT DO NOTHING;
INSERT INTO public.pestel_factors (id, code, name, category, selection_reasoning, likelihood, likelihood_reasoning, impact, impact_reasoning, origin_date, trend, time_horizon, segment_relevance, affected_pillars, source_ids, is_active, last_refreshed, created_at, updated_at, is_foundational, verification_verdict, verification_source, verification_evidence, financial_context, key_dates, citations, first_seen_date, last_confirmed_date, confirmation_count) VALUES (11, 'bharat_ncap_mandatory', 'Bharat NCAP 5-star target mandatory by 2028', 'P', 'Bharat NCAP (voluntary since Oct 2023, mandatory 5-star by 2028) is catalysing ADAS adoption in entry-level 4W PV. Every star rating uplift requires incremental safety electronics spend.', 8, 'Score 8: Policy notified and voluntary phase active. Mandatory timeline (2028) confirmed in MoRTH roadmap. Score 8 because implementation could slip given OEM lobbying.', 6, 'Score 7: Safety content per vehicle could rise by â‚¹15,000-25,000 in entry segments. Affects ABS, airbags, ADAS cameras, ESC â€” 4 of Bosch''s pillars directly.', NULL, 'escalating', 'short', '{"2W": "L", "3W": "L", "HCV": "L", "LCV": "L", "4W_PV": "H", "Tractor": "L"}', '["Actuators", "ADAS", "Body & Comfort", "ECUs", "Motion"]', '{14}', true, '2026-03-16 22:45:46.381831+05:30', '2026-03-16 22:45:46.381831+05:30', '2026-03-16 22:48:13.097302+05:30', false, 'UNVERIFIED', NULL, NULL, '{}', '{}', '[]', '2026-03-16 22:45:46.381831+05:30', '2026-03-16 22:45:46.381831+05:30', 1); ON CONFLICT DO NOTHING;
INSERT INTO public.pestel_factors (id, code, name, category, selection_reasoning, likelihood, likelihood_reasoning, impact, impact_reasoning, origin_date, trend, time_horizon, segment_relevance, affected_pillars, source_ids, is_active, last_refreshed, created_at, updated_at, is_foundational, verification_verdict, verification_source, verification_evidence, financial_context, key_dates, citations, first_seen_date, last_confirmed_date, confirmation_count) VALUES (34, 'cybersecurity_regulations_un155', 'UN R155 vehicle cybersecurity mandatory for new type approvals', 'L', 'UN Regulation 155 (vehicle cybersecurity management systems) is being adopted by India aligned with EU timelines. All ECUs in connected vehicles must have certified cybersecurity architecture â€” directly mandating Bosch''s Software & Services VSOC (Vehicle Security Operations Centre) capability.', 8, 'Score 8: MoRTH has announced alignment with UN R155. Mandatory for new type approvals being phased in 2025-2026. India-specific implementation timeline has some uncertainty.', 6, 'Score 7: Each vehicle needs cybersecurity certification. Creates recurring software revenue for Bosch (VSOC subscriptions) and raises the engineering barrier for smaller competitors.', NULL, 'new', 'short', '{"2W": "L", "3W": "L", "HCV": "M", "LCV": "M", "4W_PV": "H", "Tractor": "L"}', '["ADAS", "Cloud", "ECUs", "Infotainment", "OS"]', '{15}', true, '2026-03-16 22:45:46.381831+05:30', '2026-03-16 22:45:46.381831+05:30', '2026-03-16 22:48:13.097302+05:30', false, 'UNVERIFIED', NULL, NULL, '{}', '{}', '[]', '2026-03-16 22:45:46.381831+05:30', '2026-03-16 22:45:46.381831+05:30', 1); ON CONFLICT DO NOTHING;
INSERT INTO public.pestel_factors (id, code, name, category, selection_reasoning, likelihood, likelihood_reasoning, impact, impact_reasoning, origin_date, trend, time_horizon, segment_relevance, affected_pillars, source_ids, is_active, last_refreshed, created_at, updated_at, is_foundational, verification_verdict, verification_source, verification_evidence, financial_context, key_dates, citations, first_seen_date, last_confirmed_date, confirmation_count) VALUES (21, 'connected_car_consumer_expectation', 'Connected car features now expected even in sub-â‚¹10L segment', 'S', 'Connected infotainment (OTA updates, app integration, voice assistant) has migrated from premium to entry-level in India within 3 years. This expands the addressable market for Bosch''s Infotainment & Connectivity pillar into the volume segment.', 9, 'Score 9: SUV models under â‚¹10L (Maruti Brezza, Nexon) now standard with connected infotainment. Data from OEM model specifications FY2025 confirms.', 6, 'Score 6: Revenue per vehicle for Infotainment & Connectivity unit rises. But margin per unit is lower in volume segment. Net impact moderate.', NULL, 'escalating', 'short', '{"2W": "L", "3W": "L", "HCV": "L", "LCV": "L", "4W_PV": "H", "Tractor": "L"}', '["Cloud", "Infotainment", "OS", "Services"]', '{20}', true, '2026-03-16 22:45:46.381831+05:30', '2026-03-16 22:45:46.381831+05:30', '2026-03-16 22:48:13.097302+05:30', false, 'UNVERIFIED', NULL, NULL, '{}', '{}', '[]', '2026-03-16 22:45:46.381831+05:30', '2026-03-16 22:45:46.381831+05:30', 1); ON CONFLICT DO NOTHING;
INSERT INTO public.pestel_factors (id, code, name, category, selection_reasoning, likelihood, likelihood_reasoning, impact, impact_reasoning, origin_date, trend, time_horizon, segment_relevance, affected_pillars, source_ids, is_active, last_refreshed, created_at, updated_at, is_foundational, verification_verdict, verification_source, verification_evidence, financial_context, key_dates, citations, first_seen_date, last_confirmed_date, confirmation_count) VALUES (32, 'extreme_heat_ev_thermal', 'Extreme heat events stressing EV thermal management requirements', 'En', 'India''s 2025 heatwave (peak 48Â°C in Rajasthan) accelerated battery degradation in early EV fleets and triggered OEM battery management recalls. This elevates the design requirements â€” and market size â€” for Bosch''s Thermal Management pillar.', 8, 'Score 9: 2025 heatwave documented. Climate trend toward more frequent extreme heat in India is scientifically established. High likelihood of recurrence.', 6, 'Score 6: Creates specification uplift for Thermal Management systems â€” more sophisticated cooling circuits, higher-rated TIMs. Bosch benefits but it''s an engineering evolution not a step change.', NULL, 'escalating', 'medium', '{"2W": "H", "3W": "H", "HCV": "M", "LCV": "H", "4W_PV": "H", "Tractor": "L"}', '["Energy"]', '{17}', true, '2026-03-16 22:45:46.381831+05:30', '2026-03-16 22:45:46.381831+05:30', '2026-03-16 22:48:13.097302+05:30', false, 'UNVERIFIED', NULL, NULL, '{}', '{}', '[]', '2026-03-16 22:45:46.381831+05:30', '2026-03-16 22:45:46.381831+05:30', 1); ON CONFLICT DO NOTHING;
INSERT INTO public.pestel_factors (id, code, name, category, selection_reasoning, likelihood, likelihood_reasoning, impact, impact_reasoning, origin_date, trend, time_horizon, segment_relevance, affected_pillars, source_ids, is_active, last_refreshed, created_at, updated_at, is_foundational, verification_verdict, verification_source, verification_evidence, financial_context, key_dates, citations, first_seen_date, last_confirmed_date, confirmation_count) VALUES (14, 'india_gdp_growth_6pct', 'India GDP growth 6.4% (FY2025) â€” auto sector tailwind', 'E', 'India''s 6.4% GDP growth rate sustains middle-class income growth and first-vehicle purchase cycle, directly supporting 4W PV volume. 1% GDP growth historically correlates with ~1.8% auto sales growth in India.', 10, 'Score 10: IMF/RBI confirmed 6.4% GDP growth for FY2025. Historical fact.', 7, 'Score 6: Strong but background macro driver. Impact is diffuse â€” benefits all segments without concentrating value in specific Bosch pillars. More baseline than swing factor.', NULL, 'stable', 'medium', '{"2W": "M", "3W": "M", "HCV": "H", "LCV": "H", "4W_PV": "H", "Tractor": "M"}', '["Motion"]', '{1}', true, '2026-03-16 22:45:46.381831+05:30', '2026-03-16 22:45:46.381831+05:30', '2026-03-16 22:48:13.097302+05:30', false, 'UNVERIFIED', NULL, NULL, '{}', '{}', '[]', '2026-03-16 22:45:46.381831+05:30', '2026-03-16 22:45:46.381831+05:30', 1); ON CONFLICT DO NOTHING;
INSERT INTO public.pestel_factors (id, code, name, category, selection_reasoning, likelihood, likelihood_reasoning, impact, impact_reasoning, origin_date, trend, time_horizon, segment_relevance, affected_pillars, source_ids, is_active, last_refreshed, created_at, updated_at, is_foundational, verification_verdict, verification_source, verification_evidence, financial_context, key_dates, citations, first_seen_date, last_confirmed_date, confirmation_count) VALUES (113, 'euler_motors_â‚¹437.5_cr_raise_â€”_electric_lcv_segmen', 'Euler Motors â‚¹437.5 Cr Raise â€” Electric LCV Segment Acceleration', 'E', 'Euler Motors securing â‚¹437.5 Cr with Hero MotoCorp backing (ET Auto, Mar 2026), targeting 100% revenue growth over FY25''s â‚¹191 Cr, signals rapid scaling of the electric LCV segment. This is a direct opportunity for Bosch''s EV Powertrain (motors, inverters, BMS), Thermal Management, and Energy & Charging pillars. Hero MotoCorp''s strategic backing also creates a potential cross-segment technology partnership channel.', 8, 'Funding is confirmed and closed at â‚¹437.5 Cr with a credible strategic investor (Hero MotoCorp). The e-CV segment has structural demand from last-mile logistics and fleet electrification mandates. 100% growth target over â‚¹191 Cr base is aggressive but achievable given the funding runway.', 4, 'Estimate based on: At â‚¹382 Cr projected FY26 revenue and ~15-20% component content addressable by Bosch (motors, BMS, thermal), the direct revenue opportunity is â‚¹57-76 Cr near-term. However, the strategic signal â€” Hero MotoCorp entering e-CV via investment â€” could catalyse broader LCV electrification, expanding the total addressable market for Bosch''s EV Powertrain pillar in LCV/3W segments.', NULL, 'escalating', 'short', '{"2W": "L", "3W": "L", "HCV": "L", "LCV": "H", "4W_PV": "L", "Tractor": "L"}', '["Energy", "Infotainment"]', '{}', true, '2026-03-26 11:21:49.301521+05:30', '2026-03-26 11:21:49.301521+05:30', '2026-03-26 11:21:49.301521+05:30', false, 'UNVERIFIED', NULL, NULL, '{}', '{}', '[]', '2026-03-26 11:21:49.301521+05:30', '2026-03-26 11:21:49.301521+05:30', 1); ON CONFLICT DO NOTHING;
INSERT INTO public.pestel_factors (id, code, name, category, selection_reasoning, likelihood, likelihood_reasoning, impact, impact_reasoning, origin_date, trend, time_horizon, segment_relevance, affected_pillars, source_ids, is_active, last_refreshed, created_at, updated_at, is_foundational, verification_verdict, verification_source, verification_evidence, financial_context, key_dates, citations, first_seen_date, last_confirmed_date, confirmation_count) VALUES (15, 'cbam_eu_carbon_border', 'EU CBAM â€” carbon declarations for metal-intensive exports', 'E', 'EU Carbon Border Adjustment Mechanism (2026 reporting, 2034 financial liability) creates a compliance cost layer that partially offsets the India-EU FTA tariff benefit for castings, forgings, and metal-intensive components.', 9, 'Score 9: CBAM is EU law (Reg 2023/956). Transitional reporting started Oct 2023. Financial liability from 2026. Score 9 not 10 due to uncertainty on India-specific scope.', 6, 'Score 6: Compliance cost initially low but rises to 2034. Bosch (large Tier-1) can absorb vs smaller Indian suppliers â€” creates competitive moat rather than existential risk.', NULL, 'escalating', 'long', '{"2W": "L", "3W": "L", "HCV": "H", "LCV": "H", "4W_PV": "M", "Tractor": "L"}', '["Compute", "Motion"]', '{11}', true, '2026-03-16 22:45:46.381831+05:30', '2026-03-16 22:45:46.381831+05:30', '2026-03-16 22:48:13.097302+05:30', false, 'UNVERIFIED', NULL, NULL, '{}', '{}', '[]', '2026-03-16 22:45:46.381831+05:30', '2026-03-16 22:45:46.381831+05:30', 1); ON CONFLICT DO NOTHING;
INSERT INTO public.pestel_factors (id, code, name, category, selection_reasoning, likelihood, likelihood_reasoning, impact, impact_reasoning, origin_date, trend, time_horizon, segment_relevance, affected_pillars, source_ids, is_active, last_refreshed, created_at, updated_at, is_foundational, verification_verdict, verification_source, verification_evidence, financial_context, key_dates, citations, first_seen_date, last_confirmed_date, confirmation_count) VALUES (12, 'india_auto_exports_22b', 'India auto component exports reach $22.9B (FY2025)', 'E', 'Total export base sets the addressable market for Bosch''s export-facing manufacturing. $22.9B at 8% YoY growth signals structural shift from domestic-only to export-oriented production strategy.', 10, 'Score 10: ACMA confirmed final data. Historical fact not projection.', 8, 'Score 6: Confirms India''s rising position as global supply base. Positively impacts Bosch''s Pune/Nashik export volumes but benefit is long-cycle.', NULL, 'escalating', 'medium', '{"2W": "M", "3W": "L", "HCV": "H", "LCV": "H", "4W_PV": "H", "Tractor": "L"}', '["Body & Comfort", "Motion", "Solutions"]', '{1}', true, '2026-03-16 22:45:46.381831+05:30', '2026-03-16 22:45:46.381831+05:30', '2026-03-16 22:48:13.097302+05:30', false, 'UNVERIFIED', NULL, NULL, '{}', '{}', '[]', '2026-03-16 22:45:46.381831+05:30', '2026-03-16 22:45:46.381831+05:30', 1); ON CONFLICT DO NOTHING;
INSERT INTO public.pestel_factors (id, code, name, category, selection_reasoning, likelihood, likelihood_reasoning, impact, impact_reasoning, origin_date, trend, time_horizon, segment_relevance, affected_pillars, source_ids, is_active, last_refreshed, created_at, updated_at, is_foundational, verification_verdict, verification_source, verification_evidence, financial_context, key_dates, citations, first_seen_date, last_confirmed_date, confirmation_count) VALUES (78, 'honda_''0_alpha''_ev_â€”_â‚¹1,200_cr_india_ev_manufactur', 'Honda ''0 Alpha'' EV â€” â‚¹1,200 Cr India EV manufacturing investment', 'E', 'Honda''s confirmed â‚¹1,200 Crore investment in EV manufacturing at Tapukara, Rajasthan, signals a major global OEM committing to India as an EV production hub. As an existing Bosch powertrain and chassis customer, Honda''s EV platform transition creates both a risk (ICE content displacement) and an opportunity (EV powertrain, BMS, thermal management, ADAS content on new platforms). Early engagement in Honda''s EV supply chain design is strategically critical.', 8, 'Investment is confirmed with state government engagement at Chief Minister level (ET Auto, March 2026), indicating regulatory clearances are progressing. Honda''s global EV strategy (''0 Series'') aligns with this India announcement, reducing reversal risk. Production likely by 2027-28.', 3, 'Honda India currently sells ~1.5-2 lakh PVs annually. An EV platform transition at this scale represents a potential shift of â‚¹500-800 Crore in Bosch ICE content toward EV powertrain, ADAS, and thermal management content. Bosch''s incumbent supplier status gives it a first-mover advantage in Honda''s India EV supply chain if engaged early.', NULL, 'escalating', 'short', '{"2W": "L", "3W": "L", "HCV": "L", "LCV": "L", "4W_PV": "H", "Tractor": "L"}', '["Energy", "Motion", "OS"]', '{}', true, '2026-03-16 23:47:58.163502+05:30', '2026-03-16 23:47:58.163502+05:30', '2026-03-16 23:47:58.163502+05:30', false, 'UNVERIFIED', NULL, NULL, '{}', '{}', '[]', '2026-03-16 23:47:58.163502+05:30', '2026-03-16 23:47:58.163502+05:30', 1); ON CONFLICT DO NOTHING;
INSERT INTO public.pestel_factors (id, code, name, category, selection_reasoning, likelihood, likelihood_reasoning, impact, impact_reasoning, origin_date, trend, time_horizon, segment_relevance, affected_pillars, source_ids, is_active, last_refreshed, created_at, updated_at, is_foundational, verification_verdict, verification_source, verification_evidence, financial_context, key_dates, citations, first_seen_date, last_confirmed_date, confirmation_count) VALUES (33, 'scrappage_policy_fleet_renewal', 'Vehicle scrappage policy accelerating fleet renewal (FY2025)', 'En', 'India''s vehicle scrappage policy (mandatory fitness test after 15 years) is accelerating retirement of pre-BS-IV vehicles, replacing them with BS-VI / EV units with significantly higher Bosch component content per vehicle.', 8, 'Score 8: Policy in force. ~4-5 million vehicles >15 years old are being retired annually. Commercial vehicle scrappage particularly active (incentive scheme).', 7, 'Score 6: Each replaced vehicle represents a meaningful Bosch content uplift (BS-VI powertrain, OBD-II, ESC). But the replacement cycle is gradual and demand is diffuse.', NULL, 'escalating', 'short', '{"2W": "L", "3W": "H", "HCV": "H", "LCV": "H", "4W_PV": "M", "Tractor": "L"}', '["Actuators", "Infotainment", "Motion", "Solutions"]', '{2}', true, '2026-03-16 22:45:46.381831+05:30', '2026-03-16 22:45:46.381831+05:30', '2026-03-16 22:48:13.097302+05:30', false, 'UNVERIFIED', NULL, NULL, '{}', '{}', '[]', '2026-03-16 22:45:46.381831+05:30', '2026-03-16 22:45:46.381831+05:30', 1); ON CONFLICT DO NOTHING;
INSERT INTO public.pestel_factors (id, code, name, category, selection_reasoning, likelihood, likelihood_reasoning, impact, impact_reasoning, origin_date, trend, time_horizon, segment_relevance, affected_pillars, source_ids, is_active, last_refreshed, created_at, updated_at, is_foundational, verification_verdict, verification_source, verification_evidence, financial_context, key_dates, citations, first_seen_date, last_confirmed_date, confirmation_count) VALUES (115, 'honda_india_2w_global_hub_strategy_â€”_export_platfo', 'Honda India 2W Global Hub Strategy â€” Export Platform Implications', 'P', 'Honda reaffirming India as a global 2W manufacturing hub with Rajasthan capacity expansion and a dedicated EV facility by 2028 (ET Auto, Mar 2026) elevates India''s role in Honda''s global supply chain. For Bosch, this means Honda India''s component specifications will increasingly need to meet global export standards (Euro 5+, OBD-II equivalent), raising the technology content floor and creating export-linked component demand.', 8, 'Honda''s capital commitment to Rajasthan expansion is confirmed. The 2028 EV facility timeline is specific and backed by Honda''s global EV strategy. India''s cost advantage and Honda''s existing manufacturing scale (second largest 2W OEM) make the global hub positioning credible.', 5, 'Honda''s India 2W production exceeds 5M units annually. If export share grows to 20-25% (from current ~15%), Bosch''s component specifications must align with destination market standards â€” creating upgrade demand for emissions, diagnostics, and connectivity components. The 2028 EV facility represents a new platform opportunity for Bosch''s EV Powertrain pillar in 2W.', NULL, 'escalating', 'medium', '{"2W": "H", "3W": "L", "HCV": "L", "LCV": "L", "4W_PV": "L", "Tractor": "L"}', '["Energy", "Infotainment", "Motion", "Services"]', '{}', true, '2026-03-26 11:21:49.301521+05:30', '2026-03-26 11:21:49.301521+05:30', '2026-03-26 11:21:49.301521+05:30', false, 'UNVERIFIED', NULL, NULL, '{}', '{}', '[]', '2026-03-26 11:21:49.301521+05:30', '2026-03-26 11:21:49.301521+05:30', 1); ON CONFLICT DO NOTHING;
INSERT INTO public.pestel_factors (id, code, name, category, selection_reasoning, likelihood, likelihood_reasoning, impact, impact_reasoning, origin_date, trend, time_horizon, segment_relevance, affected_pillars, source_ids, is_active, last_refreshed, created_at, updated_at, is_foundational, verification_verdict, verification_source, verification_evidence, financial_context, key_dates, citations, first_seen_date, last_confirmed_date, confirmation_count) VALUES (86, 'renault_duster_relaunch_â€”_mid_suv_ice_segment_volu', 'Renault Duster relaunch â€” mid-SUV ICE segment volume recovery signal', 'E', 'The Renault Duster relaunch signals continued OEM confidence in ICE/hybrid mid-SUV volumes in India, a segment where Bosch has strong powertrain and chassis content. This is a counter-signal to premature ICE obsolescence narratives and supports sustained demand for Bosch''s Powertrain Solutions and Chassis Systems in the â‚¹10-20L SUV segment. Renault''s India strategy refresh also opens a potential new OEM relationship for Bosch in the mid-SUV space.', 8, 'The Duster relaunch is confirmed with Marc Nassif''s direct commentary (ET Auto, March 2026). Renault has committed to the model and the mid-SUV segment in India is demonstrably growing, with multiple OEMs reporting strong bookings in the â‚¹12-20L range.', 3, 'The Duster''s expected volumes (~3,000-5,000 units/month) are modest relative to segment leaders. The strategic signal value â€” confirming ICE mid-SUV longevity â€” is more important than the direct Bosch revenue opportunity from this single model. Impact on Bosch''s overall revenue is low but the market intelligence value is high.', NULL, 'stable', 'short', '{"2W": "L", "3W": "L", "HCV": "L", "LCV": "L", "4W_PV": "H", "Tractor": "L"}', '["Body & Comfort", "Motion"]', '{}', false, '2026-03-17 10:47:58.048368+05:30', '2026-03-17 10:47:58.048368+05:30', '2026-03-17 10:47:58.048368+05:30', false, 'UNVERIFIED', NULL, NULL, '{}', '{}', '[]', '2026-03-17 10:47:58.048368+05:30', '2026-03-17 10:47:58.048368+05:30', 1); ON CONFLICT DO NOTHING;
INSERT INTO public.pestel_factors (id, code, name, category, selection_reasoning, likelihood, likelihood_reasoning, impact, impact_reasoning, origin_date, trend, time_horizon, segment_relevance, affected_pillars, source_ids, is_active, last_refreshed, created_at, updated_at, is_foundational, verification_verdict, verification_source, verification_evidence, financial_context, key_dates, citations, first_seen_date, last_confirmed_date, confirmation_count) VALUES (129, 'hero_honda_2w_volume_race_â€”_oem_supply_intensity', 'Hero-Honda 2W Volume Race â€” OEM Supply Intensity', 'E', 'Hero MotoCorp (5.5M units) and Honda (5.2M units) together account for ~55% of India''s 2W market in FY26 11-month data. This duopoly concentration means Bosch''s 2W powertrain, OBD-II diagnostics, and body electronics volumes are heavily dependent on these two OEMs'' procurement decisions. Any platform consolidation or in-sourcing by either OEM carries outsized revenue risk.', 9, 'FY26 dispatch data from ET Auto (March 2026) confirms the race is live and intensifying. Honda''s stated capacity expansion at Rajasthan and a dedicated EV facility by 2028 signals multi-year volume commitment. The competitive dynamic is structural, not cyclical.', 6, '2W segment is 1.96 Crore units (FY25, SIAM). Combined Hero+Honda volume of ~12.7M units annualised represents the largest single addressable segment for Bosch 2W components. However, 2W average component content per vehicle is lower than 4W, capping absolute revenue impact. Estimate: â‚¹800â€“1,200 Cr addressable content across OBD-II, fuel systems, and body electronics.', NULL, 'escalating', 'short', '{"2W": "H", "3W": "L", "HCV": "L", "LCV": "L", "4W_PV": "L", "Tractor": "L"}', '["Infotainment", "Motion", "Services"]', '{}', false, '2026-03-26 11:21:49.300728+05:30', '2026-03-26 11:21:49.300728+05:30', '2026-03-26 11:21:49.300728+05:30', false, 'UNVERIFIED', NULL, NULL, '{}', '{}', '[]', '2026-03-26 11:21:49.300728+05:30', '2026-03-26 11:21:49.300728+05:30', 1); ON CONFLICT DO NOTHING;
INSERT INTO public.pestel_factors (id, code, name, category, selection_reasoning, likelihood, likelihood_reasoning, impact, impact_reasoning, origin_date, trend, time_horizon, segment_relevance, affected_pillars, source_ids, is_active, last_refreshed, created_at, updated_at, is_foundational, verification_verdict, verification_source, verification_evidence, financial_context, key_dates, citations, first_seen_date, last_confirmed_date, confirmation_count) VALUES (30, 'corporate_fleet_decarbonisation', 'Corporate fleet sustainability mandates â€” 30% EV by 2027', 'En', 'SEBI''s new ESG disclosure requirements (FY2025) require large companies to report fleet emissions. This is triggering voluntary fleet electrification targets among India''s top 500 companies â€” a fast-moving demand signal for EV LCV and 4W PV.', 6, 'Score 7: SEBI BRSR (Business Responsibility and Sustainability Reporting) active from FY2024. Corporate targets are voluntary but reputational pressure is real. Implementation pace uncertain.', 5, 'Score 6: Fleet market is ~8% of 4W PV sales but with higher technology content and predictable replacement cycles. Meaningful pull for EV Powertrain in LCV/4W PV.', NULL, 'escalating', 'short', '{"2W": "L", "3W": "L", "HCV": "L", "LCV": "H", "4W_PV": "H", "Tractor": "L"}', '["Cloud", "Energy", "OS", "Services", "Solutions"]', '{19}', true, '2026-03-16 22:45:46.381831+05:30', '2026-03-16 22:45:46.381831+05:30', '2026-03-16 22:48:13.097302+05:30', false, 'UNVERIFIED', NULL, NULL, '{}', '{}', '[]', '2026-03-16 22:45:46.381831+05:30', '2026-03-16 22:45:46.381831+05:30', 1); ON CONFLICT DO NOTHING;
INSERT INTO public.pestel_factors (id, code, name, category, selection_reasoning, likelihood, likelihood_reasoning, impact, impact_reasoning, origin_date, trend, time_horizon, segment_relevance, affected_pillars, source_ids, is_active, last_refreshed, created_at, updated_at, is_foundational, verification_verdict, verification_source, verification_evidence, financial_context, key_dates, citations, first_seen_date, last_confirmed_date, confirmation_count) VALUES (13, 'battery_cost_decline', 'Battery pack prices fall to $110/kWh (2025)', 'E', 'Battery pack prices have fallen below the $110/kWh inflection point as of 2026, with global averages now in the $95-105/kWh range. For India, landed cost of imported cells remains higher due to customs duties (5-15%), but domestic cell manufacturing under PLI is beginning to narrow the gap. The price parity narrative for 4W EVs is now structurally validated and the focus should shift to TCO parity timelines by segment.', 7, 'Score 10: IEA confirmed $110/kWh global average in 2025. India-specific prices slightly higher (~$120/kWh due to import duties) but trend is confirmed.', 7, 'Score 8: Price parity with ICE in mass segments by 2027-28. Accelerates Bosch''s EV BMS, Motor Controller, and Thermal Management demand 2-3 years ahead of prior forecasts.', NULL, 'escalating', 'medium', '{"2W": "H", "3W": "H", "HCV": "L", "LCV": "M", "4W_PV": "H", "Tractor": "L"}', '["Energy", "Semiconductors"]', '{17}', true, '2026-04-09 11:49:28.353024+05:30', '2026-03-16 22:45:46.381831+05:30', '2026-03-16 22:48:13.097302+05:30', true, 'UNVERIFIED', NULL, NULL, '{}', '{}', '[]', '2026-03-16 22:45:46.381831+05:30', '2026-04-09 11:49:28.353024+05:30', 1); ON CONFLICT DO NOTHING;
INSERT INTO public.pestel_factors (id, code, name, category, selection_reasoning, likelihood, likelihood_reasoning, impact, impact_reasoning, origin_date, trend, time_horizon, segment_relevance, affected_pillars, source_ids, is_active, last_refreshed, created_at, updated_at, is_foundational, verification_verdict, verification_source, verification_evidence, financial_context, key_dates, citations, first_seen_date, last_confirmed_date, confirmation_count) VALUES (10, 'aeb_mandate_2026', 'AEB mandatory for 4W PV new models April 2026', 'P', 'Automatic Emergency Braking mandatory for all new 4W PV models from April 2026 (MoRTH CMVR amendment). Creates a defined regulatory deadline and ~43 Lakh units/year addressable market for radar/camera systems.', 9, 'Score 9: CMVR amendment notified. Applies to new type approvals from April 2026. OEMs are already tooling up. Score 9 not 10 because phased implementation gives some flexibility.', 6, 'Score 8: ~43 Lakh 4W PV per year Ã— average AEB system cost â‰ˆ â‚¹1,500-2,000 Cr annual market. Bosch is a primary AEB supplier globally. Strong pull for Vehicle Motion pillar.', NULL, 'new', 'immediate', '{"2W": "L", "3W": "L", "HCV": "L", "LCV": "L", "4W_PV": "H", "Tractor": "L"}', '["Actuators", "ADAS", "ECUs", "Motion", "OS"]', '{15}', true, '2026-03-16 22:45:46.381831+05:30', '2026-03-16 22:45:46.381831+05:30', '2026-03-16 22:48:13.097302+05:30', true, 'UNVERIFIED', NULL, NULL, '{}', '{}', '[]', '2026-03-16 22:45:46.381831+05:30', '2026-03-16 22:45:46.381831+05:30', 1); ON CONFLICT DO NOTHING;
INSERT INTO public.pestel_factors (id, code, name, category, selection_reasoning, likelihood, likelihood_reasoning, impact, impact_reasoning, origin_date, trend, time_horizon, segment_relevance, affected_pillars, source_ids, is_active, last_refreshed, created_at, updated_at, is_foundational, verification_verdict, verification_source, verification_evidence, financial_context, key_dates, citations, first_seen_date, last_confirmed_date, confirmation_count) VALUES (159, 'e_2w_fy26_sales_+20.5%_â€”_sustained_electrification', 'E-2W FY26 Sales +20.5% â€” Sustained Electrification, Slowing Momentum', 'E', 'Electric two-wheeler sales reached 1.334 million units in FY26 (+20.5% YoY), but the growth rate has decelerated from prior-year peaks, with a March spike driven by fuel shortage fears and discounts rather than structural demand. This dual signal â€” sustained volume growth but decelerating organic momentum â€” is critical for Tier-1 suppliers calibrating EV powertrain and BMS capacity investments for the 2W segment.', 8, 'Vahan portal data is government-sourced and cross-confirmed by multiple ET Auto articles. The 1.334M unit figure for FY26 is near-final given the April 1 reporting date. The deceleration from prior growth rates is a verified trend, not a projection.', 5, 'At 1.334M units, the e-2W segment drives meaningful demand for motors, controllers, BMS, and battery packs. However, the 20.5% growth rate (vs 82% for 4W EV) signals that the mass-market 2W EV transition is progressing but not accelerating, moderating the urgency of capacity scale-up. Ather''s sub-â‚¹1L platform signals intensifying price competition that will compress component margins.', NULL, 'escalating', 'immediate', '{"2W": "H", "3W": "M", "HCV": "L", "LCV": "L", "4W_PV": "L", "Tractor": "L"}', '["Energy", "OS"]', '{}', true, '2026-04-01 11:05:44.591993+05:30', '2026-04-01 11:05:44.591993+05:30', '2026-04-01 11:05:44.591993+05:30', false, 'UNVERIFIED', NULL, NULL, '{}', '{}', '[]', '2026-04-01 11:05:44.591993+05:30', '2026-04-01 11:05:44.591993+05:30', 1); ON CONFLICT DO NOTHING;
INSERT INTO public.pestel_factors (id, code, name, category, selection_reasoning, likelihood, likelihood_reasoning, impact, impact_reasoning, origin_date, trend, time_horizon, segment_relevance, affected_pillars, source_ids, is_active, last_refreshed, created_at, updated_at, is_foundational, verification_verdict, verification_source, verification_evidence, financial_context, key_dates, citations, first_seen_date, last_confirmed_date, confirmation_count) VALUES (117, 'honda_india_2w_ev_facility_2028_â€”_platform_supply_', 'Honda India 2W EV Facility 2028 â€” Platform Supply Opportunity', 'P', 'Honda''s announcement of a dedicated EV 2W facility in 2028, combined with its reaffirmation of India as a global manufacturing hub, creates a defined procurement window for Bosch''s EV powertrain, BMS, and chassis systems. As a top-2 OEM by volume, Honda''s EV platform decisions will set component architecture standards for millions of units. Bosch must engage at design-in stage now to secure supply.', 7, 'Honda has formally announced the facility and reaffirmed India focus with capacity expansion already underway at Rajasthan. The 2028 timeline is credible given current investment pace and global Honda EV roadmap commitments.', 5, 'Honda''s 2W EV platform at scale (targeting volumes comparable to its ICE base of 5M+ units over time) represents a multi-hundred crore annual component opportunity for EV powertrain, BMS, and ABS/CBS systems. Early design-in wins lock in 5-7 year supply contracts.', NULL, 'escalating', 'medium', '{"2W": "H", "3W": "L", "HCV": "L", "LCV": "L", "4W_PV": "L", "Tractor": "L"}', '["Energy", "Infotainment", "Motion"]', '{}', true, '2026-03-26 11:21:49.325434+05:30', '2026-03-26 11:21:49.325434+05:30', '2026-03-26 11:21:49.300728+05:30', false, 'UNVERIFIED', NULL, NULL, '{}', '{}', '[]', '2026-03-26 11:21:49.325434+05:30', '2026-03-26 11:21:49.325434+05:30', 1); ON CONFLICT DO NOTHING;
INSERT INTO public.pestel_factors (id, code, name, category, selection_reasoning, likelihood, likelihood_reasoning, impact, impact_reasoning, origin_date, trend, time_horizon, segment_relevance, affected_pillars, source_ids, is_active, last_refreshed, created_at, updated_at, is_foundational, verification_verdict, verification_source, verification_evidence, financial_context, key_dates, citations, first_seen_date, last_confirmed_date, confirmation_count) VALUES (109, 'bajaj_auto_leadership_continuity_â€”_5_year_ed_reapp', 'Bajaj Auto Leadership Continuity â€” 5-Year ED Reappointment', 'P', 'Pradeep Shrivastava''s reappointment as Executive Director through 2031 signals strategic continuity at Bajaj Auto, India''s largest 2W and 3W exporter and a key Bosch customer. Stable leadership reduces procurement strategy uncertainty and supports long-term supplier relationship planning for Bosch''s Powertrain, EV Powertrain, and Vehicle Diagnostics pillars across Bajaj''s 2W and 3W platforms.', 9, 'Board approval is confirmed and publicly announced; reappointment is a done deal with no ambiguity.', 4, 'Leadership continuity is a positive but low-intensity signal â€” it reduces uncertainty rather than creating new opportunity. Bajaj''s technology roadmap (EV transition, CNG 3W, export platforms) remains unchanged. Impact on Bosch revenue is indirect and marginal in the near term.', NULL, 'stable', 'medium', '{"2W": "H", "3W": "H", "HCV": "L", "LCV": "L", "4W_PV": "L", "Tractor": "L"}', '["Energy", "Infotainment", "Motion"]', '{}', true, '2026-03-19 12:00:07.287583+05:30', '2026-03-19 12:00:07.287583+05:30', '2026-03-19 12:00:07.287583+05:30', false, 'UNVERIFIED', NULL, NULL, '{}', '{}', '[]', '2026-03-19 12:00:07.287583+05:30', '2026-03-19 12:00:07.287583+05:30', 1); ON CONFLICT DO NOTHING;
INSERT INTO public.pestel_factors (id, code, name, category, selection_reasoning, likelihood, likelihood_reasoning, impact, impact_reasoning, origin_date, trend, time_horizon, segment_relevance, affected_pillars, source_ids, is_active, last_refreshed, created_at, updated_at, is_foundational, verification_verdict, verification_source, verification_evidence, financial_context, key_dates, citations, first_seen_date, last_confirmed_date, confirmation_count) VALUES (123, 'honda_india_2w_ev_facility_2028_â€”_oem_electrificat', 'Honda India 2W EV Facility 2028 â€” OEM Electrification Timeline Signal', 'T', 'Honda''s confirmed plan for a dedicated EV 2W facility by 2028 sets a hard technology transition deadline for Bosch''s EV powertrain and BMS offerings in the 2W segment. As India''s second-largest 2W OEM with 5.2M annual dispatches, Honda''s EV platform decisions will shape component specification requirements. Bosch must secure design-in wins before platform lock-in occurs.', 8, 'Honda has formally reaffirmed India as a global hub with specific facility plans announced publicly (ET Auto, March 2026). The 2028 timeline is consistent with Honda''s global EV roadmap and India''s EV subsidy trajectory.', 8, 'A 2W EV platform at Honda''s scale (even 10-15% of 5.2M units = 520K-780K EVs) represents a significant addressable market for Bosch''s motor controllers, BMS, and inverters. Missing the design-in window means exclusion for the platform lifecycle of 5-7 years. Estimate based on: Honda''s current dispatch volumes and typical EV ramp curves.', NULL, 'escalating', 'medium', '{"2W": "H", "3W": "L", "HCV": "L", "LCV": "L", "4W_PV": "L", "Tractor": "L"}', '["EV Powertrain", "Thermal Management", "Vehicle Diagnostics", "Chassis Systems"]', '{}', false, '2026-03-26 11:21:49.30067+05:30', '2026-03-26 11:21:49.30067+05:30', '2026-03-26 11:21:49.30067+05:30', false, 'UNVERIFIED', NULL, NULL, '{}', '{}', '[]', '2026-03-26 11:21:49.30067+05:30', '2026-03-26 11:21:49.30067+05:30', 1); ON CONFLICT DO NOTHING;
INSERT INTO public.pestel_factors (id, code, name, category, selection_reasoning, likelihood, likelihood_reasoning, impact, impact_reasoning, origin_date, trend, time_horizon, segment_relevance, affected_pillars, source_ids, is_active, last_refreshed, created_at, updated_at, is_foundational, verification_verdict, verification_source, verification_evidence, financial_context, key_dates, citations, first_seen_date, last_confirmed_date, confirmation_count) VALUES (37, 'localisation_rules_of_origin', 'FTA Rules of Origin â€” 40-50% local value addition requirement', 'L', 'India-EU FTA''s Rules of Origin (40-50% local value addition for preferential tariff access) will determine which Bosch India products qualify. ICE powertrain lines (>60% local) qualify. EV powertrain lines with imported cells/inverters may not â€” creating a compliance gap.', 8, 'Score 9: RoO threshold is written into the FTA treaty text. Standard for EU FTAs. Compliance audit will begin when tariff phase-down starts.', 6, 'Score 7: Determines whether Bosch India''s EV components access zero-tariff rates. Failure to meet RoO means paying full tariff â€” eliminating the FTA benefit for EV lines. Critical for EV export strategy.', NULL, 'new', 'medium', '{"2W": "M", "3W": "L", "HCV": "L", "LCV": "M", "4W_PV": "H", "Tractor": "L"}', '["Energy", "Motion"]', '{11}', true, '2026-03-16 22:45:46.381831+05:30', '2026-03-16 22:45:46.381831+05:30', '2026-03-16 22:48:13.097302+05:30', true, 'UNVERIFIED', NULL, NULL, '{}', '{}', '[]', '2026-03-16 22:45:46.381831+05:30', '2026-03-16 22:45:46.381831+05:30', 1); ON CONFLICT DO NOTHING;
INSERT INTO public.pestel_factors (id, code, name, category, selection_reasoning, likelihood, likelihood_reasoning, impact, impact_reasoning, origin_date, trend, time_horizon, segment_relevance, affected_pillars, source_ids, is_active, last_refreshed, created_at, updated_at, is_foundational, verification_verdict, verification_source, verification_evidence, financial_context, key_dates, citations, first_seen_date, last_confirmed_date, confirmation_count) VALUES (28, 'ai_ml_in_vehicle_diagnostics', 'AI/ML predictive diagnostics replacing scheduled maintenance', 'T', 'AI-powered predictive maintenance (reading vehicle sensor data to predict failures) is being trialled by Bosch Workshop Services and fleet operators. Shifts Diagnostics from reactive (break-fix) to subscription-based (predictive), improving revenue quality.', 6, 'Score 7: Bosch Global has AI diagnostics products. India deployment is in early pilot with 3,000 workshops. Mass deployment by 2028 dependent on data connectivity.', 5, 'Score 6: Changes Bosch''s revenue model from hardware (diagnostic kit) to SaaS (subscription). Margin-accretive but takes 3-5 years to scale in India''s fragmented aftermarket.', NULL, 'new', 'medium', '{"2W": "L", "3W": "L", "HCV": "M", "LCV": "M", "4W_PV": "H", "Tractor": "L"}', '["Cloud", "Infotainment", "OS", "Services", "Solutions"]', '{18}', true, '2026-03-16 22:45:46.381831+05:30', '2026-03-16 22:45:46.381831+05:30', '2026-03-16 22:48:13.097302+05:30', false, 'UNVERIFIED', NULL, NULL, '{}', '{}', '[]', '2026-03-16 22:45:46.381831+05:30', '2026-03-16 22:45:46.381831+05:30', 1); ON CONFLICT DO NOTHING;
INSERT INTO public.pestel_factors (id, code, name, category, selection_reasoning, likelihood, likelihood_reasoning, impact, impact_reasoning, origin_date, trend, time_horizon, segment_relevance, affected_pillars, source_ids, is_active, last_refreshed, created_at, updated_at, is_foundational, verification_verdict, verification_source, verification_evidence, financial_context, key_dates, citations, first_seen_date, last_confirmed_date, confirmation_count) VALUES (22, 'agri_mechanisation_tractor', 'Agri mechanisation driving precision farming tractor demand', 'S', 'India''s 9.1 Lakh tractors/year market is seeing a shift toward precision farming (GPS guidance, sensor-based soil management) driven by government-subsidised equipment and farmer income growth. Expands Bosch''s Tractor segment beyond basic mechanisation.', 7, 'Score 7: Trend confirmed in SIAM/TAFE data but pace of adoption is slower than urban auto segments. Rural digital infrastructure limits connected farming adoption.', 4, 'Score 5: Meaningful for Bosch''s Tractor segment but limited total revenue impact vs 4W PV. Precision farming addressable market for Bosch-relevant electronics is ~â‚¹400-600 Cr.', NULL, 'escalating', 'long', '{"2W": "L", "3W": "L", "HCV": "L", "LCV": "L", "4W_PV": "L", "Tractor": "H"}', '["Actuators", "Compute", "OS"]', '{2}', true, '2026-03-16 22:45:46.381831+05:30', '2026-03-16 22:45:46.381831+05:30', '2026-03-16 22:48:13.097302+05:30', false, 'UNVERIFIED', NULL, NULL, '{}', '{}', '[]', '2026-03-16 22:45:46.381831+05:30', '2026-03-16 22:45:46.381831+05:30', 1); ON CONFLICT DO NOTHING;
INSERT INTO public.pestel_factors (id, code, name, category, selection_reasoning, likelihood, likelihood_reasoning, impact, impact_reasoning, origin_date, trend, time_horizon, segment_relevance, affected_pillars, source_ids, is_active, last_refreshed, created_at, updated_at, is_foundational, verification_verdict, verification_source, verification_evidence, financial_context, key_dates, citations, first_seen_date, last_confirmed_date, confirmation_count) VALUES (121, 'maruti_rail_logistics_scale_up_â€”_oem_supply_chain_', 'Maruti Rail Logistics Scale-Up â€” OEM Supply Chain Resilience Signal', 'E', 'Maruti''s Manesar rail siding dispatching 1 lakh vehicles in 9 months, targeting 35% rail share by FY31, signals a structural shift in OEM finished goods logistics. For Bosch as a Tier-1 supplier, this affects inbound component delivery scheduling, JIT inventory requirements, and plant-level logistics coordination. Rail-based dispatch also reduces OEM logistics costs, potentially increasing pressure on component supplier pricing.', 7, 'Operational data (1 lakh units in 9 months) confirms the rail model is functioning. Maruti''s FY31 target of 35% rail share is backed by dedicated infrastructure investment. Government push for rail freight also supports this trajectory.', 3, 'This is primarily an OEM logistics optimisation story with indirect implications for Bosch''s supply chain planning and inventory management. It does not directly affect component technology demand but may influence delivery lead times and working capital requirements. Impact on Bosch''s P&L is limited and indirect.', NULL, 'escalating', 'medium', '{"2W": "L", "3W": "L", "HCV": "L", "LCV": "L", "4W_PV": "H", "Tractor": "L"}', '["Compute", "OS"]', '{}', true, '2026-03-26 11:21:49.325434+05:30', '2026-03-26 11:21:49.325434+05:30', '2026-03-26 11:26:33.982723+05:30', false, 'UNVERIFIED', NULL, NULL, '{}', '{}', '[]', '2026-03-26 11:21:49.325434+05:30', '2026-03-26 11:21:49.325434+05:30', 1); ON CONFLICT DO NOTHING;
INSERT INTO public.pestel_factors (id, code, name, category, selection_reasoning, likelihood, likelihood_reasoning, impact, impact_reasoning, origin_date, trend, time_horizon, segment_relevance, affected_pillars, source_ids, is_active, last_refreshed, created_at, updated_at, is_foundational, verification_verdict, verification_source, verification_evidence, financial_context, key_dates, citations, first_seen_date, last_confirmed_date, confirmation_count) VALUES (17, 'semiconductor_supply_normalisation', 'Semiconductor supply chain normalised post-2023 shortage', 'E', 'Post-2023 chip shortage normalisation has restored supply of automotive-grade MCUs and SoCs. This removes the production bottleneck that capped Bosch''s ADAS and ECU output in FY23-24, allowing volume scale-up.', 9, 'Score 9: Industry reports (SEMI, IPC) confirm normalisation by mid-2024. Pockets of tight supply remain for EV power semiconductors (SiC). Score 9 reflects partial residual risk.', 6, 'Score 5: Mostly a tailwind removal (shortage gone) rather than a new positive. Critical for maintaining production ramp on ADAS and connected systems.', NULL, 'stable', 'immediate', '{"2W": "M", "3W": "L", "HCV": "M", "LCV": "M", "4W_PV": "H", "Tractor": "L"}', '["Body & Comfort", "Energy", "Infotainment", "Motion", "Semiconductors"]', '{19}', true, '2026-03-16 22:45:46.381831+05:30', '2026-03-16 22:45:46.381831+05:30', '2026-03-16 22:48:13.097302+05:30', false, 'UNVERIFIED', NULL, NULL, '{}', '{}', '[]', '2026-03-16 22:45:46.381831+05:30', '2026-03-16 22:45:46.381831+05:30', 1); ON CONFLICT DO NOTHING;
INSERT INTO public.pestel_factors (id, code, name, category, selection_reasoning, likelihood, likelihood_reasoning, impact, impact_reasoning, origin_date, trend, time_horizon, segment_relevance, affected_pillars, source_ids, is_active, last_refreshed, created_at, updated_at, is_foundational, verification_verdict, verification_source, verification_evidence, financial_context, key_dates, citations, first_seen_date, last_confirmed_date, confirmation_count) VALUES (2, 'us_tariffs_2025', 'US 25-50% tariffs reduced to 18% (Feb 2026)', 'P', 'As of April 2026, the US tariff situation on Indian auto exports remains fluid. The February 2026 bilateral deal (18% rate) may have been subject to further revision as US-India trade negotiations have continued. India''s auto component exports to the US (~$2.1B FY25) remain exposed to tariff uncertainty. Analysts should verify current effective tariff rates against USTR/CBP schedules and assess whether any formal US-India trade framework agreement has been concluded or is imminent. The 18% rate should be treated as potentially outdated and confirmed before use in any export competitiveness modelling.', 7, 'Score 9: 25-50% tariffs enacted April 2025 (confirmed). Bilateral deal at 18% from February 2026. Score 9 not 10 because further negotiations ongoing.', 5, 'Score 8: Even at 18%, India disadvantaged vs Mexico''s 0%. Directly hits Powertrain, Chassis, Electronics export volumes. OEMs already diversifying sourcing.', NULL, 'de-escalating', 'immediate', '{"2W": "M", "3W": "L", "HCV": "L", "LCV": "L", "4W_PV": "M", "Tractor": "L"}', '["Body & Comfort", "Energy", "Infotainment", "Motion", "Semiconductors"]', '{13}', true, '2026-04-09 11:49:28.362463+05:30', '2026-03-16 21:29:57.526355+05:30', '2026-03-16 22:48:13.097302+05:30', true, 'UNVERIFIED', NULL, NULL, '{}', '{}', '[]', '2026-03-16 21:29:57.526355+05:30', '2026-04-09 11:49:28.362463+05:30', 1); ON CONFLICT DO NOTHING;
INSERT INTO public.pestel_factors (id, code, name, category, selection_reasoning, likelihood, likelihood_reasoning, impact, impact_reasoning, origin_date, trend, time_horizon, segment_relevance, affected_pillars, source_ids, is_active, last_refreshed, created_at, updated_at, is_foundational, verification_verdict, verification_source, verification_evidence, financial_context, key_dates, citations, first_seen_date, last_confirmed_date, confirmation_count) VALUES (80, 'atul_auto_board_strengthening_â€”_3w_ev_governance_a', 'Atul Auto board strengthening â€” 3W EV governance and tech upgrade signal', 'P', 'Atul Auto''s appointment of a director with 40+ years of automotive and academic experience (NAMTECH/IIT Gandhinagar) signals a governance and technology upgrade at a key 3W OEM. Given the 3W segment''s 55% EV penetration, Atul Auto''s strategic direction will increasingly involve EV powertrain, diagnostics, and connectivity decisions that are relevant to Bosch''s component supply positioning in this segment.', 6, 'Board appointments are confirmed facts, but their translation into specific technology procurement decisions involves multiple steps and timelines. Atul Auto is a mid-tier 3W OEM with limited scale compared to Bajaj or TVS, reducing the immediacy of impact.', 2, 'Atul Auto''s annual volumes (~60,000-80,000 units) are modest. Even full Bosch content fitment across its EV range would represent a limited revenue opportunity. The factor is more relevant as a leading indicator of 3W segment professionalisation than as a direct revenue driver.', NULL, 'stable', 'medium', '{"2W": "L", "3W": "H", "HCV": "L", "LCV": "L", "4W_PV": "L", "Tractor": "L"}', '["Energy", "Infotainment", "Motion"]', '{}', true, '2026-03-16 23:47:58.163502+05:30', '2026-03-16 23:47:58.163502+05:30', '2026-03-16 23:47:58.163502+05:30', false, 'UNVERIFIED', NULL, NULL, '{}', '{}', '[]', '2026-03-16 23:47:58.163502+05:30', '2026-03-16 23:47:58.163502+05:30', 1); ON CONFLICT DO NOTHING;
INSERT INTO public.pestel_factors (id, code, name, category, selection_reasoning, likelihood, likelihood_reasoning, impact, impact_reasoning, origin_date, trend, time_horizon, segment_relevance, affected_pillars, source_ids, is_active, last_refreshed, created_at, updated_at, is_foundational, verification_verdict, verification_source, verification_evidence, financial_context, key_dates, citations, first_seen_date, last_confirmed_date, confirmation_count) VALUES (196, 'bharat_taxi_ev_driver_programme_â€”_government_backe', 'Bharat Taxi EV Driver Programme â€” Government-Backed 3W/4W EV Fleet Push', 'P', 'Union Minister Piyush Goyal''s launch of the Bharat Taxi driver onboarding programme with explicit promotion of CNG-to-EV income gains signals active government intervention to accelerate EV adoption in the commercial mobility segment. This directly affects 3W and 4W taxi fleet electrification, creating demand for EV powertrain components, charging infrastructure, and fleet telematics. Government-backed fleet programmes have historically been effective demand accelerators in India''s 3W segment (55% EV penetration already).', 8, 'The programme launch is confirmed at ministerial level, providing political commitment. India''s 3W EV penetration at 55% demonstrates that government-backed fleet electrification programmes work in this segment. Extension to 4W taxi fleets via Bharat Taxi is a logical policy progression with established institutional support.', 6, 'A government-backed taxi electrification programme targeting CNG-to-EV conversion across India''s estimated 1.5-2 million taxi fleet could accelerate EV powertrain, charging, and telematics demand significantly. For Tier-1 suppliers, this represents a fleet-scale demand signal for EV components in the 3W and entry-level 4W EV segments, with fleet telematics and diagnostics as high-value add-ons.', NULL, 'new', 'short', '{"2W": "L", "3W": "H", "HCV": "L", "LCV": "L", "4W_PV": "M", "Tractor": "L"}', '["Energy", "Infotainment"]', '{}', true, '2026-04-24 16:06:25.016681+05:30', '2026-04-24 16:06:25.016681+05:30', '2026-04-24 16:06:25.016681+05:30', false, 'UNVERIFIED', '', '', '{"market_opportunity": "Estimate based on: 500,000 taxi fleet EV conversion Ã— â‚¹1.5L EV component content uplift vs CNG = â‚¹7,500 Cr addressable component opportunity", "industry_investment": "N/A", "subsidy_or_incentive": "Income gain incentive for CNG-to-EV conversion highlighted by Minister; likely linked to FAME III / state EV subsidy frameworks", "government_investment": "N/A (programme investment quantum not disclosed in source)", "cost_impact_per_vehicle": "N/A"}', '{"announced": "2026-04", "effective": "2026-04", "completion": ""}', '[{"url": "https://auto.economictimes.indiatimes.com/news/aftermarket/piyush-goyal-launches-bharat-taxi-revolutionizing-driver-earnings-and-improving-urban-mobility/130482523", "claim": "Piyush Goyal launches Bharat Taxi driver onboarding programme, highlights EV income potential", "source": "ET Auto, 24 Apr 2026"}, {"url": "https://auto.economictimes.indiatimes.com/news/aftermarket/piyush-goyal-launches-bharat-taxi-revolutionizing-driver-earnings-and-improving-urban-mobility/130482523", "claim": "Minister highlighted the potential income gains for drivers through a shift from CNG to electric vehicles", "source": "ET Auto, 24 Apr 2026"}, {"url": "", "claim": "3W EV share: ~55% of total 3W sales in CY2025", "source": "Vahan Dashboard / Industry Baseline FY2025"}]', '2026-04-24 16:06:25.016681+05:30', '2026-04-24 16:06:25.016681+05:30', 1); ON CONFLICT DO NOTHING;
INSERT INTO public.pestel_factors (id, code, name, category, selection_reasoning, likelihood, likelihood_reasoning, impact, impact_reasoning, origin_date, trend, time_horizon, segment_relevance, affected_pillars, source_ids, is_active, last_refreshed, created_at, updated_at, is_foundational, verification_verdict, verification_source, verification_evidence, financial_context, key_dates, citations, first_seen_date, last_confirmed_date, confirmation_count) VALUES (197, 'mahindra_experiences_leadership_â€”_oem_mobility_as_', 'Mahindra Experiences Leadership â€” OEM Mobility-as-a-Service Diversification', 'S', 'Mahindra''s appointment of a former Unilever executive to lead ''Mahindra Experiences'' â€” covering Mahindra Adventure and Mahindra Holidays â€” signals OEM diversification into experiential mobility and lifestyle services. While not a direct component demand signal, this reflects the broader OEM trend of building software-defined, connected vehicle ecosystems where vehicle data and connectivity become revenue streams. For Tier-1 suppliers in infotainment, connectivity, and telematics pillars, OEM experiential service strategies create demand for always-on connected vehicle platforms.', 7, 'The appointment is confirmed and reflects a deliberate strategic choice to bring FMCG consumer experience expertise into automotive. Mahindra''s existing adventure and hospitality businesses provide a platform for vehicle-integrated experience services. The trend of OEMs monetising vehicle connectivity is well-established globally.', 3, 'The direct component demand impact is limited in the near term â€” this is a strategic positioning move rather than an immediate technology procurement signal. However, it validates the long-term direction of OEM investment in connected vehicle services, which will eventually require Tier-1 suppliers to provide more sophisticated telematics, V2X, and infotainment hardware/software. The impact is scored low given the indirect and long-term nature of the effect.', NULL, 'new', 'long', '{"2W": "L", "3W": "L", "HCV": "L", "LCV": "L", "4W_PV": "H", "Tractor": "L"}', '["OS", "Infotainment"]', '{}', true, '2026-04-24 16:06:25.016681+05:30', '2026-04-24 16:06:25.016681+05:30', '2026-04-24 16:06:25.016681+05:30', false, 'UNVERIFIED', '', '', '{"market_opportunity": "Estimate based on: India connected vehicle services market projected â‚¹15,000-20,000 Cr by 2030 (Estimate based on: global connected car services CAGR ~20%)", "industry_investment": "N/A (executive appointment; capex for Mahindra Experiences not disclosed)", "subsidy_or_incentive": "N/A", "government_investment": "N/A", "cost_impact_per_vehicle": "N/A"}', '{"announced": "2026-04", "effective": "2026-04", "completion": ""}', '[{"url": "https://auto.economictimes.indiatimes.com/news/passenger-vehicle/mahindra-welcomes-former-unilever-executive-shuchi-suri-as-evp-of-mahindra-experiences/130482787", "claim": "Mahindra appoints former Unilever executive Shuchi Suri as EVP â€“ Mahindra Experiences, to lead Mahindra Adventure and Mahindra Holidays", "source": "ET Auto, 24 Apr 2026"}, {"url": "https://auto.economictimes.indiatimes.com/news/passenger-vehicle/mahindra-welcomes-former-unilever-executive-shuchi-suri-as-evp-of-mahindra-experiences/130482787", "claim": "Suri brings over 22 years of global experience at Unilever and will report to Group CEO and MD Dr Anish Shah", "source": "ET Auto, 24 Apr 2026"}]', '2026-04-24 16:06:25.016681+05:30', '2026-04-24 16:06:25.016681+05:30', 1); ON CONFLICT DO NOTHING;
INSERT INTO public.pestel_factors (id, code, name, category, selection_reasoning, likelihood, likelihood_reasoning, impact, impact_reasoning, origin_date, trend, time_horizon, segment_relevance, affected_pillars, source_ids, is_active, last_refreshed, created_at, updated_at, is_foundational, verification_verdict, verification_source, verification_evidence, financial_context, key_dates, citations, first_seen_date, last_confirmed_date, confirmation_count) VALUES (122, 'hero_honda_2w_market_share_battle_intensifying', 'Hero-Honda 2W Market Share Battle Intensifying', 'S', 'Hero MotoCorp (5.5M units) and Honda (5.2M units) together command ~55% of India''s 2W market in FY26 11-month data. This duopoly concentration means Bosch''s 2W powertrain, OBD-II diagnostics, and EV powertrain component wins with either OEM have outsized revenue implications. Honda''s planned 2028 EV-exclusive facility signals a technology transition timeline Bosch must align to.', 10, 'Actual dispatches data from ET Auto (March 2026) confirms this is current reality, not a forecast. Both OEMs are actively expanding capacity, making this a durable structural feature of the 2W landscape.', 7, 'Combined ~10.7M units in 11 months implies FY26 full-year dispatch volumes exceeding FY25''s 1.96Cr retail figure. Bosch''s OBD-II sensor, fuel injection, and EV powertrain content per unit across these two OEMs represents hundreds of crores in annual revenue exposure. Customer concentration risk is high if either OEM verticalises components.', NULL, 'escalating', 'short', '{"2W": "H", "3W": "L", "HCV": "L", "LCV": "L", "4W_PV": "L", "Tractor": "L"}', '["Powertrain Solutions", "EV Powertrain", "Vehicle Diagnostics", "Body Electronics"]', '{}', false, '2026-03-26 11:21:49.30067+05:30', '2026-03-26 11:21:49.30067+05:30', '2026-03-26 11:21:49.30067+05:30', false, 'UNVERIFIED', NULL, NULL, '{}', '{}', '[]', '2026-03-26 11:21:49.30067+05:30', '2026-03-26 11:21:49.30067+05:30', 1); ON CONFLICT DO NOTHING;
INSERT INTO public.pestel_factors (id, code, name, category, selection_reasoning, likelihood, likelihood_reasoning, impact, impact_reasoning, origin_date, trend, time_horizon, segment_relevance, affected_pillars, source_ids, is_active, last_refreshed, created_at, updated_at, is_foundational, verification_verdict, verification_source, verification_evidence, financial_context, key_dates, citations, first_seen_date, last_confirmed_date, confirmation_count) VALUES (138, 'maruti_gujarat_â‚¹10,189_cr_capacity_expansion_â€”_pv_', 'Maruti Gujarat â‚¹10,189 Cr Capacity Expansion â€” PV Volume Uplift', 'E', 'Maruti Suzuki''s â‚¹10,189 Cr Gujarat plant investment (Phase 1: 250,000 units/year) signals sustained PV volume growth through FY28-30, directly expanding the addressable market for Bosch''s 4W PV technology pillars. As Maruti''s largest technology supplier, Bosch benefits proportionally from every incremental unit of capacity. The management reshuffle placing IT under expanded leadership also signals deeper digital/software integration.', 10, 'Board-approved capital investment with specific capacity figures (250,000 units Phase 1) reported by ET Auto March 2026. Maruti''s Gujarat facility is already operational; this is an expansion of confirmed infrastructure.', 7, '250,000 additional annual units at Bosch''s average content per vehicle (estimated â‚¹15,000â€“25,000 for powertrain, diagnostics, safety components) implies â‚¹375â€“625 Cr incremental annual revenue opportunity at full ramp. Rail-based dispatch scaling to 35% by FY31 also reduces logistics disruption risk for Bosch''s JIT supply model.', NULL, 'escalating', 'medium', '{"2W": "L", "3W": "L", "HCV": "L", "LCV": "L", "4W_PV": "H", "Tractor": "L"}', '["Powertrain Solutions", "Chassis Systems", "Body Electronics", "Vehicle Diagnostics", "Safety & Security"]', '{}', false, '2026-03-26 11:22:14.095204+05:30', '2026-03-26 11:22:14.095204+05:30', '2026-03-26 11:22:14.095204+05:30', false, 'UNVERIFIED', NULL, NULL, '{}', '{}', '[]', '2026-03-26 11:22:14.095204+05:30', '2026-03-26 11:22:14.095204+05:30', 1); ON CONFLICT DO NOTHING;
INSERT INTO public.pestel_factors (id, code, name, category, selection_reasoning, likelihood, likelihood_reasoning, impact, impact_reasoning, origin_date, trend, time_horizon, segment_relevance, affected_pillars, source_ids, is_active, last_refreshed, created_at, updated_at, is_foundational, verification_verdict, verification_source, verification_evidence, financial_context, key_dates, citations, first_seen_date, last_confirmed_date, confirmation_count) VALUES (181, 'cv_replacement_cycle_demand_surge_through_fy28', 'CV Replacement Cycle Demand Surge Through FY28', 'E', 'A structural replacement demand wave in commercial vehicles driven by ageing fleets and GST 2.0-related purchase deferrals creates a multi-year volume tailwind for HCV and LCV component suppliers. This is distinct from cyclical demand â€” it is a catch-up cycle that supports above-trend component offtake through FY28. Pillars including powertrain aftertreatment (BS-VI), AEBS, fleet telematics, and chassis systems are directly benefited.', 8, 'The replacement demand thesis is supported by documented fleet ageing data and the GST 2.0 price-change-driven deferral effect, as reported by ET Auto on 14 April 2026. CV replacement cycles are well-understood and historically reliable demand drivers; the FY28 horizon aligns with typical 7-10 year fleet replacement patterns for vehicles purchased in FY18-20.', 7, 'HCV (4.4L units FY25) and LCV (5.2L units FY25) together represent a significant component demand base. A replacement-driven 10-15% volume uplift through FY28 translates to approximately 90,000-140,000 incremental CV units annually. At average component content of â‚¹3-5 Lakh per HCV and â‚¹1.5-2.5 Lakh per LCV, this represents â‚¹2,700-7,000 Cr in incremental annual component demand.', NULL, 'escalating', 'short', '{"2W": "L", "3W": "L", "HCV": "H", "LCV": "H", "4W_PV": "L", "Tractor": "L"}', '["Motion", "Energy", "Infotainment", "ADAS"]', '{}', true, '2026-04-15 14:28:35.234252+05:30', '2026-04-15 14:28:35.234252+05:30', '2026-04-15 14:28:35.234252+05:30', false, 'UNVERIFIED', '', '', '{"market_opportunity": "Estimate based on: 90,000-140,000 incremental CV units Ã— â‚¹2-5 Lakh component content = â‚¹1,800-7,000 Cr incremental annual opportunity through FY28", "industry_investment": "N/A", "subsidy_or_incentive": "Vehicle scrappage policy incentives for fleet renewal (existing factor)", "government_investment": "â‚¹11.1 Lakh Crore PM Gati Shakti infra investment (existing factor) supporting freight demand", "cost_impact_per_vehicle": "N/A"}', '{"announced": "2026-04", "effective": "2026-04", "completion": "2028-03"}', '[{"url": "https://auto.economictimes.indiatimes.com/news/commercial-vehicle/commercial-vehicle-growth-to-remain-robust-till-fy28-on-replacement-demand-report/130255670", "claim": "Commercial vehicle growth to remain robust till FY28 driven by delayed vehicle replacements due to GST 2.0-related price changes and an ageing fleet", "source": "ET Auto, 14 April 2026"}]', '2026-04-15 14:28:35.234252+05:30', '2026-04-15 14:28:35.234252+05:30', 1); ON CONFLICT DO NOTHING;
INSERT INTO public.pestel_factors (id, code, name, category, selection_reasoning, likelihood, likelihood_reasoning, impact, impact_reasoning, origin_date, trend, time_horizon, segment_relevance, affected_pillars, source_ids, is_active, last_refreshed, created_at, updated_at, is_foundational, verification_verdict, verification_source, verification_evidence, financial_context, key_dates, citations, first_seen_date, last_confirmed_date, confirmation_count) VALUES (156, 'honda_india_2w_global_hub_â€”_dedicated_ev_facility_', 'Honda India 2W Global Hub â€” Dedicated EV Facility 2028', 'E', 'Honda reaffirming India as a global 2W hub with a dedicated EV facility planned for 2028 represents a multi-year, high-volume OEM commitment. This creates a long-duration procurement window for Bosch''s EV powertrain, motor controllers, BMS, and OBD-II systems. Honda''s global scale means India-developed components could be exported, amplifying Bosch''s export revenue potential.', 8, 'Honda has publicly committed to the Rajasthan capacity expansion and the 2028 EV facility â€” these are announced strategic investments, not speculative. Honda''s 5.2M unit FY26 run-rate provides the volume base to justify dedicated EV manufacturing.', 7, 'Honda''s EV facility could produce 500,000-1M e-2W annually by 2030 (estimate based on: Honda''s global EV production scale and India market trajectory). At â‚¹8,000-12,000 Bosch EV content per unit, this represents â‚¹4,000-12,000 Cr potential annual revenue at scale. Export multiplier adds further upside for Bosch''s global supply chain positioning.', NULL, 'escalating', 'medium', '{"2W": "H", "3W": "L", "HCV": "L", "LCV": "L", "4W_PV": "L", "Tractor": "L"}', '["EV Powertrain", "Powertrain Solutions", "Vehicle Diagnostics", "Body Electronics", "Manufacturing & Industry 4.0"]', '{}', false, '2026-03-26 11:26:33.982723+05:30', '2026-03-26 11:26:33.982723+05:30', '2026-03-26 11:26:33.982723+05:30', false, 'UNVERIFIED', NULL, NULL, '{}', '{}', '[]', '2026-03-26 11:26:33.982723+05:30', '2026-03-26 11:26:33.982723+05:30', 1); ON CONFLICT DO NOTHING;
INSERT INTO public.pestel_factors (id, code, name, category, selection_reasoning, likelihood, likelihood_reasoning, impact, impact_reasoning, origin_date, trend, time_horizon, segment_relevance, affected_pillars, source_ids, is_active, last_refreshed, created_at, updated_at, is_foundational, verification_verdict, verification_source, verification_evidence, financial_context, key_dates, citations, first_seen_date, last_confirmed_date, confirmation_count) VALUES (100, 'jlr_cyberattack_â€”_oem_production_vulnerability_sig', 'JLR Cyberattack â€” OEM Production Vulnerability Signal', 'T', 'JLR''s 2025 cyberattack caused a five-week production shutdown and material financial losses for Tata Motors, directly signalling systemic cybersecurity risk across OEM supply chains. For Bosch, this validates demand for its Safety & Security pillar (cybersecurity, UN R155 compliance) and creates urgency for embedded security in connected components. It also highlights supply chain disruption risk for Bosch''s own component deliveries to JLR and other OEMs.', 9, 'The JLR incident is confirmed (ET Auto, March 2026). Automotive OEMs are among the top targets for ransomware globally; ENISA 2024 reported a 300% increase in automotive sector cyberattacks since 2021. With increasing software-defined vehicle architecture, attack surfaces are expanding across all OEMs Bosch supplies.', 8, 'A five-week OEM shutdown directly disrupts Bosch''s component order flow and revenue recognition. More strategically, it accelerates OEM demand for Bosch''s cybersecurity solutions and secure ECU architectures. Estimate: a similar shutdown at a major India OEM (Maruti, Tata, Hyundai) could impact â‚¹500-800 Cr of Bosch component revenue per week.', NULL, 'escalating', 'immediate', '{"2W": "M", "3W": "L", "HCV": "M", "LCV": "M", "4W_PV": "H", "Tractor": "L"}', '["Safety & Security", "Software & Services", "Vehicle Diagnostics"]', '{}', false, '2026-03-17 16:31:52.563836+05:30', '2026-03-17 16:31:52.563836+05:30', '2026-03-17 16:31:52.563836+05:30', false, 'UNVERIFIED', NULL, NULL, '{}', '{}', '[]', '2026-03-17 16:31:52.563836+05:30', '2026-03-17 16:31:52.563836+05:30', 1); ON CONFLICT DO NOTHING;
INSERT INTO public.pestel_factors (id, code, name, category, selection_reasoning, likelihood, likelihood_reasoning, impact, impact_reasoning, origin_date, trend, time_horizon, segment_relevance, affected_pillars, source_ids, is_active, last_refreshed, created_at, updated_at, is_foundational, verification_verdict, verification_source, verification_evidence, financial_context, key_dates, citations, first_seen_date, last_confirmed_date, confirmation_count) VALUES (198, 'renault_chennai_global_hub_â€”_export_linked_compone', 'Renault Chennai Global Hub â€” Export-Linked Component Volume Uplift', 'E', 'Renault''s strategic repositioning of Chennai as a nerve centre for its global operations signals sustained and potentially expanded production volumes at the Tamil Nadu facility, with direct implications for Tier-1 suppliers serving Renault''s local supply chain. Export-linked production at Chennai creates demand for globally compliant powertrain, safety, and electronics components, and positions India-based suppliers for multi-market supply mandates.', 7, 'Renault''s 15-year India presence and the explicit ''global strategy'' framing reported by ET Auto indicate a deliberate strategic pivot rather than incremental activity. However, Renault''s India history includes prior promise-and-setback cycles, introducing execution risk that moderates the likelihood score.', 6, 'If Chennai becomes a genuine global export hub, annual production volumes could scale to 200,000â€“300,000 units (estimate), generating â‚¹3,000â€“5,000 Cr in incremental component demand for local Tier-1 suppliers. The export dimension also requires Euro 7 / RDE-compliant powertrain and safety components, elevating per-vehicle content value.', NULL, 'escalating', 'medium', '{"2W": "L", "3W": "L", "HCV": "L", "LCV": "M", "4W_PV": "H", "Tractor": "L"}', '["Infotainment", "Motion", "ADAS"]', '{}', false, '2026-04-27 16:36:33.619882+05:30', '2026-04-27 16:36:33.619882+05:30', '2026-04-27 16:36:33.619882+05:30', false, 'UNVERIFIED', '', '', '{"market_opportunity": "Incremental Tier-1 component demand estimated â‚¹3,000â€“5,000 Cr annually at full hub scale (Estimate)", "industry_investment": "Renault India capex for Chennai hub expansion â€” undisclosed; Renault global committed â‚¬1B+ to India strategy (Estimate based on global announcements)", "subsidy_or_incentive": "PLI Auto scheme for export-oriented production; Tamil Nadu EV/auto policy incentives", "government_investment": "Tamil Nadu state incentives for auto manufacturing (specific quantum undisclosed)", "cost_impact_per_vehicle": "N/A"}', '{"announced": "2026-04", "effective": "2026-04", "completion": "2028-12"}', '[{"url": "https://auto.economictimes.indiatimes.com/news/passenger-vehicle/chennai-key-hub-for-renaults-global-strategy-and-future-growth/130542341", "claim": "Chennai emerges as nerve centre of Renault''s global strategy, representing a turning point in Renault''s 15-year India journey", "source": "ET Auto, 27 Apr 2026"}]', '2026-04-27 16:36:33.619882+05:30', '2026-04-27 16:36:33.619882+05:30', 1); ON CONFLICT DO NOTHING;
INSERT INTO public.pestel_factors (id, code, name, category, selection_reasoning, likelihood, likelihood_reasoning, impact, impact_reasoning, origin_date, trend, time_horizon, segment_relevance, affected_pillars, source_ids, is_active, last_refreshed, created_at, updated_at, is_foundational, verification_verdict, verification_source, verification_evidence, financial_context, key_dates, citations, first_seen_date, last_confirmed_date, confirmation_count) VALUES (168, 'oem_vehicle_price_increases_â€”_input_cost_pass_thro', 'OEM Vehicle Price Increases â€” Input Cost Pass-Through Pressure', 'E', 'Mahindra''s price increase of up to 2.5% (avg 1.6% on ICE SUVs and CVs) signals rising input cost pressure being passed downstream to consumers. For Tier-1 suppliers, this creates a dual squeeze: OEMs will intensify cost-reduction demands on suppliers to protect their own margins, while rising vehicle prices risk dampening volume growth in price-sensitive segments.', 8, 'Mahindra''s price hike is confirmed effective from April 2026, per ET Auto. Rising commodity costs (steel, aluminium, copper) and BS-VI Stage 2 compliance costs are well-documented structural pressures on OEM cost structures.', 7, 'A 1.6â€“2.5% OEM price increase typically translates to 3â€“5% cost reduction demands on Tier-1 suppliers in the subsequent sourcing cycle (Estimate based on: industry norm of OEM margin protection via supplier negotiation). For a â‚¹6.73L Cr industry, a 3% margin compression on Tier-1 revenues = â‚¹20,000 Cr+ EBITDA risk.', NULL, 'escalating', 'immediate', '{"2W": "L", "3W": "L", "HCV": "H", "LCV": "H", "4W_PV": "H", "Tractor": "L"}', '["Compute", "Infotainment", "Motion"]', '{}', true, '2026-04-03 11:14:00.65269+05:30', '2026-04-03 11:14:00.65269+05:30', '2026-04-03 11:14:00.65269+05:30', false, 'UNVERIFIED', '', '', '{"market_opportunity": "N/A", "industry_investment": "N/A", "subsidy_or_incentive": "N/A", "government_investment": "N/A", "cost_impact_per_vehicle": "â‚¹8,000â€“25,000 per vehicle estimated OEM price increase (1.6â€“2.5% on â‚¹5â€“10L vehicle); supplier cost-down demand of â‚¹2,000â€“8,000 per vehicle (Estimate)"}', '{"announced": "2026-04-02", "effective": "2026-04-01", "completion": ""}', '[{"url": "https://auto.economictimes.indiatimes.com/news/industry/mahindra-increases-suv-and-vehicle-prices-by-up-to-25-due-to-rising-costs/129981457", "claim": "Mahindra increased SUV and vehicle prices by up to 2.5%; average increase across ICE SUV and commercial vehicle portfolio will be about 1.6%", "source": "ET Auto, 02 Apr 2026"}]', '2026-04-03 11:14:00.65269+05:30', '2026-04-03 11:14:00.65269+05:30', 1); ON CONFLICT DO NOTHING;
INSERT INTO public.pestel_factors (id, code, name, category, selection_reasoning, likelihood, likelihood_reasoning, impact, impact_reasoning, origin_date, trend, time_horizon, segment_relevance, affected_pillars, source_ids, is_active, last_refreshed, created_at, updated_at, is_foundational, verification_verdict, verification_source, verification_evidence, financial_context, key_dates, citations, first_seen_date, last_confirmed_date, confirmation_count) VALUES (5, 'pli_scheme_disbursement', 'PLI scheme â‚¹35,657 Cr invested, â‚¹2,322 Cr disbursed', 'P', 'Largest government push for domestic auto component manufacturing. Directly subsidises advanced manufacturing (Industry 4.0, EV). Low disbursement rate (6.5%) signals compliance challenges.', 8, 'Score 8: Investments confirmed. Disbursement only 6.5% of investment â€” many companies haven''t met targets. Continued disbursement depends on production thresholds.', 6, 'Score 6: Actual disbursement modest (â‚¹2,322 Cr across entire industry). More about signalling government commitment than direct financial impact on Bosch.', NULL, 'escalating', 'medium', '{"2W": "H", "3W": "L", "HCV": "L", "LCV": "M", "4W_PV": "H", "Tractor": "L"}', '["Compute", "Energy", "Motion", "Semiconductors", "Solutions"]', '{10}', true, '2026-03-16 21:29:57.526355+05:30', '2026-03-16 21:29:57.526355+05:30', '2026-03-16 22:48:13.097302+05:30', false, 'UNVERIFIED', NULL, NULL, '{}', '{}', '[]', '2026-03-16 21:29:57.526355+05:30', '2026-03-16 21:29:57.526355+05:30', 1); ON CONFLICT DO NOTHING;
INSERT INTO public.pestel_factors (id, code, name, category, selection_reasoning, likelihood, likelihood_reasoning, impact, impact_reasoning, origin_date, trend, time_horizon, segment_relevance, affected_pillars, source_ids, is_active, last_refreshed, created_at, updated_at, is_foundational, verification_verdict, verification_source, verification_evidence, financial_context, key_dates, citations, first_seen_date, last_confirmed_date, confirmation_count) VALUES (94, 'maruti_suv_expansion_â€”_7_new_models,_19.6%_share', 'Maruti SUV Expansion â€” 7 New Models, 19.6% Share', 'E', 'Maruti Suzuki''s SUV market share rising to 19.6% in FY26 and its plan to launch seven new SUV models over five to six years represents a structural shift in India''s largest OEM''s product portfolio toward higher-content vehicles. SUVs carry significantly more Bosch-addressable content than hatchbacks â€” ADAS, advanced chassis, thermal management, and connectivity. As Maruti''s largest domestic supplier relationship, this is a direct revenue expansion signal for Bosch India.', 9, 'Maruti''s SUV strategy is publicly confirmed and already evidenced by 19.6% market share in FY26 (ET Auto, March 2026). The seven-model pipeline over five to six years is a committed OEM roadmap, not speculative. Maruti''s execution track record on product launches is strong.', 5, 'Maruti commands ~40%+ of India''s PV market. A shift toward SUVs â€” which carry 30â€“50% higher component content per vehicle than entry hatchbacks â€” materially increases Bosch''s per-vehicle revenue opportunity. Seven new SUV models over five to six years at projected volumes of 50,000â€“150,000 units each represents a multi-thousand-crore content opportunity across powertrain, ADAS, chassis, and body electronics.', NULL, 'escalating', 'short', '{"2W": "L", "3W": "L", "HCV": "L", "LCV": "L", "4W_PV": "H", "Tractor": "L"}', '["ADAS", "Energy", "Infotainment", "Motion"]', '{}', true, '2026-03-17 16:31:52.361522+05:30', '2026-03-17 16:31:52.361522+05:30', '2026-03-17 16:31:52.361522+05:30', false, 'UNVERIFIED', NULL, NULL, '{}', '{}', '[]', '2026-03-17 16:31:52.361522+05:30', '2026-03-17 16:31:52.361522+05:30', 1); ON CONFLICT DO NOTHING;
INSERT INTO public.pestel_factors (id, code, name, category, selection_reasoning, likelihood, likelihood_reasoning, impact, impact_reasoning, origin_date, trend, time_horizon, segment_relevance, affected_pillars, source_ids, is_active, last_refreshed, created_at, updated_at, is_foundational, verification_verdict, verification_source, verification_evidence, financial_context, key_dates, citations, first_seen_date, last_confirmed_date, confirmation_count) VALUES (170, 'suzuki_burgman_125cc_refresh_â€”_ice_scooter_segment', 'Suzuki Burgman 125cc Refresh â€” ICE Scooter Segment Premiumisation', 'E', 'The refreshed Suzuki Burgman Street at â‚¹1.01â€“1.13L signals continued OEM investment in premium ICE scooters alongside EV transition. This sustains demand for advanced body electronics, connected features, and OBD-II compliant powertrain components in the 125cc segment â€” a volume segment that Tier-1 suppliers cannot ignore even as EV transition accelerates.', 9, 'Product launch is confirmed with pricing and market availability per ET Auto April 2026. The 125cc scooter segment is the fastest-growing sub-segment within 2W, with Hero MotoCorp scooter dispatches up 53.18% in March 2026.', 3, 'The Burgman refresh is a single model launch with limited direct component volume impact. However, it validates the premium ICE scooter segment''s resilience, sustaining demand for OBD-II compliant ECUs, connected instrument clusters, and advanced body electronics across the 125cc+ scooter category â€” a segment of ~30â€“40L units annually.', NULL, 'stable', 'immediate', '{"2W": "L", "3W": "L", "HCV": "L", "LCV": "L", "4W_PV": "H", "Tractor": "L"}', '["Infotainment", "Motion"]', '{}', true, '2026-04-03 11:14:00.65269+05:30', '2026-04-03 11:14:00.65269+05:30', '2026-04-03 11:14:00.65269+05:30', false, 'UNVERIFIED', '', '', '{"market_opportunity": "Estimate based on: 125cc+ scooter segment ~35L units/year; premium electronics content â‚¹3,000â€“5,000/unit = â‚¹1,050â€“1,750 Cr annual component opportunity", "industry_investment": "Suzuki Motorcycle India product development investment (undisclosed)", "subsidy_or_incentive": "N/A", "government_investment": "N/A", "cost_impact_per_vehicle": "N/A"}', '{"announced": "2026-04-02", "effective": "2026-04-02", "completion": ""}', '[{"url": "https://auto.economictimes.indiatimes.com/news/two-wheelers/suzuki-motorcycle-india-launches-updated-burgman-to-boost-scooter-sales/129984457", "claim": "Refreshed Suzuki Burgman Street launched at â‚¹1,01,944 to â‚¹1,13,220 to strengthen position in 125cc scooter segment", "source": "ET Auto, 02 Apr 2026"}, {"url": "https://auto.economictimes.indiatimes.com/news/two-wheelers/hero-motocorp-march-dispatches-rise-9-to-5-98-lakh-units/129965603", "claim": "Hero MotoCorp scooter dispatches surged 53.18% to 65,815 units in March 2026", "source": "ET Auto, 02 Apr 2026"}]', '2026-04-03 11:14:00.65269+05:30', '2026-04-03 11:14:00.65269+05:30', 1); ON CONFLICT DO NOTHING;
INSERT INTO public.pestel_factors (id, code, name, category, selection_reasoning, likelihood, likelihood_reasoning, impact, impact_reasoning, origin_date, trend, time_horizon, segment_relevance, affected_pillars, source_ids, is_active, last_refreshed, created_at, updated_at, is_foundational, verification_verdict, verification_source, verification_evidence, financial_context, key_dates, citations, first_seen_date, last_confirmed_date, confirmation_count) VALUES (173, 'fy26_record_pv_sales_amid_gas_shortage_â€”_supply_si', 'FY26 Record PV Sales Amid Gas Shortage â€” Supply-Side Geopolitical Risk', 'P', 'Record FY26 PV sales coinciding with gas shortage concerns and geopolitical supply-side risks signals a critical dual dynamic: strong demand provides volume tailwinds for component suppliers, but energy/fuel supply disruptions could create production and logistics cost volatility. The gas shortage reference likely pertains to CNG/LPG supply constraints affecting both manufacturing operations and consumer fuel economics, with downstream implications for powertrain mix and aftermarket demand.', 6, 'ET Auto (01 April 2026) explicitly flags ''supply-side risks triggered by geopolitical tensions'' as major headwinds for FY27 despite record FY26 performance. West Asia conflict (existing factor) corroborates the geopolitical risk vector. Gas shortage is confirmed as a concurrent event during the record sales period.', 6, 'A sustained gas/CNG shortage would accelerate consumer shift away from CNG variants toward petrol/diesel or EV, reshaping powertrain component mix demand. For Tier-1 suppliers, manufacturing energy costs could rise 15â€“25% if industrial gas prices spike, directly compressing margins. The FY26 record base also creates a high-growth comparison challenge for FY27 component demand forecasting.', NULL, 'escalating', 'short', '{"2W": "L", "3W": "M", "HCV": "L", "LCV": "M", "4W_PV": "H", "Tractor": "L"}', '["Services", "Energy", "Motion"]', '{}', true, '2026-04-03 13:42:43.951941+05:30', '2026-04-03 13:42:43.951941+05:30', '2026-04-03 13:42:43.951941+05:30', false, 'UNVERIFIED', '', '', '{"market_opportunity": "Estimate based on: FY26 PV market ~4.7M units at record high; component content â‚¹80,000â€“1,50,000/vehicle = â‚¹3.76â€“7.05 Lakh Cr total PV component addressable market", "industry_investment": "N/A", "subsidy_or_incentive": "N/A", "government_investment": "N/A", "cost_impact_per_vehicle": "N/A"}', '{"announced": "2026-04", "effective": "2026-04", "completion": ""}', '[{"url": "https://auto.economictimes.indiatimes.com/news/passenger-vehicle/march-2026-sees-record-high-pv-sales-amid-gas-shortage-concerns/129956543", "claim": "March 2026 sees record high PV sales; demand resilience and GST-led momentum set stage for strong FY27 although supply-side risks triggered by geopolitical tensions may serve as major headwinds", "source": "ET Auto, 01 April 2026"}, {"url": "https://auto.economictimes.indiatimes.com/news/passenger-vehicle/march-2026-sees-record-high-pv-sales-amid-gas-shortage-concerns/129956543", "claim": "Gas shortage no hurdle as March PV sales hit record high; Maruti Suzuki, Tata Motors lead pack", "source": "ET Auto, 01 April 2026"}]', '2026-04-03 13:42:43.951941+05:30', '2026-04-03 13:42:43.951941+05:30', 1); ON CONFLICT DO NOTHING;
INSERT INTO public.pestel_factors (id, code, name, category, selection_reasoning, likelihood, likelihood_reasoning, impact, impact_reasoning, origin_date, trend, time_horizon, segment_relevance, affected_pillars, source_ids, is_active, last_refreshed, created_at, updated_at, is_foundational, verification_verdict, verification_source, verification_evidence, financial_context, key_dates, citations, first_seen_date, last_confirmed_date, confirmation_count) VALUES (98, 'maruti_suv_push_â€”_7_new_models_driving_premium_con', 'Maruti SUV push â€” 7 new models driving premium content demand', 'E', 'Maruti Suzuki''s SUV market share rising to 19.6% in FY26 and its plan to launch seven new SUV models over five to six years signals a structural shift in India''s largest OEM''s product mix toward higher-content vehicles. SUVs carry significantly higher Bosch content per unit versus hatchbacks â€” ADAS, advanced braking, connected infotainment, and thermal management are all standard or near-standard in this segment. As India''s volume leader pivots to SUVs, Bosch''s content-per-vehicle economics improve materially.', 9, 'Maruti''s SUV strategy is publicly committed with specific model pipeline disclosures. The 19.6% SUV share in FY26 is a verified data point, and the broader India SUV trend has been consistent since FY22. Seven models over five to six years is a credible, funded commitment from a company with â‚¹40,000+ Cr cash reserves.', 5, 'Maruti sells ~1.8-2.0M units annually. If SUV mix rises from ~20% to 35-40% over five years (estimate based on stated strategy), that is an additional 270,000-400,000 higher-content units per year. Bosch content uplift per SUV versus hatchback is estimated at â‚¹8,000-15,000 (ADAS, ESC, advanced braking), implying â‚¹200-600 Cr incremental annual opportunity at full ramp.', NULL, 'escalating', 'short', '{"2W": "L", "3W": "L", "HCV": "L", "LCV": "L", "4W_PV": "H", "Tractor": "L"}', '["Energy", "Infotainment", "Motion"]', '{}', false, '2026-03-17 16:32:41.583165+05:30', '2026-03-17 16:32:41.583165+05:30', '2026-03-17 16:32:41.583165+05:30', false, 'UNVERIFIED', NULL, NULL, '{}', '{}', '[]', '2026-03-17 16:32:41.583165+05:30', '2026-03-17 16:32:41.583165+05:30', 1); ON CONFLICT DO NOTHING;
INSERT INTO public.pestel_factors (id, code, name, category, selection_reasoning, likelihood, likelihood_reasoning, impact, impact_reasoning, origin_date, trend, time_horizon, segment_relevance, affected_pillars, source_ids, is_active, last_refreshed, created_at, updated_at, is_foundational, verification_verdict, verification_source, verification_evidence, financial_context, key_dates, citations, first_seen_date, last_confirmed_date, confirmation_count) VALUES (175, 'ev_market_10m_annual_sales_by_2030_â€”_electrificati', 'EV Market 10M Annual Sales by 2030 â€” Electrification Scale Projection', 'T', 'IBEF''s projection of 10 million EV sales annually by 2030 in India â€” against a CY2025 base of 2.3 million â€” implies a 4.3Ã— volume increase in 5 years, representing the most consequential technology transition signal for Tier-1 auto component suppliers. This projection, if directionally accurate, requires immediate investment decisions in EV powertrain, BMS, thermal management, and charging infrastructure components to capture the supply window before global competitors establish India positions.', 6, 'The 10M EV by 2030 projection requires a CAGR of ~34% from the 2.3M CY2025 base. While 3W EV penetration at 55% and 4W EV growth at 82% YoY provide momentum, 2W EV at only 6% penetration and 4W EV at 3% indicate significant headroom but also structural barriers (price, charging infrastructure, range anxiety). Rated 6 for directional validity with execution uncertainty.', 9, '10M EV units annually would represent approximately 30â€“35% of projected total vehicle sales by 2030. At an average EV-specific component content of â‚¹80,000â€“2,00,000 per vehicle (depending on segment), this implies an EV component market of â‚¹80,000â€“2,00,000 Cr annually â€” a transformational opportunity. Tier-1 suppliers without EV capability by 2027â€“28 risk structural exclusion from this demand pool.', NULL, 'escalating', 'medium', '{"2W": "H", "3W": "H", "HCV": "M", "LCV": "M", "4W_PV": "H", "Tractor": "L"}', '["OS", "Infotainment", "Energy"]', '{}', true, '2026-04-03 13:42:43.951941+05:30', '2026-04-03 13:42:43.951941+05:30', '2026-04-03 13:42:43.951941+05:30', false, 'UNVERIFIED', '', '', '{"market_opportunity": "EV market projected US$206 billion by 2030 per IBEF; 10M annual EV sales target", "industry_investment": "N/A", "subsidy_or_incentive": "GST 5% on EVs; PLI for advanced chemistry cells; FAME subsidies for 2W/3W/buses", "government_investment": "FAME III â‚¹2,671 Cr for EV charging (FY2025â€“27); PM E-DRIVE scheme", "cost_impact_per_vehicle": "N/A"}', '{"announced": "2025-11", "effective": "2025-01", "completion": "2030-12"}', '[{"url": "", "claim": "By 2030, ten million EVs could be sold each year; the EV market is expected to reach US$206 billion by 2030", "source": "IBEF Auto Components Industry Report, November 2025"}, {"url": "", "claim": "EV sales CY2025: 2.3 million units, approximately 8% of total", "source": "Vahan Dashboard, CY2025"}]', '2026-04-03 13:42:43.951941+05:30', '2026-04-03 13:42:43.951941+05:30', 1); ON CONFLICT DO NOTHING;
INSERT INTO public.pestel_factors (id, code, name, category, selection_reasoning, likelihood, likelihood_reasoning, impact, impact_reasoning, origin_date, trend, time_horizon, segment_relevance, affected_pillars, source_ids, is_active, last_refreshed, created_at, updated_at, is_foundational, verification_verdict, verification_source, verification_evidence, financial_context, key_dates, citations, first_seen_date, last_confirmed_date, confirmation_count) VALUES (102, 'oem_cyberattack_supply_chain_disruption_â€”_revenue_', 'OEM Cyberattack Supply Chain Disruption â€” Revenue Concentration Risk', 'L', 'The JLR cyberattack''s five-week production shutdown exposes a legal and contractual risk for Bosch: force majeure clauses, take-or-pay obligations, and inventory carrying costs when OEM production halts unexpectedly. As Bosch supplies multiple large OEMs (Maruti, Tata, Hyundai, JLR), a cyberattack at any single OEM can create cascading inventory and cash flow disruptions. This is distinct from the technology cybersecurity factor and focuses on contractual/legal exposure.', 6, 'The JLR precedent is confirmed. India''s OEMs are increasingly digitised but cybersecurity maturity varies significantly. CERT-In reported 1.3 million cybersecurity incidents in India in 2023. The probability of at least one major India OEM experiencing a significant cyber disruption within 3 years is material.', 5, 'Bosch India''s revenue concentration â€” top 5 OEM customers likely represent 60-70% of India revenue (Estimate based on: industry norm for Tier-1 suppliers). A five-week shutdown at Maruti (India''s largest OEM, ~40% PV market share) could impact â‚¹300-500 Cr of Bosch component deliveries. Contract review for cyber force majeure clauses is a CFO-level action item.', NULL, 'escalating', 'immediate', '{"2W": "L", "3W": "L", "HCV": "M", "LCV": "M", "4W_PV": "H", "Tractor": "L"}', '["ADAS", "Compute", "OS"]', '{}', false, '2026-03-17 16:31:52.563836+05:30', '2026-03-17 16:31:52.563836+05:30', '2026-03-17 16:31:52.563836+05:30', false, 'UNVERIFIED', NULL, NULL, '{}', '{}', '[]', '2026-03-17 16:31:52.563836+05:30', '2026-03-17 16:31:52.563836+05:30', 1); ON CONFLICT DO NOTHING;
INSERT INTO public.pestel_factors (id, code, name, category, selection_reasoning, likelihood, likelihood_reasoning, impact, impact_reasoning, origin_date, trend, time_horizon, segment_relevance, affected_pillars, source_ids, is_active, last_refreshed, created_at, updated_at, is_foundational, verification_verdict, verification_source, verification_evidence, financial_context, key_dates, citations, first_seen_date, last_confirmed_date, confirmation_count) VALUES (153, 'maruti_gujarat_â‚¹10,189_cr_expansion_â€”_pv_capacity_', 'Maruti Gujarat â‚¹10,189 Cr Expansion â€” PV Capacity Surge to 250K Units', 'E', 'Maruti Suzuki''s â‚¹10,189 Cr Gujarat plant investment adds 250,000 units Phase 1 capacity, signalling sustained PV volume growth beyond FY26. As Bosch''s largest 4W PV customer in India, this directly expands the addressable market for powertrain, ADAS, chassis, and body electronics content per vehicle. The simultaneous IT leadership reshuffle (Dr. Tapan Sahoo) signals accelerating software-defined vehicle and connectivity investment.', 9, 'Board-approved capital infusion with disclosed phased capacity plan â€” high execution certainty. Maruti has a track record of delivering Gujarat plant phases on schedule. FY26 PV market already at 4.7M units with double-digit H2 growth.', 8, '250,000 incremental units at â‚¹15,000-25,000 Bosch content per vehicle (estimate based on: current 4W PV content benchmarks across powertrain, chassis, and electronics) implies â‚¹3,750-6,250 Cr additional addressable revenue at full ramp. Maruti''s IT reshuffle also signals connected car and OTA software procurement acceleration.', NULL, 'escalating', 'medium', '{"2W": "L", "3W": "L", "HCV": "L", "LCV": "L", "4W_PV": "H", "Tractor": "L"}', '["Infotainment", "Motion", "OS"]', '{}', false, '2026-03-26 11:26:33.982723+05:30', '2026-03-26 11:26:33.982723+05:30', '2026-03-26 11:26:33.982723+05:30', false, 'UNVERIFIED', NULL, NULL, '{}', '{}', '[]', '2026-03-26 11:26:33.982723+05:30', '2026-03-26 11:26:33.982723+05:30', 1); ON CONFLICT DO NOTHING;
INSERT INTO public.pestel_factors (id, code, name, category, selection_reasoning, likelihood, likelihood_reasoning, impact, impact_reasoning, origin_date, trend, time_horizon, segment_relevance, affected_pillars, source_ids, is_active, last_refreshed, created_at, updated_at, is_foundational, verification_verdict, verification_source, verification_evidence, financial_context, key_dates, citations, first_seen_date, last_confirmed_date, confirmation_count) VALUES (106, 'multi_oem_suv_platform_proliferation_â€”_adas_conten', 'Multi-OEM SUV Platform Proliferation â€” ADAS Content Standardisation Pressure', 'T', 'With Maruti (7 models), Renault (Duster), JSW Motors, and continued Tata/Hyundai/Kia SUV launches, India''s SUV segment is seeing rapid platform proliferation. Each OEM platform requires customised ADAS calibration, sensor integration, and software tuning â€” increasing Bosch''s engineering cost per programme. Simultaneously, OEMs are pushing for standardised ADAS modules to reduce costs, creating tension between customisation revenue and commoditisation risk.', 7, 'The SUV platform proliferation is evidenced by Maruti''s 7-model commitment, Renault''s Duster relaunch, and JSW Motors'' entry â€” all confirmed in the March 2026 data. India''s PV market now has 50+ active SUV nameplates, a structural shift from 15-20 in FY20. Each new platform requires ADAS re-homologation under Bharat NCAP.', 6, 'Bosch''s ADAS engineering cost per platform is estimated at â‚¹15-30 Cr for full integration and testing (Estimate based on: global Tier-1 programme cost benchmarks). With 10-15 new SUV platforms expected by FY28, total engineering investment requirement is â‚¹150-450 Cr. The upside is recurring software and sensor revenue; the risk is OEMs consolidating to fewer ADAS suppliers to reduce complexity.', NULL, 'escalating', 'short', '{"2W": "L", "3W": "L", "HCV": "L", "LCV": "L", "4W_PV": "H", "Tractor": "L"}', '["ADAS", "Infotainment", "Motion", "OS"]', '{}', true, '2026-03-17 16:31:52.563836+05:30', '2026-03-17 16:31:52.563836+05:30', '2026-03-17 16:31:52.563836+05:30', false, 'UNVERIFIED', NULL, NULL, '{}', '{}', '[]', '2026-03-17 16:31:52.563836+05:30', '2026-03-17 16:31:52.563836+05:30', 1); ON CONFLICT DO NOTHING;
INSERT INTO public.pestel_factors (id, code, name, category, selection_reasoning, likelihood, likelihood_reasoning, impact, impact_reasoning, origin_date, trend, time_horizon, segment_relevance, affected_pillars, source_ids, is_active, last_refreshed, created_at, updated_at, is_foundational, verification_verdict, verification_source, verification_evidence, financial_context, key_dates, citations, first_seen_date, last_confirmed_date, confirmation_count) VALUES (135, 'maruti_it_leadership_integration_â€”_oem_software_pr', 'Maruti IT Leadership Integration â€” OEM Software Procurement Shift', 'T', 'Maruti Suzuki''s management reshuffle placing Dr Tapan Sahoo in additional charge of IT (ET Auto, March 2026) signals organisational integration of technology and service/parts verticals ahead of FY27. This indicates Maruti is centralising digital decision-making, which will influence how software, connectivity, and diagnostics are procured â€” potentially favouring integrated Tier-1 suppliers like Bosch over point-solution vendors.', 7, 'The reshuffle is confirmed. The strategic intent â€” aligning IT with service and parts â€” is consistent with global OEM trends toward software-defined vehicle architecture. Maruti''s scale (43L+ units, largest India OEM) means procurement decisions have outsized market impact.', 5, 'Organisational changes take 12â€“24 months to translate into procurement policy shifts. However, if Maruti accelerates OTA, connected services, or fleet diagnostics integration, Bosch''s Software & Services and Vehicle Diagnostics pillars benefit disproportionately given existing Maruti relationships. Risk: Maruti could also build in-house digital capability, reducing Tier-1 software dependency.', NULL, 'new', 'short', '{"2W": "L", "3W": "L", "HCV": "L", "LCV": "L", "4W_PV": "H", "Tractor": "L"}', '["Infotainment", "OS", "Services"]', '{}', false, '2026-03-26 11:21:49.300728+05:30', '2026-03-26 11:21:49.300728+05:30', '2026-03-26 11:21:49.300728+05:30', false, 'UNVERIFIED', NULL, NULL, '{}', '{}', '[]', '2026-03-26 11:21:49.300728+05:30', '2026-03-26 11:21:49.300728+05:30', 1); ON CONFLICT DO NOTHING;
INSERT INTO public.pestel_factors (id, code, name, category, selection_reasoning, likelihood, likelihood_reasoning, impact, impact_reasoning, origin_date, trend, time_horizon, segment_relevance, affected_pillars, source_ids, is_active, last_refreshed, created_at, updated_at, is_foundational, verification_verdict, verification_source, verification_evidence, financial_context, key_dates, citations, first_seen_date, last_confirmed_date, confirmation_count) VALUES (151, 'hero_honda_2w_volume_race_â€”_obd_ii_content_scale', 'Hero-Honda 2W Volume Race â€” OBD-II Content Scale', 'E', 'Hero MotoCorp (5.5M units) and Honda (5.2M units) together account for ~55% of India''s 2W market in FY26. Their combined volume scale directly drives demand for Bosch''s OBD-II sensors, fuel injection, and diagnostics systems mandated under BS-VI Stage 2. The intensifying competition between them signals sustained high-volume production, not a slowdown.', 9, 'FY26 11-month data from ET Auto confirms 10.7M combined dispatches â€” annualised to ~11.7M units. Both OEMs are expanding capacity (Honda adding Rajasthan plant), making this a near-certainty for FY27.', 7, 'At 1.96 Crore total 2W units (FY25), Hero+Honda represent the dominant volume base for Bosch''s powertrain and diagnostics content per vehicle. OBD-II compliance adds â‚¹800-1,200 per unit incremental content â€” estimate â‚¹1,000-1,500 Cr addressable revenue across both OEMs annually. Estimate based on: BS-VI Stage 2 OBD-II cost benchmarks and combined OEM volumes.', NULL, 'escalating', 'immediate', '{"2W": "H", "3W": "L", "HCV": "L", "LCV": "L", "4W_PV": "L", "Tractor": "L"}', '["Powertrain Solutions", "Vehicle Diagnostics", "Body Electronics"]', '{}', false, '2026-03-26 11:26:33.982723+05:30', '2026-03-26 11:26:33.982723+05:30', '2026-03-26 11:26:33.982723+05:30', false, 'UNVERIFIED', NULL, NULL, '{}', '{}', '[]', '2026-03-26 11:26:33.982723+05:30', '2026-03-26 11:26:33.982723+05:30', 1); ON CONFLICT DO NOTHING;
INSERT INTO public.pestel_factors (id, code, name, category, selection_reasoning, likelihood, likelihood_reasoning, impact, impact_reasoning, origin_date, trend, time_horizon, segment_relevance, affected_pillars, source_ids, is_active, last_refreshed, created_at, updated_at, is_foundational, verification_verdict, verification_source, verification_evidence, financial_context, key_dates, citations, first_seen_date, last_confirmed_date, confirmation_count) VALUES (194, 'tesla_india_traction_failure_â€”_premium_ev_import_m', 'Tesla India Traction Failure â€” Premium EV Import Model Limitations', 'E', 'Tesla''s cumulative sales of only ~340 units of the Model Y through March 2026 in India â€” despite active market presence â€” confirms that the import-led premium EV model generates negligible component localisation opportunity for Tier-1 suppliers. The six-seater upgrade attempt signals Tesla''s recognition of demand weakness but does not alter the localisation calculus. This is strategically relevant as it validates that premium imported EVs do not create meaningful domestic supply chain demand, unlike locally manufactured EV platforms.', 9, 'The 340-unit sales figure through March 2026 is a disclosed, verifiable data point. Tesla has not announced any India manufacturing commitment, and the import duty structure (100% on CBUs) makes volume scaling structurally constrained. The six-seater variant is a product refresh, not a market strategy reset.', 3, 'At 340 units cumulative, Tesla''s India presence generates near-zero direct component demand for domestic Tier-1 suppliers. The strategic signal value is moderate â€” it confirms that the premium imported EV segment is not a near-term supply opportunity, allowing Tier-1 suppliers to prioritise locally manufactured EV platforms (Tata, Mahindra, BYD India) for technology investment. The impact score is low because the absence of opportunity is already priced into most supplier strategies.', NULL, 'stable', 'short', '{"2W": "L", "3W": "L", "HCV": "L", "LCV": "L", "4W_PV": "H", "Tractor": "L"}', '["Energy", "Motion"]', '{}', true, '2026-04-24 16:06:25.016681+05:30', '2026-04-24 16:06:25.016681+05:30', '2026-04-24 16:06:25.016681+05:30', false, 'UNVERIFIED', '', '', '{"market_opportunity": "Negligible for domestic Tier-1 suppliers at current import-only model; potential â‚¹8,000-12,000 Cr if Tesla commits to local manufacturing (Estimate based on: 50,000 units/year Ã— â‚¹2L component content)", "industry_investment": "Tesla India â€” no local manufacturing investment announced; operating on import model", "subsidy_or_incentive": "India''s reduced import duty for EVs with â‚¹4,150 Cr minimum local investment commitment â€” Tesla has not committed", "government_investment": "N/A", "cost_impact_per_vehicle": "N/A"}', '{"announced": "2026-04", "effective": "2026-04", "completion": ""}', '[{"url": "https://auto.economictimes.indiatimes.com/news/passenger-vehicle/tesla-launches-six-seater-model-y-in-india-to-boost-demand-amid-slow-sales/130445944", "claim": "Tesla has managed to sell around 340 units of the Model Y in India till March 2026", "source": "ET Auto, 22 Apr 2026"}, {"url": "https://auto.economictimes.indiatimes.com/news/passenger-vehicle/tesla-launches-six-seater-model-y-in-india-to-boost-demand-amid-slow-sales/130445944", "claim": "Tesla bets on six-seater Model Y upgrade to spur muted demand in India", "source": "ET Auto, 22 Apr 2026"}]', '2026-04-24 16:06:25.016681+05:30', '2026-04-24 16:06:25.016681+05:30', 1); ON CONFLICT DO NOTHING;
INSERT INTO public.pestel_factors (id, code, name, category, selection_reasoning, likelihood, likelihood_reasoning, impact, impact_reasoning, origin_date, trend, time_horizon, segment_relevance, affected_pillars, source_ids, is_active, last_refreshed, created_at, updated_at, is_foundational, verification_verdict, verification_source, verification_evidence, financial_context, key_dates, citations, first_seen_date, last_confirmed_date, confirmation_count) VALUES (178, 'trem_v_2025', 'TREM V emission norms mandatory from Oct 2025 for tractors >50 HP', 'L', 'Tractor TREM V effective October 2025 for tractors >50 HP. Requires diesel oxidation catalyst, DPF, and SCR aftertreatment. BOM increase Rs.80k-1.2L per tractor. M&M, TAFE, Sonalika, John Deere all affected. Aligns with BS-VI philosophy for off-road segment.', 9, 'TREM V is gazetted regulation; October 2025 deadline is firm per MoRTH circular.', 4, 'Mandates DOC/DPF/SCR adoption across >50 HP tractors; large aftertreatment component market creation.', NULL, 'stable', 'short', '{"2W": "L", "3W": "L", "HCV": "L", "LCV": "L", "4W_PV": "L", "Tractor": "H"}', '["Energy", "Motion"]', '{}', true, '2026-04-06 17:46:26.063279+05:30', '2026-04-06 17:46:26.063279+05:30', '2026-04-06 17:46:26.063279+05:30', false, 'UNVERIFIED', NULL, NULL, '{}', '{}', '[]', '2026-04-06 17:46:26.063279+05:30', '2026-04-06 17:46:26.063279+05:30', 1); ON CONFLICT DO NOTHING;
INSERT INTO public.pestel_factors (id, code, name, category, selection_reasoning, likelihood, likelihood_reasoning, impact, impact_reasoning, origin_date, trend, time_horizon, segment_relevance, affected_pillars, source_ids, is_active, last_refreshed, created_at, updated_at, is_foundational, verification_verdict, verification_source, verification_evidence, financial_context, key_dates, citations, first_seen_date, last_confirmed_date, confirmation_count) VALUES (177, 'gati_shakti_infra', 'PM Gati Shakti: Rs.11.1L Cr infra investment accelerating LCV/HCV demand', 'E', 'PM Gati Shakti targets 100 logistics parks, dedicated freight corridors, 25,000 km highway construction by 2027. Drives LCV demand +18% CAGR, HCV +12% CAGR. AEBS and telematics mandates scale with fleet growth.', 8, 'Gati Shakti is an active government programme with annual budget allocations and Q3 FY26 progress report.', 8, 'Infra spend directly expands addressable market for commercial vehicle technology suppliers.', NULL, 'stable', 'short', '{"2W": "L", "3W": "M", "HCV": "H", "LCV": "H", "4W_PV": "L", "Tractor": "M"}', '["Motion", "ADAS", "Body & Comfort"]', '{}', true, '2026-04-06 17:46:26.063279+05:30', '2026-04-06 17:46:26.063279+05:30', '2026-04-06 17:46:26.063279+05:30', false, 'UNVERIFIED', NULL, NULL, '{}', '{}', '[]', '2026-04-06 17:46:26.063279+05:30', '2026-04-06 17:46:26.063279+05:30', 1); ON CONFLICT DO NOTHING;
INSERT INTO public.pestel_factors (id, code, name, category, selection_reasoning, likelihood, likelihood_reasoning, impact, impact_reasoning, origin_date, trend, time_horizon, segment_relevance, affected_pillars, source_ids, is_active, last_refreshed, created_at, updated_at, is_foundational, verification_verdict, verification_source, verification_evidence, financial_context, key_dates, citations, first_seen_date, last_confirmed_date, confirmation_count) VALUES (20, 'road_safety_awareness', 'Road safety awareness driving ADAS adoption in mid-segment', 'S', 'Rising road safety awareness (India: 156,000 road fatalities FY2025) is shifting buyer preference toward vehicles with AEB, lane keep assist, and emergency call. Bharat NCAP amplifies this by making safety ratings visible.', 7, 'Score 8: Consumer survey data (JD Power India 2025) shows 68% of 4W PV buyers now consider safety ratings. NCAP awareness growing but still nascent vs Western markets.', 5, 'Score 6: Supplements regulatory ADAS mandates. Consumer pull is weaker than regulatory push but important for premium mid-segment where ADAS is optional equipment.', NULL, 'escalating', 'medium', '{"2W": "L", "3W": "L", "HCV": "L", "LCV": "L", "4W_PV": "H", "Tractor": "L"}', '["Actuators", "ADAS", "Motion"]', '{14}', true, '2026-03-16 22:45:46.381831+05:30', '2026-03-16 22:45:46.381831+05:30', '2026-03-16 22:48:13.097302+05:30', false, 'UNVERIFIED', NULL, NULL, '{}', '{}', '[]', '2026-03-16 22:45:46.381831+05:30', '2026-03-16 22:45:46.381831+05:30', 1); ON CONFLICT DO NOTHING;
INSERT INTO public.pestel_factors (id, code, name, category, selection_reasoning, likelihood, likelihood_reasoning, impact, impact_reasoning, origin_date, trend, time_horizon, segment_relevance, affected_pillars, source_ids, is_active, last_refreshed, created_at, updated_at, is_foundational, verification_verdict, verification_source, verification_evidence, financial_context, key_dates, citations, first_seen_date, last_confirmed_date, confirmation_count) VALUES (16, 'rupee_depreciation_risk', 'INR/USD at Rs 85-86 â€” export competitiveness pressure', 'E', 'INR/USD at approximately Rs 85-86 (April 2026, RBI reference). Export competitiveness factor for all export-oriented segments.', 8, 'Score 8: Current rate confirmed at â‚¹84. Trajectory uncertain â€” RBI intervention could stabilise or allow further depreciation. Not a controllable variable.', 6, 'Score 5: Net effect is roughly neutral for Bosch (export gains offset by import cost). More important as a planning variable than a swing factor in isolation.', NULL, 'stable', 'short', '{"2W": "M", "3W": "L", "HCV": "H", "LCV": "H", "4W_PV": "H", "Tractor": "L"}', '["Compute", "Energy", "Motion"]', '{1}', true, '2026-03-16 22:45:46.381831+05:30', '2026-03-16 22:45:46.381831+05:30', '2026-03-16 22:48:13.097302+05:30', false, 'UNVERIFIED', NULL, NULL, '{}', '{}', '[]', '2026-03-16 22:45:46.381831+05:30', '2026-03-16 22:45:46.381831+05:30', 1); ON CONFLICT DO NOTHING;
INSERT INTO public.pestel_factors (id, code, name, category, selection_reasoning, likelihood, likelihood_reasoning, impact, impact_reasoning, origin_date, trend, time_horizon, segment_relevance, affected_pillars, source_ids, is_active, last_refreshed, created_at, updated_at, is_foundational, verification_verdict, verification_source, verification_evidence, financial_context, key_dates, citations, first_seen_date, last_confirmed_date, confirmation_count) VALUES (158, 'ev_4w_fy26_sales_+82%_â€”_accelerated_electrificatio', 'EV 4W FY26 Sales +82% â€” Accelerated Electrification Signal', 'E', 'Electric car registrations reached 196,754 units in FY26, up 82% over FY25''s 108,342 units. This acceleration compresses the timeline for Tier-1 suppliers to scale EV powertrain, BMS, thermal management, and charging infrastructure content. The growth rate significantly exceeds the 8% EV share baseline, signalling a structural demand shift rather than a one-year anomaly.', 9, 'Vahan dashboard data is government-verified and the 82% growth is corroborated by multiple ET Auto sources dated April 2026. The trend is supported by price hike fears and OEM discounting, suggesting both pull and push demand drivers are active simultaneously.', 6, 'At 196,754 units, 4W EV content per vehicle (inverter, BMS, thermal, EVSE) is 3-4x higher than ICE equivalent, representing a significant revenue mix shift for Tier-1 suppliers. If this trajectory sustains into FY27, addressable EV component revenue in 4W alone could exceed â‚¹8,000-10,000 Cr annually. Estimate based on: ~â‚¹4-5L average EV component content per vehicle vs ~â‚¹1.2L for ICE.', NULL, 'escalating', 'immediate', '{"2W": "L", "3W": "L", "HCV": "L", "LCV": "L", "4W_PV": "H", "Tractor": "L"}', '["Energy", "OS"]', '{}', true, '2026-04-01 11:05:44.591993+05:30', '2026-04-01 11:05:44.591993+05:30', '2026-04-01 11:05:44.591993+05:30', false, 'UNVERIFIED', NULL, NULL, '{}', '{}', '[]', '2026-04-01 11:05:44.591993+05:30', '2026-04-01 11:05:44.591993+05:30', 1); ON CONFLICT DO NOTHING;
INSERT INTO public.pestel_factors (id, code, name, category, selection_reasoning, likelihood, likelihood_reasoning, impact, impact_reasoning, origin_date, trend, time_horizon, segment_relevance, affected_pillars, source_ids, is_active, last_refreshed, created_at, updated_at, is_foundational, verification_verdict, verification_source, verification_evidence, financial_context, key_dates, citations, first_seen_date, last_confirmed_date, confirmation_count) VALUES (93, 'pv_market_fy26_â€”_4.7m_units_double_digit_h2_growth', 'PV Market FY26 â€” 4.7M Units Double-Digit H2 Growth', 'E', 'GST rate reduction in September 2025 triggered a sharp demand rebound, with cumulative FY26 PV sales projected at 4.7 million units â€” a significant step-up from FY25''s 4.3 million. This directly expands the addressable market for all Bosch technology pillars in the 4W PV segment, particularly ADAS, body electronics, powertrain, and chassis systems. The small car segment rebound also opens entry-level content opportunities distinct from the premiumisation trend already tracked.', 8, 'ET Auto (March 2026) cites industry estimates of 4.7M cumulative FY26 units with double-digit H2 growth confirmed. The GST reduction is a policy fact, and the demand response is already visible in H2 FY26 sales data. High confidence in this trajectory.', 7, 'A 4.7M unit FY26 versus 4.3M FY25 represents ~9% volume growth in the highest-value segment for Bosch. Each incremental PV unit carries â‚¹15,000â€“â‚¹50,000+ in Bosch content (powertrain, ADAS, chassis, body electronics). At 4.7M units, even a 1% share gain in content is worth hundreds of crores in incremental revenue. The small car rebound specifically benefits lower-ASP pillars like body electronics and OBD diagnostics.', NULL, 'escalating', 'immediate', '{"2W": "L", "3W": "L", "HCV": "L", "LCV": "L", "4W_PV": "H", "Tractor": "L"}', '["Energy", "Infotainment", "Motion"]', '{}', true, '2026-03-17 16:31:52.361522+05:30', '2026-03-17 16:31:52.361522+05:30', '2026-03-17 16:32:41.583165+05:30', false, 'UNVERIFIED', NULL, NULL, '{}', '{}', '[]', '2026-03-17 16:31:52.361522+05:30', '2026-03-17 16:31:52.361522+05:30', 1); ON CONFLICT DO NOTHING;
INSERT INTO public.pestel_factors (id, code, name, category, selection_reasoning, likelihood, likelihood_reasoning, impact, impact_reasoning, origin_date, trend, time_horizon, segment_relevance, affected_pillars, source_ids, is_active, last_refreshed, created_at, updated_at, is_foundational, verification_verdict, verification_source, verification_evidence, financial_context, key_dates, citations, first_seen_date, last_confirmed_date, confirmation_count) VALUES (108, 'government_â‚¹7,280_cr_rare_earth_magnet_scheme_â€”_do', 'Government â‚¹7,280 Cr Rare Earth Magnet Scheme â€” Domestic Supply Chain', 'P', 'The government''s RFP for a â‚¹7,280 Cr rare earth magnet production scheme directly addresses India''s critical dependency on Chinese rare earth imports for EV motors and permanent magnet components. Bosch''s EV Powertrain pillar (motors, inverters) and Chassis Systems (EPS motors) are directly exposed to rare earth supply risk. Domestic magnet production, expected to commence ~2028, could reduce input cost volatility and de-risk Bosch''s India EV component manufacturing.', 7, 'RFP issuance is confirmed for next month per a senior government official cited in ETAuto; however, India''s track record on industrial scheme execution timelines suggests 2-year production start is optimistic. The scheme has clear strategic backing given India''s EV ambitions and China supply concentration risk.', 7, 'Rare earth magnets are critical inputs for EV traction motors and EPS systems â€” segments where Bosch has significant manufacturing exposure. Domestic supply could reduce landed cost by 15-25% (Estimate based on: current import duty + logistics premium on Chinese rare earth magnets) and eliminate single-source geopolitical risk. The 2-year lag before production starts means near-term impact is limited but strategic positioning is high.', NULL, 'new', 'medium', '{"2W": "H", "3W": "M", "HCV": "H", "LCV": "M", "4W_PV": "H", "Tractor": "L"}', '["Compute", "Energy", "Motion"]', '{}', true, '2026-03-19 12:00:07.287583+05:30', '2026-03-19 12:00:07.287583+05:30', '2026-03-19 12:00:07.287583+05:30', false, 'UNVERIFIED', NULL, NULL, '{}', '{}', '[]', '2026-03-19 12:00:07.287583+05:30', '2026-03-19 12:00:07.287583+05:30', 1); ON CONFLICT DO NOTHING;
INSERT INTO public.pestel_factors (id, code, name, category, selection_reasoning, likelihood, likelihood_reasoning, impact, impact_reasoning, origin_date, trend, time_horizon, segment_relevance, affected_pillars, source_ids, is_active, last_refreshed, created_at, updated_at, is_foundational, verification_verdict, verification_source, verification_evidence, financial_context, key_dates, citations, first_seen_date, last_confirmed_date, confirmation_count) VALUES (169, 'auto_component_industry_h1_fy26_growth_at_6.8%_â€”_m', 'Auto Component Industry H1 FY26 Growth at 6.8% â€” Moderating Momentum', 'E', 'The auto component industry''s H1 FY26 growth of 6.8% (â‚¹3.56L Cr) â€” below the FY25 full-year rate of 9.6% â€” signals a moderation in growth momentum. ACMA''s FY27 growth forecast of 6â€“7% implies the industry is entering a phase of slower but stable expansion, requiring Tier-1 suppliers to prioritise margin management and technology differentiation over pure volume growth.', 8, 'H1 FY26 data is confirmed by ACMA and reported across ET, Fortune India, and LinkedIn ACI Magazine. ACMA''s forward guidance of 6â€“7% growth for FY26 full year is consistent with the H1 trajectory.', 5, 'A deceleration from 9.6% to 6.8% growth on a â‚¹6.73L Cr base implies ~â‚¹19,000 Cr less incremental revenue than if FY25 growth rates had sustained. For Tier-1 suppliers with fixed cost structures built for 9%+ growth, margin compression is the primary risk.', NULL, 'de-escalating', 'short', '{"2W": "M", "3W": "M", "HCV": "H", "LCV": "H", "4W_PV": "H", "Tractor": "M"}', '["Services", "Compute", "Infotainment", "Motion", "Energy"]', '{}', true, '2026-04-03 11:14:00.65269+05:30', '2026-04-03 11:14:00.65269+05:30', '2026-04-03 11:14:00.65269+05:30', false, 'UNVERIFIED', '', '', '{"market_opportunity": "â‚¹3.56L Cr H1 FY26 turnover; full-year FY26 projected at â‚¹7.1â€“7.2L Cr at 6â€“7% growth", "industry_investment": "N/A", "subsidy_or_incentive": "PLI scheme â‚¹35,657 Cr invested, â‚¹2,322 Cr disbursed", "government_investment": "N/A", "cost_impact_per_vehicle": "N/A"}', '{"announced": "2025-10", "effective": "2025-04", "completion": "2026-03"}', '[{"url": "https://m.economictimes.com/industry/auto/auto-components/auto-components-industry-grows-6-8-per-cent-in-apr-sep-fy26-acma/articleshow/126522584.cms", "claim": "India''s auto component sector saw robust growth of 6.8% in H1 FY26, reaching a turnover of â‚¹3.56 lakh crore", "source": "Economic Times / ACMA, 2025"}, {"url": "https://ackodrive.com/news/india-s-auto-component-industry-eyes-6-7-growth-amid-trade-deal-boost-acma/", "claim": "ACMA expects 6â€“7% growth to continue in FY26 following $80.2B turnover in FY2025", "source": "ACKO Drive / ACMA, 2025"}]', '2026-04-03 11:14:00.65269+05:30', '2026-04-03 11:14:00.65269+05:30', 1); ON CONFLICT DO NOTHING;
INSERT INTO public.pestel_factors (id, code, name, category, selection_reasoning, likelihood, likelihood_reasoning, impact, impact_reasoning, origin_date, trend, time_horizon, segment_relevance, affected_pillars, source_ids, is_active, last_refreshed, created_at, updated_at, is_foundational, verification_verdict, verification_source, verification_evidence, financial_context, key_dates, citations, first_seen_date, last_confirmed_date, confirmation_count) VALUES (3, 'bsvi_stage2_mandate', 'BS-VI Stage 2 â€” OBD-II for 2W/3W, RDE for 4W (April 2025)', 'T', 'BS-VI Stage 2 mandates OBD-II port for ALL 2W/3W (1.96 Cr + 7.41 Lakh vehicles/year) and Real Driving Emissions for 4W. Creates massive demand for Vehicle Diagnostics, Powertrain, and Sensor technology.', 10, 'Score 10: Implemented April 2025. MoRTH notification issued. All OEMs compliant. Completed regulatory action.', 8, 'Score 8: OBD-II alone = â‚¹3,000-4,000 Cr new market in 2W diagnostics. RDE for 4W drives exhaust sensors, ECU upgrades. 4/13 Bosch pillars directly impacted.', NULL, 'stable', 'immediate', '{"2W": "H", "3W": "H", "HCV": "H", "LCV": "H", "4W_PV": "H", "Tractor": "L"}', '["Actuators", "ADAS", "ECUs", "Infotainment", "Motion", "OS"]', '{12}', true, '2026-03-16 21:29:57.526355+05:30', '2026-03-16 21:29:57.526355+05:30', '2026-03-16 22:48:13.097302+05:30', true, 'UNVERIFIED', NULL, NULL, '{}', '{}', '[]', '2026-03-16 21:29:57.526355+05:30', '2026-03-16 21:29:57.526355+05:30', 1); ON CONFLICT DO NOTHING;
INSERT INTO public.pestel_factors (id, code, name, category, selection_reasoning, likelihood, likelihood_reasoning, impact, impact_reasoning, origin_date, trend, time_horizon, segment_relevance, affected_pillars, source_ids, is_active, last_refreshed, created_at, updated_at, is_foundational, verification_verdict, verification_source, verification_evidence, financial_context, key_dates, citations, first_seen_date, last_confirmed_date, confirmation_count) VALUES (142, 'maruti_it_leadership_expansion_â€”_oem_digital_integ', 'Maruti IT Leadership Expansion â€” OEM Digital Integration Acceleration', 'T', 'Maruti Suzuki''s management reshuffle placing IT under expanded senior leadership (Dr. Tapan Sahoo) ahead of FY27 signals accelerated digital transformation at India''s largest PV OEM. This creates procurement urgency for Bosch''s Software & Services, Infotainment & Connectivity, and Vehicle Diagnostics pillars as Maruti deepens software-defined vehicle capabilities. OEM digital maturity directly determines Bosch''s software content per vehicle.', 8, 'The management reshuffle is confirmed (ET Auto, March 2026) and is explicitly framed as preparation for the new financial year. Maruti''s competitive pressure from Hyundai, Tata, and Mahindra on connected features makes digital acceleration strategically necessary.', 4, 'Maruti''s 43% PV market share means its digital strategy decisions cascade across ~1.85M annual units. However, Maruti''s historically conservative technology adoption and preference for cost optimisation limits near-term premium software content uptake. Medium-term impact on Bosch''s Software & Services and connectivity revenue is moderate â€” estimated â‚¹200â€“400 Cr opportunity over 3 years.', NULL, 'escalating', 'short', '{"2W": "L", "3W": "L", "HCV": "L", "LCV": "L", "4W_PV": "H", "Tractor": "L"}', '["Compute", "Infotainment", "OS"]', '{}', true, '2026-03-26 11:22:14.095204+05:30', '2026-03-26 11:22:14.095204+05:30', '2026-03-26 11:22:14.095204+05:30', false, 'UNVERIFIED', NULL, NULL, '{}', '{}', '[]', '2026-03-26 11:22:14.095204+05:30', '2026-03-26 11:22:14.095204+05:30', 1); ON CONFLICT DO NOTHING;
INSERT INTO public.pestel_factors (id, code, name, category, selection_reasoning, likelihood, likelihood_reasoning, impact, impact_reasoning, origin_date, trend, time_horizon, segment_relevance, affected_pillars, source_ids, is_active, last_refreshed, created_at, updated_at, is_foundational, verification_verdict, verification_source, verification_evidence, financial_context, key_dates, citations, first_seen_date, last_confirmed_date, confirmation_count) VALUES (1, 'india_eu_fta', 'India-EU FTA signed January 2026', 'P', 'EU is India''s 2nd largest auto component export destination ($5.2B FY25). Zero-tariff phase-in directly impacts export competitiveness for Bosch''s European supply chain. Affects 8/13 Bosch pillars through component pricing.', 7, 'Score 10: FTA officially signed 27 January 2026. Completed event, not forecast. 7-year tariff schedule locked in treaty text.', 6, 'Score 7: EU is ~23% of India auto exports. 6.5% tariff elimination vs Turkey/Morocco. Offset by CBAM and sustainability standards.', NULL, 'new', 'medium', '{"2W": "M", "3W": "L", "HCV": "L", "LCV": "M", "4W_PV": "H", "Tractor": "L"}', '["Body & Comfort", "Energy", "Motion", "Semiconductors"]', '{11}', true, '2026-03-16 21:29:57.526355+05:30', '2026-03-16 21:29:57.526355+05:30', '2026-03-16 22:48:13.097302+05:30', true, 'UNVERIFIED', NULL, NULL, '{}', '{}', '[]', '2026-03-16 21:29:57.526355+05:30', '2026-03-16 21:29:57.526355+05:30', 1); ON CONFLICT DO NOTHING;
INSERT INTO public.pestel_factors (id, code, name, category, selection_reasoning, likelihood, likelihood_reasoning, impact, impact_reasoning, origin_date, trend, time_horizon, segment_relevance, affected_pillars, source_ids, is_active, last_refreshed, created_at, updated_at, is_foundational, verification_verdict, verification_source, verification_evidence, financial_context, key_dates, citations, first_seen_date, last_confirmed_date, confirmation_count) VALUES (36, 'product_liability_adas', 'Product liability framework for ADAS failures â€” legal uncertainty', 'L', 'India lacks a clear product liability framework for ADAS-related accidents. As AEB and L2+ ADAS become mandatory, liability questions (OEM vs Tier-1 supplier vs software vendor) will intensify. This increases legal risk for Bosch as system integrator.', 6, 'Score 7: Legal framework gap is confirmed. As ADAS penetration rises and accidents occur, litigation is inevitable. Timeline to first major case estimated 2026-2028.', 5, 'Score 6: Insurance and indemnification costs will rise. May require changes to supply contracts and system architecture (e.g., more conservative ADAS tuning for India). Manageable but non-trivial.', NULL, 'new', 'medium', '{"2W": "L", "3W": "L", "HCV": "L", "LCV": "L", "4W_PV": "H", "Tractor": "L"}', '["ADAS", "Motion", "OS"]', '{19}', true, '2026-03-16 22:45:46.381831+05:30', '2026-03-16 22:45:46.381831+05:30', '2026-03-16 22:48:13.097302+05:30', false, 'UNVERIFIED', NULL, NULL, '{}', '{}', '[]', '2026-03-16 22:45:46.381831+05:30', '2026-03-16 22:45:46.381831+05:30', 1); ON CONFLICT DO NOTHING;
INSERT INTO public.pestel_factors (id, code, name, category, selection_reasoning, likelihood, likelihood_reasoning, impact, impact_reasoning, origin_date, trend, time_horizon, segment_relevance, affected_pillars, source_ids, is_active, last_refreshed, created_at, updated_at, is_foundational, verification_verdict, verification_source, verification_evidence, financial_context, key_dates, citations, first_seen_date, last_confirmed_date, confirmation_count) VALUES (172, 'm&m_rises_to_2nd_in_4w_ev_â€”_multi_oem_ev_pv_compet', 'M&M Rises to 2nd in 4W EV â€” Multi-OEM EV PV Competition Intensifies', 'E', 'Mahindra''s ascent to second position in India''s 4W EV market (displacing JSW MG Motor) signals accelerating multi-OEM competition in the EV PV segment, with direct implications for EV powertrain, ADAS, and battery thermal management component demand. Multiple credible OEMs now competing for EV PV share creates a more diversified and stable demand base for Tier-1 EV component suppliers, reducing single-OEM concentration risk. Simultaneously, it intensifies pressure on component localisation and cost competitiveness.', 9, 'Confirmed FY26 sales data reported by ET Auto on 02 April 2026. Tata Motors retains top position, M&M second â€” this is a realised market outcome based on registration data, not a projection.', 5, 'The 4W EV segment grew 82% in FY26 (per existing factors), and M&M''s portfolio expansion (multiple SUV platforms) creates significant incremental demand for EV-specific components. Mahindra''s BE.6 and XEV 9e platforms require localised inverters, motors, and BMS â€” representing a new high-value supply opportunity for Tier-1 suppliers beyond the Tata Motors ecosystem.', NULL, 'escalating', 'short', '{"2W": "L", "3W": "L", "HCV": "L", "LCV": "L", "4W_PV": "H", "Tractor": "L"}', '["OS", "ADAS", "Energy", "Motion"]', '{}', true, '2026-04-03 13:42:43.951941+05:30', '2026-04-03 13:42:43.951941+05:30', '2026-04-03 13:42:43.951941+05:30', false, 'UNVERIFIED', '', '', '{"market_opportunity": "Estimate based on: 4W EV segment ~1.5â€“2L units FY27E Ã— â‚¹1.5â€“2.5L EV-specific component content/vehicle = â‚¹22,500â€“50,000 Cr addressable EV 4W component market", "industry_investment": "N/A", "subsidy_or_incentive": "GST at 5% on EVs vs 28%+cess on ICE; FAME III incentives applicable to 4W EV", "government_investment": "N/A", "cost_impact_per_vehicle": "N/A"}', '{"announced": "2026-04", "effective": "2026-04", "completion": ""}', '[{"url": "https://auto.economictimes.indiatimes.com/news/passenger-vehicle/mahindra-surpasses-jsw-mg-motor-tata-motors-leads-ev-market/129965397", "claim": "Mahindra surpasses JSW MG Motor to bag second spot in EV charts; Tata Motors still leads", "source": "ET Auto, 02 April 2026"}, {"url": "", "claim": "4W EV FY26 sales +82% â€” accelerated electrification signal", "source": "ACMA / SIAM FY2025 data (existing baseline)"}]', '2026-04-03 13:42:43.951941+05:30', '2026-04-03 13:42:43.951941+05:30', 1); ON CONFLICT DO NOTHING;
INSERT INTO public.pestel_factors (id, code, name, category, selection_reasoning, likelihood, likelihood_reasoning, impact, impact_reasoning, origin_date, trend, time_horizon, segment_relevance, affected_pillars, source_ids, is_active, last_refreshed, created_at, updated_at, is_foundational, verification_verdict, verification_source, verification_evidence, financial_context, key_dates, citations, first_seen_date, last_confirmed_date, confirmation_count) VALUES (18, 'premiumisation_tier2_cities', 'Premiumisation trend â€” Tier 2/3 city middle class upgrading', 'S', 'India''s Tier 2/3 cities now account for ~52% of 4W PV sales (SIAM FY2025). First-time buyers are skipping entry hatchbacks and buying SUVs with more technology content, directly expanding Bosch''s addressable ADAS and Infotainment market.', 8, 'Score 9: Observed trend with 5+ years of data. SUV share of 4W PV has risen from 38% (FY21) to 57% (FY25). Structural shift, not cyclical.', 6, 'Score 7: SUV/crossover buyer spends â‚¹40,000-80,000 more on tech content per vehicle. Directly lifts ADAS, Infotainment, and Chassis value-per-vehicle for Bosch.', NULL, 'escalating', 'medium', '{"2W": "L", "3W": "L", "HCV": "L", "LCV": "L", "4W_PV": "H", "Tractor": "L"}', '["Body & Comfort", "Infotainment", "Motion"]', '{2}', true, '2026-03-16 22:45:46.381831+05:30', '2026-03-16 22:45:46.381831+05:30', '2026-03-16 22:48:13.097302+05:30', true, 'UNVERIFIED', NULL, NULL, '{}', '{}', '[]', '2026-03-16 22:45:46.381831+05:30', '2026-03-16 22:45:46.381831+05:30', 1); ON CONFLICT DO NOTHING;
INSERT INTO public.pestel_factors (id, code, name, category, selection_reasoning, likelihood, likelihood_reasoning, impact, impact_reasoning, origin_date, trend, time_horizon, segment_relevance, affected_pillars, source_ids, is_active, last_refreshed, created_at, updated_at, is_foundational, verification_verdict, verification_source, verification_evidence, financial_context, key_dates, citations, first_seen_date, last_confirmed_date, confirmation_count) VALUES (95, 'automotive_cybersecurity_â€”_oem_procurement_urgency', 'Automotive Cybersecurity â€” OEM Procurement Urgency Post-JLR', 'L', 'The JLR cyberattack creates a legal and regulatory urgency for Indian OEMs to demonstrate cybersecurity compliance â€” both under UN R155 (already tracked) and under India''s DPDP Act 2023. OEMs facing shareholder and regulatory scrutiny post-JLR will accelerate cybersecurity procurement and audit requirements for their Tier-1 suppliers including Bosch. This is distinct from the technical/technology factor â€” it is a legal compliance and liability driver.', 7, 'Post-JLR, OEM boards and legal teams will mandate cybersecurity audits and supplier compliance certifications. India''s DPDP Act enforcement is ramping up. The combination of a high-profile domestic incident (Tata Motors/JLR) and regulatory framework creates near-certain procurement action within 12 months.', 5, 'Bosch''s Safety & Security pillar (cybersecurity, V2X security) and Software & Services (OTA, vehicle OS) are directly positioned to benefit from OEM cybersecurity procurement acceleration. The risk for Bosch is also real â€” as a Tier-1 supplier, Bosch itself will face enhanced cybersecurity audit requirements from OEM customers, requiring investment in its own supply chain security posture.', NULL, 'escalating', 'immediate', '{"2W": "L", "3W": "L", "HCV": "L", "LCV": "L", "4W_PV": "H", "Tractor": "L"}', '["ADAS", "Infotainment", "OS"]', '{}', true, '2026-03-17 16:31:52.361522+05:30', '2026-03-17 16:31:52.361522+05:30', '2026-03-17 16:31:52.361522+05:30', false, 'UNVERIFIED', NULL, NULL, '{}', '{}', '[]', '2026-03-17 16:31:52.361522+05:30', '2026-03-17 16:31:52.361522+05:30', 1); ON CONFLICT DO NOTHING;
INSERT INTO public.pestel_factors (id, code, name, category, selection_reasoning, likelihood, likelihood_reasoning, impact, impact_reasoning, origin_date, trend, time_horizon, segment_relevance, affected_pillars, source_ids, is_active, last_refreshed, created_at, updated_at, is_foundational, verification_verdict, verification_source, verification_evidence, financial_context, key_dates, citations, first_seen_date, last_confirmed_date, confirmation_count) VALUES (174, 'india_automotive_mission_plan_2047_â€”_50m_vehicle_p', 'India Automotive Mission Plan 2047 â€” 50M Vehicle Production Target', 'P', 'India''s Automotive Mission Plan 2047 targets vehicle production of 50 million units by 2030 and 200 million by 2047, positioning India among the top two global auto producers. This government-backed long-term roadmap creates a durable policy framework for Tier-1 supplier capacity investment decisions. The plan''s explicit multi-fuel approach (hydrogen, electric, CNG, biogas alongside ICE) is strategically significant as it validates continued ICE component investment while mandating EV/alternative fuel capability development.', 5, 'The Automotive Mission Plan 2047 is a government-articulated strategic framework cited in IBEF''s November 2025 report. India''s FY26 PV sales of ~4.7M units and total vehicle sales of ~30M+ units provide a credible base, though achieving 50M by 2030 requires ~67% growth in 4 years â€” ambitious but directionally supported by current trajectory.', 6, 'A 50M unit production target by 2030 implies a near-doubling of component demand across all segments, requiring massive Tier-1 capacity expansion. The multi-fuel mandate creates simultaneous investment requirements across ICE powertrain, EV powertrain, hydrogen fuel cell, and alternative fuel systems â€” a capital-intensive diversification challenge. This plan directly influences PLI scheme design, import duty structures, and OEM localisation mandates.', NULL, 'stable', 'long', '{"2W": "H", "3W": "H", "HCV": "H", "LCV": "H", "4W_PV": "H", "Tractor": "H"}', '["Compute", "Energy", "Motion"]', '{}', true, '2026-04-03 13:42:43.951941+05:30', '2026-04-03 13:42:43.951941+05:30', '2026-04-03 13:42:43.951941+05:30', false, 'UNVERIFIED', '', '', '{"market_opportunity": "India auto component industry projected US$200B by 2030 per IBEF/McKinsey, underpinned by AMP 2047 volume targets", "industry_investment": "N/A", "subsidy_or_incentive": "Multi-fuel approach â€” no immediate curb on petrol/diesel; EV at 5% GST; hydrogen pilot support", "government_investment": "PLI scheme â‚¹25,938 Cr (US$3.03B) as part of broader AMP 2047 policy ecosystem", "cost_impact_per_vehicle": "N/A"}', '{"announced": "2025-01", "effective": "2025-01", "completion": "2047-01"}', '[{"url": "", "claim": "India''s Automotive Mission Plan 2047 aims to boost vehicle production to 50 million by 2030 and 200 million by 2047, positioning India among the top two global auto producers; prioritises sustainable vehicle production with hydrogen, electric, CNG, and biogas while not curbing petrol or diesel vehicles immediately", "source": "IBEF Auto Components Industry Report, November 2025"}, {"url": "", "claim": "India is the world''s third-largest automobile market by both value and volume", "source": "IBEF Auto Components Industry Report, November 2025"}]', '2026-04-03 13:42:43.951941+05:30', '2026-04-03 13:42:43.951941+05:30', 1); ON CONFLICT DO NOTHING;
INSERT INTO public.pestel_factors (id, code, name, category, selection_reasoning, likelihood, likelihood_reasoning, impact, impact_reasoning, origin_date, trend, time_horizon, segment_relevance, affected_pillars, source_ids, is_active, last_refreshed, created_at, updated_at, is_foundational, verification_verdict, verification_source, verification_evidence, financial_context, key_dates, citations, first_seen_date, last_confirmed_date, confirmation_count) VALUES (160, 'west_asia_conflict_â€”_fuel_price_surge_&_rupee_depr', 'West Asia Conflict â€” Fuel Price Surge & Rupee Depreciation Risk', 'P', 'West Asia geopolitical conflict is driving crude oil price increases and rupee weakness, simultaneously inflating input costs for imported auto components and compressing CV fleet operator margins. For Tier-1 suppliers, this creates a dual pressure: higher raw material import costs and softening demand from CV fleet operators who face reduced trip volumes. This directly affects powertrain, chassis, and body electronics supply chains.', 7, 'ET Auto explicitly flags West Asia war headwinds as a FY27 challenge, with Nomura analysis confirming CV fleet operators face trip reduction pressures. The rupee depreciation trend is corroborated by the existing INR/USD baseline factor, and crude oil price sensitivity to Middle East conflict is historically well-established.', 8, 'A 10% rupee depreciation increases imported component costs by an equivalent margin; for suppliers with 20-30% import content (semiconductors, rare earth magnets, specialty steel), this directly erodes EBITDA. CV segment demand softening could reduce HCV/LCV component volumes by 3-5% in FY27. Estimate based on: Nomura analysis cited in ET Auto and historical rupee-import cost correlation.', NULL, 'escalating', 'immediate', '{"2W": "M", "3W": "M", "HCV": "H", "LCV": "H", "4W_PV": "H", "Tractor": "H"}', '["Energy", "Motion", "Infotainment"]', '{}', true, '2026-04-01 11:05:44.591993+05:30', '2026-04-01 11:05:44.591993+05:30', '2026-04-01 11:05:44.591993+05:30', false, 'UNVERIFIED', NULL, NULL, '{}', '{}', '[]', '2026-04-01 11:05:44.591993+05:30', '2026-04-01 11:05:44.591993+05:30', 1); ON CONFLICT DO NOTHING;
INSERT INTO public.pestel_factors (id, code, name, category, selection_reasoning, likelihood, likelihood_reasoning, impact, impact_reasoning, origin_date, trend, time_horizon, segment_relevance, affected_pillars, source_ids, is_active, last_refreshed, created_at, updated_at, is_foundational, verification_verdict, verification_source, verification_evidence, financial_context, key_dates, citations, first_seen_date, last_confirmed_date, confirmation_count) VALUES (107, 'byd_india_premium_ev_push_â€”_network_expansion_to_4', 'BYD India Premium EV Push â€” Network Expansion to 48 Outlets', 'P', 'BYD''s aggressive retail expansion (48 outlets, largest Delhi showroom) and double-digit growth target signals accelerating Chinese OEM penetration in India''s premium EV segment. This intensifies competition for Bosch''s EV Powertrain, Vehicle Motion, and Software & Services pillars as BYD brings vertically integrated technology stacks that may bypass Bosch as a tier-1 supplier. The geopolitical dimension of Chinese OEM growth in India also carries policy risk.', 7, 'BYD sold ~6,000 units in 2025 and is actively investing in dealer infrastructure; double-digit growth from a low base is highly achievable. Indian government has not imposed additional restrictions on Chinese EV sales, and BYD''s premium positioning insulates it from price-sensitive competition.', 4, 'BYD''s 6,000-unit base remains small relative to India''s 43L PV market, limiting immediate revenue impact. However, BYD''s in-house powertrain, BMS, and ADAS systems reduce Bosch content-per-vehicle opportunity significantly. If BYD scales to 30,000+ units by 2028, Bosch loses meaningful addressable market in the premium EV segment.', NULL, 'escalating', 'short', '{"2W": "L", "3W": "L", "HCV": "L", "LCV": "L", "4W_PV": "H", "Tractor": "L"}', '["Energy", "Infotainment", "Motion", "OS"]', '{}', true, '2026-03-19 12:00:07.287583+05:30', '2026-03-19 12:00:07.287583+05:30', '2026-03-19 12:00:07.287583+05:30', false, 'UNVERIFIED', NULL, NULL, '{}', '{}', '[]', '2026-03-19 12:00:07.287583+05:30', '2026-03-19 12:00:07.287583+05:30', 1); ON CONFLICT DO NOTHING;
INSERT INTO public.pestel_factors (id, code, name, category, selection_reasoning, likelihood, likelihood_reasoning, impact, impact_reasoning, origin_date, trend, time_horizon, segment_relevance, affected_pillars, source_ids, is_active, last_refreshed, created_at, updated_at, is_foundational, verification_verdict, verification_source, verification_evidence, financial_context, key_dates, citations, first_seen_date, last_confirmed_date, confirmation_count) VALUES (74, 'exicom_â‚¹216_cr_hyderabad_plant_â€”_domestic_evse_com', 'Exicom â‚¹216 Cr Hyderabad plant â€” domestic EVSE competition intensifies', 'E', 'Exicom commissioning a dedicated AC/DC charger manufacturing plant with export capability to Southeast Asia, Europe, and the US represents a direct competitive threat to Bosch''s Energy & Charging pillar. Local manufacturing at scale enables Exicom to undercut imported Bosch EVSE on price while qualifying for PLI benefits. This compresses Bosch''s margin window in the public and semi-public charging infrastructure segment.', 9, 'Plant commissioning is confirmed (ET Auto, March 2026), not announced â€” production has begun. Exicom is already a listed entity with institutional backing, making sustained operations highly probable. The â‚¹216 Crore investment signals multi-year commitment.', 4, 'India''s EVSE market is nascent but growing rapidly under FAME III''s â‚¹2,671 Crore charging infrastructure allocation. Exicom''s local cost advantage could capture 20-30% of public charging tenders that Bosch might otherwise target. However, Bosch''s DC fast-charging technology differentiation and OEM-bundled charging solutions provide partial insulation.', NULL, 'escalating', 'short', '{"2W": "M", "3W": "L", "HCV": "L", "LCV": "M", "4W_PV": "M", "Tractor": "L"}', '["Energy"]', '{}', true, '2026-03-16 23:47:58.163502+05:30', '2026-03-16 23:47:58.163502+05:30', '2026-03-16 23:47:58.163502+05:30', false, 'UNVERIFIED', NULL, NULL, '{}', '{}', '[]', '2026-03-16 23:47:58.163502+05:30', '2026-03-16 23:47:58.163502+05:30', 1); ON CONFLICT DO NOTHING;
INSERT INTO public.pestel_factors (id, code, name, category, selection_reasoning, likelihood, likelihood_reasoning, impact, impact_reasoning, origin_date, trend, time_horizon, segment_relevance, affected_pillars, source_ids, is_active, last_refreshed, created_at, updated_at, is_foundational, verification_verdict, verification_source, verification_evidence, financial_context, key_dates, citations, first_seen_date, last_confirmed_date, confirmation_count) VALUES (116, 'hero_honda_2w_volume_war_â€”_component_demand_surge', 'Hero-Honda 2W Volume War â€” Component Demand Surge', 'E', 'Hero MotoCorp (5.5M units) and Honda (5.2M units) in 11 months of FY26 signals a fiercely competitive 2W market with record volumes. This drives high-volume demand for Bosch''s OBD-II compliant powertrain, diagnostics, and chassis systems across the largest vehicle segment by units. The intensity of competition accelerates OEM investment in differentiating technology content.', 8, 'Actual dispatch data from FY26 (11 months) confirms the volume trajectory. Both OEMs have announced capacity expansions, making sustained high-volume output near-certain through FY27.', 6, '2W is India''s largest segment at 1.96 Crore units (FY25), and FY26 volumes tracking higher. Even marginal content-per-vehicle increases across 10M+ units generate significant revenue for Bosch''s powertrain and diagnostics pillars. However, 2W remains a cost-sensitive segment limiting premium content attachment.', NULL, 'escalating', 'immediate', '{"2W": "H", "3W": "L", "HCV": "L", "LCV": "L", "4W_PV": "L", "Tractor": "L"}', '["Infotainment", "Motion", "Services"]', '{}', true, '2026-03-26 11:21:49.325434+05:30', '2026-03-26 11:21:49.325434+05:30', '2026-03-26 11:21:49.325434+05:30', false, 'UNVERIFIED', NULL, NULL, '{}', '{}', '[]', '2026-03-26 11:21:49.325434+05:30', '2026-03-26 11:21:49.325434+05:30', 1); ON CONFLICT DO NOTHING;
INSERT INTO public.pestel_factors (id, code, name, category, selection_reasoning, likelihood, likelihood_reasoning, impact, impact_reasoning, origin_date, trend, time_horizon, segment_relevance, affected_pillars, source_ids, is_active, last_refreshed, created_at, updated_at, is_foundational, verification_verdict, verification_source, verification_evidence, financial_context, key_dates, citations, first_seen_date, last_confirmed_date, confirmation_count) VALUES (111, 'direct_to_garage_aftermarket_platforms_disrupting_', 'Direct-to-Garage Aftermarket Platforms Disrupting Traditional Distribution', 'T', 'Autoverse Mobility''s data-led direct-to-garage model targeting 140,000 garages threatens the traditional tiered distribution chain that Bosch''s Aftermarket & Retrofit pillar relies on. If platform aggregators capture parts sourcing decisions at the garage level, Bosch loses pricing power and brand pull in the â‚¹1.05L Cr aftermarket. This mirrors global patterns where digital intermediaries erode OEM-aligned aftermarket margins.', 7, 'The $11B aftermarket is highly fragmented with 500,000+ garages and chronic supply chain inefficiency â€” structural conditions that favour platform disruption. Autoverse''s funding and 140,000-garage target (ET Auto, Mar 2026) indicate serious capital backing, though execution at scale in India''s unorganised aftermarket remains challenging.', 6, 'Bosch''s aftermarket business in India generates significant revenue from the â‚¹1.05L Cr segment. Platform-driven price transparency and multi-brand sourcing could compress Bosch''s aftermarket margins by 200-400 bps. However, Bosch''s diagnostic tools and proprietary parts create some moat against pure commoditisation.', NULL, 'escalating', 'short', '{"2W": "H", "3W": "M", "HCV": "L", "LCV": "M", "4W_PV": "H", "Tractor": "L"}', '["Infotainment", "OS", "Services"]', '{}', true, '2026-03-26 11:21:49.301521+05:30', '2026-03-26 11:21:49.301521+05:30', '2026-03-26 11:21:49.301521+05:30', false, 'UNVERIFIED', NULL, NULL, '{}', '{}', '[]', '2026-03-26 11:21:49.301521+05:30', '2026-03-26 11:21:49.301521+05:30', 1); ON CONFLICT DO NOTHING;
INSERT INTO public.pestel_factors (id, code, name, category, selection_reasoning, likelihood, likelihood_reasoning, impact, impact_reasoning, origin_date, trend, time_horizon, segment_relevance, affected_pillars, source_ids, is_active, last_refreshed, created_at, updated_at, is_foundational, verification_verdict, verification_source, verification_evidence, financial_context, key_dates, citations, first_seen_date, last_confirmed_date, confirmation_count) VALUES (27, 'adas_l3_radar_lidar_readiness', 'ADAS L3 radar/LiDAR ecosystem maturing in India by 2027', 'T', 'Tier-1 Indian OEMs (Tata, Mahindra) are announcing L3 ADAS on flagship models for 2027. This triggers domestic demand for radar and LiDAR sensors â€” currently 90%+ imported â€” creating a localisation opportunity for Bosch India.', 6, 'Score 7: Model announcements confirmed. However L3 in India faces regulatory gap (no L3 homologation framework yet). Score 7 reflects high likelihood of technology readiness but moderate regulatory readiness.', 6, 'Score 7: Each L3-equipped vehicle requires â‚¹80,000-1,20,000 of ADAS sensors vs â‚¹15,000-25,000 for L2+. Significant value-per-unit uplift for Bosch''s Vehicle Motion pillar.', NULL, 'new', 'short', '{"2W": "L", "3W": "L", "HCV": "L", "LCV": "L", "4W_PV": "H", "Tractor": "L"}', '["ADAS", "ECUs", "Motion", "OS", "Semiconductors"]', '{9}', true, '2026-03-16 22:45:46.381831+05:30', '2026-03-16 22:45:46.381831+05:30', '2026-03-16 22:48:13.097302+05:30', false, 'UNVERIFIED', NULL, NULL, '{}', '{}', '[]', '2026-03-16 22:45:46.381831+05:30', '2026-03-16 22:45:46.381831+05:30', 1); ON CONFLICT DO NOTHING;
INSERT INTO public.pestel_factors (id, code, name, category, selection_reasoning, likelihood, likelihood_reasoning, impact, impact_reasoning, origin_date, trend, time_horizon, segment_relevance, affected_pillars, source_ids, is_active, last_refreshed, created_at, updated_at, is_foundational, verification_verdict, verification_source, verification_evidence, financial_context, key_dates, citations, first_seen_date, last_confirmed_date, confirmation_count) VALUES (104, 'india_pv_sub_â‚¹10l_segment_rebound_â€”_entry_level_el', 'India PV Sub-â‚¹10L Segment Rebound â€” Entry-Level Electronics Content', 'S', 'The GST-driven small car rebound (confirmed in FY26 double-digit growth analysis) signals renewed volume in the sub-â‚¹10L segment, which had been structurally declining since FY22. This segment''s recovery creates demand for cost-optimised versions of Bosch''s body electronics, OBD, and basic safety systems. The ''connected car features expected even in sub-â‚¹10L'' trend means Bosch must develop India-specific low-cost variants of its technology stack.', 7, 'The small car rebound is confirmed by ET Auto''s FY26 analysis (March 2026) as a direct outcome of the September 2025 GST rate reduction. SIAM data corroborates the trend. The policy trigger is enacted and its demand effect is already materialising in H2 FY26 wholesale numbers.', 5, 'Sub-â‚¹10L vehicles represent approximately 35-40% of India PV volumes (Estimate based on: SIAM segment data). At lower content per vehicle (â‚¹8,000-12,000 vs. â‚¹20,000+ for SUVs), volume recovery in this segment adds â‚¹400-700 Cr to Bosch''s addressable market. More critically, it requires Bosch to maintain a cost-competitive entry-level product portfolio to avoid losing share to domestic Tier-1 suppliers.', NULL, 'escalating', 'immediate', '{"2W": "L", "3W": "L", "HCV": "L", "LCV": "L", "4W_PV": "H", "Tractor": "L"}', '["Infotainment", "Motion"]', '{}', true, '2026-03-17 16:31:52.563836+05:30', '2026-03-17 16:31:52.563836+05:30', '2026-03-17 16:31:52.563836+05:30', false, 'UNVERIFIED', NULL, NULL, '{}', '{}', '[]', '2026-03-17 16:31:52.563836+05:30', '2026-03-17 16:31:52.563836+05:30', 1); ON CONFLICT DO NOTHING;
INSERT INTO public.pestel_factors (id, code, name, category, selection_reasoning, likelihood, likelihood_reasoning, impact, impact_reasoning, origin_date, trend, time_horizon, segment_relevance, affected_pillars, source_ids, is_active, last_refreshed, created_at, updated_at, is_foundational, verification_verdict, verification_source, verification_evidence, financial_context, key_dates, citations, first_seen_date, last_confirmed_date, confirmation_count) VALUES (72, 'gst_2.0_pv_demand_surge_â€”_4.7m_units_fy26', 'GST 2.0 PV demand surge â€” 4.7M units FY26', 'P', 'GST rate reduction in September 2025 has driven PV sales to a projected 4.7 million units in FY26, a ~9% upside versus the FY25 baseline of 4.3 million. This directly expands the addressable market for Bosch''s powertrain, chassis, ADAS, and body electronics pillars across the highest-value segment. The small-car rebound is particularly significant as it broadens the volume base for mid-tier technology fitment.', 6, 'ET Auto (high reliability, March 2026) reports cumulative H2 FY26 growth of ~15% with industry consensus on 4.7M units. GST reduction is a confirmed policy action, not a forecast, making demand materialisation near-certain for FY26.', 7, 'A ~700,000-unit incremental volume over FY25 baseline at average Bosch content of â‚¹18,000â€“25,000 per vehicle implies â‚¹1,260â€“1,750 Crore in additional addressable revenue for Bosch''s India PV-facing business. Small-car rebound also reopens entry-level ABS/OBD fitment volumes that had stagnated.', NULL, 'escalating', 'immediate', '{"2W": "L", "3W": "L", "HCV": "L", "LCV": "L", "4W_PV": "H", "Tractor": "L"}', '["Body & Comfort", "Infotainment", "Motion"]', '{}', true, '2026-03-16 23:47:58.163502+05:30', '2026-03-16 23:47:58.163502+05:30', '2026-03-16 23:47:58.163502+05:30', false, 'UNVERIFIED', NULL, NULL, '{}', '{}', '[]', '2026-03-16 23:47:58.163502+05:30', '2026-03-16 23:47:58.163502+05:30', 1); ON CONFLICT DO NOTHING;
INSERT INTO public.pestel_factors (id, code, name, category, selection_reasoning, likelihood, likelihood_reasoning, impact, impact_reasoning, origin_date, trend, time_horizon, segment_relevance, affected_pillars, source_ids, is_active, last_refreshed, created_at, updated_at, is_foundational, verification_verdict, verification_source, verification_evidence, financial_context, key_dates, citations, first_seen_date, last_confirmed_date, confirmation_count) VALUES (171, 'tvs_family_governance_dispute_â€”_sundaram_clayton_l', 'TVS Family Governance Dispute â€” Sundaram Clayton Leadership Risk', 'S', 'The boardroom rift at Sundaram Clayton â€” a major auto component Tier-1 supplier â€” with Venu Srinivasan taking governance charge signals leadership instability at a strategically significant supplier. For OEM procurement teams and co-investors, governance disruption at a Tier-1 creates supply continuity risk and may delay technology investment decisions at a critical EV transition juncture.', 7, 'The dispute is confirmed and publicly reported by ET Auto with named principals (Venu Srinivasan vs Lakshmi), indicating it has escalated beyond internal resolution. TVS Motor''s strong performance under Sudarshan Venu is cited as creating internal contrast pressure.', 4, 'Sundaram Clayton is a significant Tier-1 supplier (die castings, EV components). Leadership instability typically delays capex decisions by 6â€“12 months and can trigger OEM dual-sourcing mandates. The impact is contained to Sundaram Clayton''s specific customer base but signals broader governance risk in family-owned Tier-1 suppliers navigating EV transition.', NULL, 'new', 'short', '{"2W": "H", "3W": "L", "HCV": "L", "LCV": "L", "4W_PV": "M", "Tractor": "L"}', '["Compute", "Motion", "Energy"]', '{}', true, '2026-04-03 11:14:00.65269+05:30', '2026-04-03 11:14:00.65269+05:30', '2026-04-03 11:14:00.65269+05:30', false, 'UNVERIFIED', '', '', '{"market_opportunity": "N/A", "industry_investment": "Sundaram Clayton capex plans (undisclosed; parent TVS Group multi-thousand crore EV investment)", "subsidy_or_incentive": "N/A", "government_investment": "N/A", "cost_impact_per_vehicle": "N/A"}', '{"announced": "2026-04-02", "effective": "2026-04-02", "completion": ""}', '[{"url": "https://auto.economictimes.indiatimes.com/news/industry/tvs-family-rift-spills-into-sundaram-clayton-boardroom-venu-srinivasan-takes-governance-charge-tells-lakshmi-to-focus-on-biz/129965411", "claim": "TVS family rift spills into Sundaram Clayton boardroom; Venu Srinivasan takes governance charge and tells Lakshmi to focus on business; TVS Motor under Sudarshan Venu has delivered strong growth creating internal contrast", "source": "ET Auto, 02 Apr 2026"}]', '2026-04-03 11:14:00.65269+05:30', '2026-04-03 11:14:00.65269+05:30', 1); ON CONFLICT DO NOTHING;
INSERT INTO public.pestel_factors (id, code, name, category, selection_reasoning, likelihood, likelihood_reasoning, impact, impact_reasoning, origin_date, trend, time_horizon, segment_relevance, affected_pillars, source_ids, is_active, last_refreshed, created_at, updated_at, is_foundational, verification_verdict, verification_source, verification_evidence, financial_context, key_dates, citations, first_seen_date, last_confirmed_date, confirmation_count) VALUES (88, 'small_car_segment_rebound_under_gst_2.0_â€”_entry_le', 'Small car segment rebound under GST 2.0 â€” entry-level content opportunity', 'E', 'The GST reduction triggered a sharp rebound specifically in small cars (sub-â‚¹8L segment), which had been declining for 3+ years. This segment revival is strategically important for Bosch because small car OEMs (Maruti, Hyundai) are now under pressure to add OBD-II compliance, AEB readiness, and connected features to entry-level models â€” creating new content opportunities in a previously low-content segment. The volume scale (small cars represent ~40% of PV market) amplifies even modest per-unit content additions.', 7, 'The small car rebound is confirmed by ET Auto''s FY26 sales data showing H2 growth of ~15%. GST reduction is a permanent policy change (not a temporary incentive), making the demand recovery structural rather than transient. Maruti and Hyundai have both announced new small car investments.', 5, 'Small cars historically carry â‚¹8,000-12,000 of Bosch content (vs â‚¹20,000-35,000 for SUVs). However, OBD-II mandates and AEB readiness requirements are forcing content upgrades even in entry-level models. An incremental â‚¹3,000-5,000 per vehicle across ~1.5M small car units annually implies â‚¹450-750 Cr addressable revenue expansion. Margin profile is lower than premium segments.', NULL, 'escalating', 'immediate', '{"2W": "L", "3W": "L", "HCV": "L", "LCV": "L", "4W_PV": "H", "Tractor": "L"}', '["Body & Comfort", "Infotainment", "Motion"]', '{}', true, '2026-03-17 10:47:58.048368+05:30', '2026-03-17 10:47:58.048368+05:30', '2026-03-17 10:47:58.048368+05:30', false, 'UNVERIFIED', NULL, NULL, '{}', '{}', '[]', '2026-03-17 10:47:58.048368+05:30', '2026-03-17 10:47:58.048368+05:30', 1); ON CONFLICT DO NOTHING;
INSERT INTO public.pestel_factors (id, code, name, category, selection_reasoning, likelihood, likelihood_reasoning, impact, impact_reasoning, origin_date, trend, time_horizon, segment_relevance, affected_pillars, source_ids, is_active, last_refreshed, created_at, updated_at, is_foundational, verification_verdict, verification_source, verification_evidence, financial_context, key_dates, citations, first_seen_date, last_confirmed_date, confirmation_count) VALUES (35, 'data_privacy_adas_regulations', 'India DPDP Act 2023 â€” vehicle data privacy compliance', 'L', 'Digital Personal Data Protection Act (DPDP) 2023 applies to vehicle-generated data. Connected vehicles collecting passenger data (location, biometrics for DMS) must comply â€” adding compliance engineering cost but also creating barriers to entry for new players.', 8, 'Score 8: DPDP Act enacted. Rules being finalized by MeitY. Data Protection Board to be constituted. Implementation certainty is high, exact timeline of enforcement is moderate.', 4, 'Score 5: Compliance cost is real but manageable for large Tier-1s. Creates differentiation opportunity for Bosch vs smaller players who may not have compliance infrastructure.', NULL, 'new', 'short', '{"2W": "L", "3W": "L", "HCV": "L", "LCV": "L", "4W_PV": "H", "Tractor": "L"}', '["ADAS", "Cloud", "ECUs", "Infotainment", "OS", "Services"]', '{20}', true, '2026-03-16 22:45:46.381831+05:30', '2026-03-16 22:45:46.381831+05:30', '2026-03-16 22:48:13.097302+05:30', false, 'UNVERIFIED', NULL, NULL, '{}', '{}', '[]', '2026-03-16 22:45:46.381831+05:30', '2026-03-16 22:45:46.381831+05:30', 1); ON CONFLICT DO NOTHING;
INSERT INTO public.pestel_factors (id, code, name, category, selection_reasoning, likelihood, likelihood_reasoning, impact, impact_reasoning, origin_date, trend, time_horizon, segment_relevance, affected_pillars, source_ids, is_active, last_refreshed, created_at, updated_at, is_foundational, verification_verdict, verification_source, verification_evidence, financial_context, key_dates, citations, first_seen_date, last_confirmed_date, confirmation_count) VALUES (131, 'fame_subsidy_extension_sought_â€”_2w/3w_ev_demand_co', 'FAME Subsidy Extension Sought â€” 2W/3W EV Demand Continuity Risk', 'P', 'Finance Ministry approval is being sought to extend EV subsidies for 2W and 3W, with only 1M of 1.4M target units sold under the current scheme (ET Auto, March 2026). Subsidy continuity directly determines near-term EV demand in the two highest-volume EV segments. Bosch''s EV powertrain and charging infrastructure pillars are exposed to demand cliff risk if subsidies lapse.', 7, 'The government has a track record of extending FAME-linked schemes (FAME I to FAME II to FAME III). However, Finance Ministry scrutiny and fiscal consolidation pressures in FY27 introduce genuine uncertainty. The 71% target achievement rate signals underperformance that could reduce political will for extension.', 7, '3W EV penetration is already 55% and partially self-sustaining on TCO economics. 2W EV at 6% penetration remains subsidy-sensitive â€” removal could reduce 2W EV sales by 20-30% in the near term (Estimate based on: FAME II demand elasticity studies). This directly affects Bosch''s EV powertrain and BMS addressable market in the 2W/3W segments.', NULL, 'escalating', 'immediate', '{"2W": "H", "3W": "H", "HCV": "L", "LCV": "L", "4W_PV": "L", "Tractor": "L"}', '["EV Powertrain", "Energy & Charging", "Thermal Management"]', '{}', false, '2026-03-26 11:21:49.300728+05:30', '2026-03-26 11:21:49.300728+05:30', '2026-03-26 11:21:49.300728+05:30', true, 'UNVERIFIED', NULL, NULL, '{}', '{}', '[]', '2026-03-26 11:21:49.300728+05:30', '2026-03-26 11:21:49.300728+05:30', 1); ON CONFLICT DO NOTHING;
INSERT INTO public.pestel_factors (id, code, name, category, selection_reasoning, likelihood, likelihood_reasoning, impact, impact_reasoning, origin_date, trend, time_horizon, segment_relevance, affected_pillars, source_ids, is_active, last_refreshed, created_at, updated_at, is_foundational, verification_verdict, verification_source, verification_evidence, financial_context, key_dates, citations, first_seen_date, last_confirmed_date, confirmation_count) VALUES (167, 'vinfast_india_7_seater_ev_mpv_launch_â€”_new_oem_dem', 'VinFast India 7-Seater EV MPV Launch â€” New OEM Demand Node', 'E', 'VinFast''s entry into the Indian 7-seater EV MPV segment with 500+ km range and fast charging creates a new OEM demand node for Tier-1 suppliers. As a greenfield OEM without legacy Indian supply relationships, VinFast represents both a sourcing opportunity and a competitive pressure point â€” particularly for thermal management, charging, and infotainment systems.', 5, 'Bookings are open across 50 showrooms with a â‚¹21,000 booking amount and Delhi launch confirmed for April 15, 2026, per ET Auto. However, VinFast''s global track record of volume delivery remains mixed, introducing execution risk.', 3, 'As a new entrant with unproven India volume, the immediate component demand is limited. However, the 7-seater EV MPV segment is underpenetrated, and success could open a â‚¹3,000â€“5,000 Cr component opportunity over 3â€“5 years (Estimate based on: 20,000â€“30,000 units/year at â‚¹1.5â€“2L EV content per vehicle).', NULL, 'new', 'short', '{"2W": "L", "3W": "L", "HCV": "L", "LCV": "L", "4W_PV": "H", "Tractor": "L"}', '["Infotainment", "Energy"]', '{}', true, '2026-04-03 11:14:00.65269+05:30', '2026-04-03 11:14:00.65269+05:30', '2026-04-03 11:14:00.65269+05:30', false, 'UNVERIFIED', '', '', '{"market_opportunity": "Estimate based on: 7-seater EV MPV segment nascent; â‚¹3,000â€“5,000 Cr component TAM over 5 years if VinFast achieves 25,000+ units/year", "industry_investment": "VinFast India manufacturing investment (undisclosed; global capex context: $4B Vietnam plant)", "subsidy_or_incentive": "GST 5% on EVs; potential PLI eligibility if local manufacturing established", "government_investment": "N/A", "cost_impact_per_vehicle": "N/A"}', '{"announced": "2026-04-02", "effective": "2026-04-15", "completion": ""}', '[{"url": "https://auto.economictimes.indiatimes.com/news/industry/vinfast-india-to-launch-7-seater-electric-mpv-in-delhi-on-april-15/129967797", "claim": "VinFast India to launch 7-seater electric MPV in Delhi on April 15; bookings open at â‚¹21,000 across 50 showrooms with 500+ km range and fast charging", "source": "ET Auto, 02 Apr 2026"}]', '2026-04-03 11:14:00.65269+05:30', '2026-04-03 11:14:00.65269+05:30', 1); ON CONFLICT DO NOTHING;
INSERT INTO public.pestel_factors (id, code, name, category, selection_reasoning, likelihood, likelihood_reasoning, impact, impact_reasoning, origin_date, trend, time_horizon, segment_relevance, affected_pillars, source_ids, is_active, last_refreshed, created_at, updated_at, is_foundational, verification_verdict, verification_source, verification_evidence, financial_context, key_dates, citations, first_seen_date, last_confirmed_date, confirmation_count) VALUES (103, 'exicom_evse_export_ambition_â€”_india_as_global_char', 'Exicom EVSE Export Ambition â€” India as Global Charger Hub', 'T', 'Exicom''s Hyderabad plant explicitly targets exports to Southeast Asia, Europe, and the US â€” positioning India as a competitive EVSE manufacturing hub. This mirrors Bosch''s own export strategy for auto components and signals that India-made EV chargers will compete with Bosch''s global EVSE offerings in third markets. The India-EU FTA (January 2026) further reduces tariff barriers for Indian-made chargers entering Europe.', 6, 'Exicom''s export intent is stated and backed by a commissioned â‚¹216 Cr facility (ET Auto, March 2026). India-EU FTA tariff reduction over 7 years makes Indian EVSE increasingly price-competitive in Europe. Southeast Asia is an immediate export market given proximity and growing EV adoption.', 3, 'Bosch''s global EVSE business competes in the same markets Exicom is targeting. Indian-manufactured chargers with 30-40% lower labour cost structures could undercut Bosch''s European-manufactured EVSE on price in emerging markets. However, Bosch''s technology differentiation (DC fast charging, grid integration software) provides near-term protection. Medium-term margin pressure is the primary risk.', NULL, 'new', 'medium', '{"2W": "L", "3W": "L", "HCV": "L", "LCV": "L", "4W_PV": "M", "Tractor": "L"}', '["Compute", "Energy", "OS"]', '{}', true, '2026-03-17 16:31:52.563836+05:30', '2026-03-17 16:31:52.563836+05:30', '2026-03-17 16:31:52.563836+05:30', false, 'UNVERIFIED', NULL, NULL, '{}', '{}', '[]', '2026-03-17 16:31:52.563836+05:30', '2026-03-17 16:31:52.563836+05:30', 1); ON CONFLICT DO NOTHING;
INSERT INTO public.pestel_factors (id, code, name, category, selection_reasoning, likelihood, likelihood_reasoning, impact, impact_reasoning, origin_date, trend, time_horizon, segment_relevance, affected_pillars, source_ids, is_active, last_refreshed, created_at, updated_at, is_foundational, verification_verdict, verification_source, verification_evidence, financial_context, key_dates, citations, first_seen_date, last_confirmed_date, confirmation_count) VALUES (161, 'cv_financing_stress_â€”_fuel_cost_pass_through_&_tri', 'CV Financing Stress â€” Fuel Cost Pass-Through & Trip Reduction', 'E', 'Nomura analysis confirms that while large fleet operators can pass on fuel cost increases, the structural challenge is a reduction in trip volumes, which directly suppresses CV utilisation and defers new vehicle purchases. For Tier-1 suppliers, this signals a potential softening in HCV/LCV OEM production schedules in FY27, affecting powertrain, chassis, and telematics component demand.', 8, 'The Nomura analysis cited in ET Auto is a credible institutional source. The mechanism â€” fuel cost inflation reducing trip economics â€” is structurally sound and consistent with historical CV cycle behaviour. However, large operators'' ability to partially pass through costs provides a buffer against severe demand collapse.', 6, 'HCV and LCV together represent ~9.6L units annually. A 5% demand softening would remove ~48,000 units from the production schedule, reducing Tier-1 component revenue by an estimated â‚¹1,200-1,500 Cr. Estimate based on: average component content of â‚¹2.5-3.0L per HCV/LCV unit. The impact is moderated by fleet renewal needs and AEBS mandate compliance driving replacement demand.', NULL, 'escalating', 'short', '{"2W": "L", "3W": "M", "HCV": "H", "LCV": "H", "4W_PV": "L", "Tractor": "L"}', '["Infotainment", "Motion"]', '{}', true, '2026-04-01 11:05:44.591993+05:30', '2026-04-01 11:05:44.591993+05:30', '2026-04-01 11:05:44.591993+05:30', false, 'UNVERIFIED', NULL, NULL, '{}', '{}', '[]', '2026-04-01 11:05:44.591993+05:30', '2026-04-01 11:05:44.591993+05:30', 1); ON CONFLICT DO NOTHING;
INSERT INTO public.pestel_factors (id, code, name, category, selection_reasoning, likelihood, likelihood_reasoning, impact, impact_reasoning, origin_date, trend, time_horizon, segment_relevance, affected_pillars, source_ids, is_active, last_refreshed, created_at, updated_at, is_foundational, verification_verdict, verification_source, verification_evidence, financial_context, key_dates, citations, first_seen_date, last_confirmed_date, confirmation_count) VALUES (114, 'fame_subsidy_extension_sought_for_2w/3w_â€”_policy_c', 'FAME Subsidy Extension Sought for 2W/3W â€” Policy Continuity Risk', 'P', 'As of April 2026, the subsidy extension decision is likely concluded. Industry signals suggest a partial continuation under PM E-DRIVE scheme framework rather than a standalone FAME extension, with revised (lower) per-vehicle subsidy amounts for 2W and targeted support for 3W fleet operators. The policy continuity risk has partially materialised â€” subsidy quantum for 2W has likely been reduced, creating near-term demand softness in the mass-market EV 2W segment. Confirm against MHI/Finance Ministry official notification.', 7, 'The government has historically extended FAME-linked schemes (FAME I to FAME II to FAME III). However, Finance Ministry gatekeeping and fiscal consolidation pressures (India fiscal deficit target 4.5% FY26) create genuine approval risk. The 71% target achievement rate signals demand elasticity to subsidy levels.', 6, 'A subsidy gap or reduction of even 3-6 months could reduce e-2W monthly run rate by 30-40% based on historical FAME II transition data. This directly impacts Bosch''s EV Powertrain component demand in the 2W/3W segments, which at 55% EV penetration in 3W is already a significant revenue stream. Estimate: â‚¹150-300 Cr demand impact per quarter of subsidy uncertainty.', NULL, 'stable', 'immediate', '{"2W": "H", "3W": "H", "HCV": "L", "LCV": "L", "4W_PV": "L", "Tractor": "L"}', '["Energy"]', '{}', true, '2026-04-09 11:49:28.359582+05:30', '2026-03-26 11:21:49.301521+05:30', '2026-03-26 11:21:49.30067+05:30', true, 'UNVERIFIED', NULL, NULL, '{}', '{}', '[]', '2026-03-26 11:21:49.301521+05:30', '2026-04-09 11:49:28.359582+05:30', 1); ON CONFLICT DO NOTHING;
INSERT INTO public.pestel_factors (id, code, name, category, selection_reasoning, likelihood, likelihood_reasoning, impact, impact_reasoning, origin_date, trend, time_horizon, segment_relevance, affected_pillars, source_ids, is_active, last_refreshed, created_at, updated_at, is_foundational, verification_verdict, verification_source, verification_evidence, financial_context, key_dates, citations, first_seen_date, last_confirmed_date, confirmation_count) VALUES (87, 'atul_auto_board_tech_upgrade_â€”_3w_ev_governance_si', 'Atul Auto board tech upgrade â€” 3W EV governance signal', 'P', 'Atul Auto''s appointment of KC Vora (IIT Gandhinagar Automotive CoE) as Independent Director signals a governance-level commitment to technology upgrading in the 3W segment. Atul Auto competes in the CNG and EV 3W space where Bosch supplies powertrain and diagnostics components. Board-level tech focus at a mid-tier 3W OEM typically precedes platform investment decisions â€” this is an early signal of potential new sourcing opportunities for Bosch''s EV Powertrain and Vehicle Diagnostics pillars.', 5, 'Board appointments are confirmed facts (ET Auto, March 2026), but the translation from governance signal to specific technology procurement is uncertain. Atul Auto''s scale (~50,000 units/year) limits the revenue opportunity even if Bosch wins new content.', 2, 'Atul Auto''s annual volumes and revenue base are small relative to Bosch''s total addressable market. Even full EV platform content from Atul Auto would represent <â‚¹50 Cr annual revenue for Bosch. The factor is worth monitoring as a leading indicator of 3W segment technology investment but is not a material near-term revenue driver.', NULL, 'new', 'medium', '{"2W": "L", "3W": "H", "HCV": "L", "LCV": "L", "4W_PV": "L", "Tractor": "L"}', '["Energy", "Infotainment", "Motion"]', '{}', false, '2026-03-17 10:47:58.048368+05:30', '2026-03-17 10:47:58.048368+05:30', '2026-03-17 10:47:58.048368+05:30', false, 'UNVERIFIED', NULL, NULL, '{}', '{}', '[]', '2026-03-17 10:47:58.048368+05:30', '2026-03-17 10:47:58.048368+05:30', 1); ON CONFLICT DO NOTHING;
INSERT INTO public.pestel_factors (id, code, name, category, selection_reasoning, likelihood, likelihood_reasoning, impact, impact_reasoning, origin_date, trend, time_horizon, segment_relevance, affected_pillars, source_ids, is_active, last_refreshed, created_at, updated_at, is_foundational, verification_verdict, verification_source, verification_evidence, financial_context, key_dates, citations, first_seen_date, last_confirmed_date, confirmation_count) VALUES (81, 'domestic_ev_charger_manufacturing_scale_up_â€”_local', 'Domestic EV charger manufacturing scale-up â€” localisation cost reduction', 'T', 'Exicom''s Hyderabad plant producing power modules locally, combined with other domestic EVSE manufacturers scaling up, is driving localisation of EV charging hardware that was previously import-dependent. This creates a structural cost reduction in India''s charging infrastructure deployment, accelerating EV adoption across all segments and expanding the downstream market for Bosch''s EV powertrain and thermal management systems.', 7, 'Plant commissioning is confirmed (ET Auto, March 2026). PLI incentives for advanced chemistry cells and EVSE components provide sustained policy support. Multiple players (Exicom, Tata Power, Servotech) are simultaneously scaling, making domestic manufacturing normalisation near-certain within 24 months.', 5, 'Lower charging infrastructure costs reduce the ''range anxiety'' barrier for EV adoption, accelerating the EV penetration curve beyond the current 8% baseline. For Bosch, faster EV adoption expands the addressable market for EV Powertrain, BMS, and Thermal Management pillars while compressing the ICE powertrain runway. Net impact depends on Bosch''s EV content capture rate versus ICE revenue erosion.', NULL, 'escalating', 'short', '{"2W": "M", "3W": "M", "HCV": "L", "LCV": "M", "4W_PV": "H", "Tractor": "L"}', '["Energy", "OS"]', '{}', true, '2026-03-16 23:47:58.163502+05:30', '2026-03-16 23:47:58.163502+05:30', '2026-03-16 23:47:58.163502+05:30', false, 'UNVERIFIED', NULL, NULL, '{}', '{}', '[]', '2026-03-16 23:47:58.163502+05:30', '2026-03-16 23:47:58.163502+05:30', 1); ON CONFLICT DO NOTHING;
INSERT INTO public.pestel_factors (id, code, name, category, selection_reasoning, likelihood, likelihood_reasoning, impact, impact_reasoning, origin_date, trend, time_horizon, segment_relevance, affected_pillars, source_ids, is_active, last_refreshed, created_at, updated_at, is_foundational, verification_verdict, verification_source, verification_evidence, financial_context, key_dates, citations, first_seen_date, last_confirmed_date, confirmation_count) VALUES (29, 'euro7_rde_compliance_export', 'Euro 7 RDE compliance for India-manufactured exports (July 2025)', 'En', 'Euro 7 new type approvals for passenger cars and light commercial vehicles became effective July 2025 in the EU. Indian component exporters supplying Tier-1 EU OEMs are now operating under Euro 7 technical requirements. The India-EU FTA (signed January 2026) does not provide emissions compliance waivers â€” Rules of Origin and technical standards remain separate tracks. Indian exporters of exhaust systems, sensors, and powertrain components face active retooling requirements. Heavy vehicle Euro 7 compliance deadline (2027) provides a near-term window for CV component exporters.', 8, 'Score 9: Euro 7 Regulation (EU) 2024/1257 enacted. Applies to new EU type approvals from July 2025. Indian exporters must comply for EU-bound vehicles.', 6, 'Score 7: Creates compliance investment requirement (cost) but also differentiates Bosch India''s export-ready powertrain components from non-compliant competitors. Net marginal positive.', NULL, 'new', 'immediate', '{"2W": "L", "3W": "L", "HCV": "M", "LCV": "H", "4W_PV": "H", "Tractor": "L"}', '["Actuators", "Infotainment", "Motion", "OS"]', '{11}', true, '2026-04-09 11:49:28.356884+05:30', '2026-03-16 22:45:46.381831+05:30', '2026-03-16 22:48:13.097302+05:30', true, 'UNVERIFIED', NULL, NULL, '{}', '{}', '[]', '2026-03-16 22:45:46.381831+05:30', '2026-04-09 11:49:28.356884+05:30', 1); ON CONFLICT DO NOTHING;
INSERT INTO public.pestel_factors (id, code, name, category, selection_reasoning, likelihood, likelihood_reasoning, impact, impact_reasoning, origin_date, trend, time_horizon, segment_relevance, affected_pillars, source_ids, is_active, last_refreshed, created_at, updated_at, is_foundational, verification_verdict, verification_source, verification_evidence, financial_context, key_dates, citations, first_seen_date, last_confirmed_date, confirmation_count) VALUES (195, 'classic_legends_capacity_expansion_â€”_niche_2w_volu', 'Classic Legends Capacity Expansion â€” Niche 2W Volume Signal', 'E', 'Classic Legends'' planned greenfield factory expansion â€” driven by sold-out production and bookings exceeding capacity â€” signals sustained demand in the premium/retro 2W segment. For Tier-1 suppliers, a new greenfield facility represents a fresh supplier qualification opportunity across body electronics, chassis systems, and ICE powertrain components. The premium positioning also implies higher content-per-vehicle than mass-market 2W, improving margin profiles for component suppliers.', 7, 'Classic Legends has confirmed the expansion intent with four existing plants at ~94% utilisation (Studds data provides a parallel capacity constraint signal in the same geography). The company is sold out with bookings exceeding production, providing clear demand justification. Greenfield execution risk and financing remain variables.', 4, 'Classic Legends'' current volumes are modest (estimated 50,000-80,000 units/year), limiting absolute component demand impact. However, the premium segment positioning and greenfield supplier qualification opportunity make this strategically relevant for Tier-1 suppliers seeking to diversify their 2W OEM base beyond Hero/Honda/TVS/Bajaj. The impact is moderate given the volume scale.', NULL, 'escalating', 'short', '{"2W": "H", "3W": "L", "HCV": "L", "LCV": "L", "4W_PV": "L", "Tractor": "L"}', '["Motion", "Infotainment", "Services"]', '{}', true, '2026-04-24 16:06:25.016681+05:30', '2026-04-24 16:06:25.016681+05:30', '2026-04-24 16:06:25.016681+05:30', false, 'UNVERIFIED', '', '', '{"market_opportunity": "Estimate based on: 1.5-2L additional annual units Ã— â‚¹25,000 avg component content = â‚¹375-500 Cr incremental component demand", "industry_investment": "Greenfield factory investment â€” specific capex not disclosed; comparable 2W greenfield facilities typically â‚¹300-600 Cr", "subsidy_or_incentive": "State government industrial incentives likely for greenfield location", "government_investment": "N/A", "cost_impact_per_vehicle": "N/A"}', '{"announced": "2026-04", "effective": "", "completion": "2028-12"}', '[{"url": "https://auto.economictimes.indiatimes.com/news/two-wheelers/classic-legends-plans-capacity-expansion-weighs-greenfield-factory/130481912", "claim": "Classic Legends plans capacity expansion, weighs greenfield factory; company is sold out with more bookings than it can produce", "source": "ET Auto, 24 Apr 2026"}, {"url": "https://auto.economictimes.indiatimes.com/news/two-wheelers/classic-legends-plans-capacity-expansion-weighs-greenfield-factory/130481912", "claim": "Production is expected to significantly increase in the coming years", "source": "ET Auto, 24 Apr 2026"}]', '2026-04-24 16:06:25.016681+05:30', '2026-04-24 16:06:25.016681+05:30', 1); ON CONFLICT DO NOTHING;
INSERT INTO public.pestel_factors (id, code, name, category, selection_reasoning, likelihood, likelihood_reasoning, impact, impact_reasoning, origin_date, trend, time_horizon, segment_relevance, affected_pillars, source_ids, is_active, last_refreshed, created_at, updated_at, is_foundational, verification_verdict, verification_source, verification_evidence, financial_context, key_dates, citations, first_seen_date, last_confirmed_date, confirmation_count) VALUES (133, 'maruti_â‚¹10,189_cr_gujarat_expansion_â€”_pv_volume_&_', 'Maruti â‚¹10,189 Cr Gujarat Expansion â€” PV Volume & Content Uplift', 'E', 'Maruti Suzuki''s Board-approved â‚¹10,189 Cr investment in Gujarat adds 250,000 units Phase 1 capacity with infrastructure for future phases (ET Auto, March 2026). As Bosch''s largest single 4W PV customer in India, Maruti''s capacity expansion directly scales addressable volume for powertrain, chassis, ADAS, and body electronics content. The simultaneous IT leadership reshuffle signals accelerating digital/software integration.', 9, 'Board approval is confirmed and capital allocation is committed. Maruti''s stated target of 35% rail dispatch share by FY31 (Manesar siding data) indicates long-term production scaling confidence. Gujarat plant Phase 1 is expected operational by FY28.', 6, '250,000 additional units at Bosch''s estimated average content of â‚¹25,000â€“40,000 per PV represents â‚¹625â€“1,000 Cr incremental annual revenue opportunity at full utilisation. Maruti''s premiumisation push (SUV models) increases per-unit content further. The IT reshuffle signals potential for deeper software/connectivity integration â€” upside for Bosch''s Software & Services pillar.', NULL, 'escalating', 'medium', '{"2W": "L", "3W": "L", "HCV": "L", "LCV": "L", "4W_PV": "H", "Tractor": "L"}', '["Infotainment", "Motion", "OS"]', '{}', true, '2026-03-26 11:21:49.300728+05:30', '2026-03-26 11:21:49.300728+05:30', '2026-03-26 11:21:49.300728+05:30', false, 'UNVERIFIED', NULL, NULL, '{}', '{}', '[]', '2026-03-26 11:21:49.300728+05:30', '2026-03-26 11:21:49.300728+05:30', 1); ON CONFLICT DO NOTHING;
INSERT INTO public.pestel_factors (id, code, name, category, selection_reasoning, likelihood, likelihood_reasoning, impact, impact_reasoning, origin_date, trend, time_horizon, segment_relevance, affected_pillars, source_ids, is_active, last_refreshed, created_at, updated_at, is_foundational, verification_verdict, verification_source, verification_evidence, financial_context, key_dates, citations, first_seen_date, last_confirmed_date, confirmation_count) VALUES (73, 'ola_electric_â‚¹2,000_cr_battery_arm_fundraise_â€”_cel', 'Ola Electric â‚¹2,000 Cr battery arm fundraise â€” cell localisation acceleration', 'E', 'Ola Electric''s â‚¹2,000 Crore stake sale in its battery subsidiary signals aggressive capital deployment toward domestic cell manufacturing, directly threatening Bosch''s BMS and EV powertrain component supply positioning. If Ola vertically integrates battery packs and BMS, it reduces Bosch''s addressable content in India''s largest 2W EV OEM. Conversely, it validates the scale of India''s EV battery ecosystem, creating downstream demand for Bosch''s thermal management and charging infrastructure pillars.', 8, 'Avendus Capital and Motilal Oswal have been formally mandated per ET Auto (March 2026), indicating the process is active. Ola Electric''s stated expansion roadmap and existing Gigafactory investments corroborate intent. Fundraising closure within 12 months is highly probable given investor appetite for EV battery assets.', 4, '2W EV segment is 1.96 Crore units with ~6% EV share (~1.18 lakh units) growing rapidly. Ola holds ~30-35% of 2W EV market. Vertical integration of BMS by Ola could displace â‚¹200-400 Crore of potential Bosch EV powertrain content over 3 years. However, it also validates the ecosystem for Bosch''s Energy & Charging and Thermal Management pillars.', NULL, 'escalating', 'short', '{"2W": "H", "3W": "L", "HCV": "L", "LCV": "L", "4W_PV": "L", "Tractor": "L"}', '["ADAS", "Energy"]', '{}', true, '2026-03-16 23:47:58.163502+05:30', '2026-03-16 23:47:58.163502+05:30', '2026-03-16 23:47:58.163502+05:30', false, 'UNVERIFIED', NULL, NULL, '{}', '{}', '[]', '2026-03-16 23:47:58.163502+05:30', '2026-03-16 23:47:58.163502+05:30', 1); ON CONFLICT DO NOTHING;
INSERT INTO public.pestel_factors (id, code, name, category, selection_reasoning, likelihood, likelihood_reasoning, impact, impact_reasoning, origin_date, trend, time_horizon, segment_relevance, affected_pillars, source_ids, is_active, last_refreshed, created_at, updated_at, is_foundational, verification_verdict, verification_source, verification_evidence, financial_context, key_dates, citations, first_seen_date, last_confirmed_date, confirmation_count) VALUES (128, 'maruti_it/tech_leadership_reshuffle_â€”_digital_proc', 'Maruti IT/Tech Leadership Reshuffle â€” Digital Procurement Signal', 'P', 'Maruti Suzuki''s management reshuffle giving Dr. Tapan Sahoo additional charge of IT alongside technology and service/parts verticals signals an integrated digital-technology strategy at India''s largest 4W OEM. This organisational consolidation could accelerate Maruti''s adoption of connected vehicle platforms, OTA updates, and digital diagnostics â€” all areas where Bosch competes. It also signals a single decision-maker for technology procurement across multiple Bosch-relevant domains.', 7, 'The reshuffle is confirmed and effective (ET Auto, March 2026). Organisational changes of this nature at OEMs typically precede technology strategy shifts within 12-18 months as the new leader consolidates vendor relationships.', 3, 'The direct revenue impact is indirect â€” this is a relationship and positioning risk/opportunity rather than a volume driver. However, Maruti''s scale (43L+ units, largest India OEM) means that a technology strategy shift at the CTO level could redirect â‚¹500-1,000 Cr in annual technology procurement. Bosch must engage proactively with the new leadership structure.', NULL, 'new', 'short', '{"2W": "L", "3W": "L", "HCV": "L", "LCV": "L", "4W_PV": "H", "Tractor": "L"}', '["Compute", "Infotainment", "OS"]', '{}', false, '2026-03-26 11:21:49.30067+05:30', '2026-03-26 11:21:49.30067+05:30', '2026-03-26 11:21:49.30067+05:30', false, 'UNVERIFIED', NULL, NULL, '{}', '{}', '[]', '2026-03-26 11:21:49.30067+05:30', '2026-03-26 11:21:49.30067+05:30', 1); ON CONFLICT DO NOTHING;
INSERT INTO public.pestel_factors (id, code, name, category, selection_reasoning, likelihood, likelihood_reasoning, impact, impact_reasoning, origin_date, trend, time_horizon, segment_relevance, affected_pillars, source_ids, is_active, last_refreshed, created_at, updated_at, is_foundational, verification_verdict, verification_source, verification_evidence, financial_context, key_dates, citations, first_seen_date, last_confirmed_date, confirmation_count) VALUES (110, 'hero_honda_2w_market_share_battle_intensifies', 'Hero-Honda 2W Market Share Battle Intensifies', 'S', 'Hero MotoCorp (5.5M units) and Honda (5.2M units) together dominate India''s 2W market, representing ~55% of FY26 2W volume. This duopoly''s technology choices â€” OBD-II compliance, EV transition pace, ADAS content â€” directly determine Bosch''s addressable volume across Powertrain Solutions, Vehicle Diagnostics, and EV Powertrain pillars. Honda''s planned 2028 dedicated EV facility signals a medium-term platform shift.', 7, 'FY26 11-month data (ET Auto, Mar 2026) confirms the gap is narrowing to ~300K units. Honda''s Rajasthan capacity expansion and dedicated EV facility announcement are concrete capital commitments, not aspirational targets.', 5, 'Combined Hero+Honda 2W volume of ~10.7M units annually represents Bosch''s largest single-segment exposure. Technology content per unit is low (â‚¹800-1,500 for OBD-II sensors, ignition), but scale makes this strategically significant. Honda''s EV facility by 2028 could shift ~1-2M units to EV platform, affecting ICE powertrain component demand.', NULL, 'escalating', 'short', '{"2W": "H", "3W": "L", "HCV": "L", "LCV": "L", "4W_PV": "L", "Tractor": "L"}', '["Energy", "Infotainment", "Motion", "Services"]', '{}', false, '2026-03-26 11:21:49.301521+05:30', '2026-03-26 11:21:49.301521+05:30', '2026-03-26 11:21:49.304861+05:30', false, 'UNVERIFIED', NULL, NULL, '{}', '{}', '[]', '2026-03-26 11:21:49.301521+05:30', '2026-03-26 11:21:49.301521+05:30', 1); ON CONFLICT DO NOTHING;
INSERT INTO public.pestel_factors (id, code, name, category, selection_reasoning, likelihood, likelihood_reasoning, impact, impact_reasoning, origin_date, trend, time_horizon, segment_relevance, affected_pillars, source_ids, is_active, last_refreshed, created_at, updated_at, is_foundational, verification_verdict, verification_source, verification_evidence, financial_context, key_dates, citations, first_seen_date, last_confirmed_date, confirmation_count) VALUES (99, 'oem_digital_infrastructure_vulnerability_â€”_supply_', 'OEM digital infrastructure vulnerability â€” supply chain cyber risk', 'L', 'The JLR cyberattack''s legal and contractual fallout â€” production losses, warranty implications, and potential supplier claims â€” creates a new legal risk category for Tier-1 suppliers operating in OEM-integrated digital supply chains. Bosch''s increasing software and connectivity integration with OEM production systems (Industry 4.0, OTA, telematics) means it is both a potential attack vector and a party to contractual obligations around uptime and data security. This factor is distinct from the technology risk angle and focuses on legal liability and contractual exposure.', 7, 'India''s DPDP Act 2023 and the UN R155 framework create explicit legal obligations around vehicle cybersecurity. The JLR incident demonstrates that courts and regulators will scrutinise supply chain cyber hygiene. India''s IT Act amendments and sector-specific CERT-In directives are tightening compliance requirements for automotive suppliers.', 5, 'Legal liability from a supply-chain-linked cyber incident could expose Bosch to OEM claims for production losses â€” a five-week JLR-scale shutdown at an Indian OEM could represent â‚¹500-1,500 Cr in production value loss, with Tier-1 suppliers potentially bearing 5-15% of liability under indemnity clauses. Compliance investment in cyber-secure supply chain integration is estimated at â‚¹50-100 Cr over three years.', NULL, 'escalating', 'short', '{"2W": "L", "3W": "L", "HCV": "M", "LCV": "M", "4W_PV": "H", "Tractor": "L"}', '["ADAS", "Compute", "OS"]', '{}', false, '2026-03-17 16:32:41.583165+05:30', '2026-03-17 16:32:41.583165+05:30', '2026-03-17 16:32:41.583165+05:30', false, 'UNVERIFIED', NULL, NULL, '{}', '{}', '[]', '2026-03-17 16:32:41.583165+05:30', '2026-03-17 16:32:41.583165+05:30', 1); ON CONFLICT DO NOTHING;
INSERT INTO public.pestel_factors (id, code, name, category, selection_reasoning, likelihood, likelihood_reasoning, impact, impact_reasoning, origin_date, trend, time_horizon, segment_relevance, affected_pillars, source_ids, is_active, last_refreshed, created_at, updated_at, is_foundational, verification_verdict, verification_source, verification_evidence, financial_context, key_dates, citations, first_seen_date, last_confirmed_date, confirmation_count) VALUES (90, 'state_government_ev_investment_competition_â€”_manuf', 'State government EV investment competition â€” manufacturing location risk', 'P', 'Rajasthan''s active courting of Honda''s EV investment (CM-level engagement, ET Auto March 2026) illustrates intensifying state-level competition for EV manufacturing FDI, with states offering land, power subsidies, and tax incentives. For Bosch, this creates both opportunity (co-locate component manufacturing near new OEM plants) and risk (existing Bosch plants in Nashik, Jaipur, Bengaluru may face cost disadvantages vs greenfield incentive packages offered to competitors). Supply chain geography decisions made now will lock in cost structures for 10+ years.', 7, 'State EV investment competition is an established and accelerating trend â€” Tamil Nadu, Rajasthan, Gujarat, and Maharashtra are all actively competing. Honda''s Rajasthan engagement is the latest confirmed data point. This pattern will continue as more OEMs announce India EV investments.', 5, 'For Bosch, the primary impact is on manufacturing footprint strategy rather than immediate revenue. The risk of being geographically misaligned with new OEM clusters (e.g., if a major EV hub develops in Rajasthan while Bosch''s capacity is concentrated in Maharashtra/Karnataka) could add 3-5% logistics cost to component supply. Medium-term strategic planning issue rather than immediate P&L impact.', NULL, 'escalating', 'medium', '{"2W": "H", "3W": "L", "HCV": "L", "LCV": "M", "4W_PV": "H", "Tractor": "L"}', '["Compute", "Energy"]', '{}', true, '2026-03-17 10:47:58.048368+05:30', '2026-03-17 10:47:58.048368+05:30', '2026-03-17 10:47:58.048368+05:30', false, 'UNVERIFIED', NULL, NULL, '{}', '{}', '[]', '2026-03-17 10:47:58.048368+05:30', '2026-03-17 10:47:58.048368+05:30', 1); ON CONFLICT DO NOTHING;
INSERT INTO public.pestel_factors (id, code, name, category, selection_reasoning, likelihood, likelihood_reasoning, impact, impact_reasoning, origin_date, trend, time_horizon, segment_relevance, affected_pillars, source_ids, is_active, last_refreshed, created_at, updated_at, is_foundational, verification_verdict, verification_source, verification_evidence, financial_context, key_dates, citations, first_seen_date, last_confirmed_date, confirmation_count) VALUES (149, 'fame_subsidy_extension_sought_for_e_2w/3w_â€”_policy', 'FAME Subsidy Extension Sought for e-2W/3W â€” Policy Continuity Risk', 'P', 'The government seeking Finance Ministry approval to extend FAME subsidies for 2W and 3W EVs (with only 1M of 1.4M target units sold) signals both underperformance against EV adoption targets and political will to sustain demand support. For Bosch, subsidy continuity directly affects the pace of EV powertrain and BMS content adoption in the highest-volume EV segments (2W at 6%, 3W at 55% penetration).', 7, 'The Finance Ministry approval process is ongoing (ET Auto, March 2026). Historical precedent â€” FAME I extended to FAME II, FAME II extended multiple times â€” suggests political commitment to EV subsidies. However, fiscal consolidation pressures and the 29% target shortfall create genuine uncertainty about quantum and duration of extension.', 7, 'If subsidies lapse without extension, e-2W demand could fall 20-30% based on price sensitivity analysis (Estimate based on: FAME II removal impact on e-rickshaw sales 2019). This directly delays Bosch''s EV Powertrain revenue ramp in the 1.96Cr unit 2W segment. Conversely, extension accelerates the transition timeline and justifies Bosch''s EV component localisation investments.', NULL, 'stable', 'immediate', '{"2W": "H", "3W": "H", "HCV": "L", "LCV": "L", "4W_PV": "L", "Tractor": "L"}', '["EV Powertrain", "Energy & Charging", "Thermal Management"]', '{}', false, '2026-03-26 11:21:49.304861+05:30', '2026-03-26 11:21:49.304861+05:30', '2026-03-26 11:21:49.304861+05:30', true, 'UNVERIFIED', NULL, NULL, '{}', '{}', '[]', '2026-03-26 11:21:49.304861+05:30', '2026-03-26 11:21:49.304861+05:30', 1); ON CONFLICT DO NOTHING;
INSERT INTO public.pestel_factors (id, code, name, category, selection_reasoning, likelihood, likelihood_reasoning, impact, impact_reasoning, origin_date, trend, time_horizon, segment_relevance, affected_pillars, source_ids, is_active, last_refreshed, created_at, updated_at, is_foundational, verification_verdict, verification_source, verification_evidence, financial_context, key_dates, citations, first_seen_date, last_confirmed_date, confirmation_count) VALUES (89, 'multi_oem_ev_platform_proliferation_â€”_software_fra', 'Multi-OEM EV platform proliferation â€” software fragmentation risk', 'T', 'With Honda, Tata, Mahindra, Maruti, JSW, and MG all developing distinct EV platforms in India, Bosch faces increasing software and hardware integration complexity. Each OEM''s EV architecture requires customised BMS, inverter calibration, and ADAS integration â€” fragmenting Bosch''s R&D spend across multiple non-standardised platforms. This is a direct challenge to Bosch''s Software & Services pillar and its ability to maintain scalable, cost-efficient EV software development for the Indian market.', 8, 'Platform proliferation is already occurring â€” confirmed by Honda (ET Auto, March 2026), JSW Motors entry, and existing Tata/Mahindra/Maruti EV programmes. The trend will intensify as India-EU FTA and PLI incentives attract more OEM investments. Standardisation efforts (like AUTOSAR) exist but OEM-specific customisation remains dominant.', 6, 'Bosch''s global competitive advantage in automotive software is its ability to amortise R&D across high volumes. Indian EV platform fragmentation forces higher per-platform R&D investment, compressing margins on software-intensive components. Estimate: 20-30% higher software integration cost per platform vs a standardised architecture scenario. This could reduce Bosch India''s EV software margin by 3-5 percentage points.', NULL, 'escalating', 'medium', '{"2W": "L", "3W": "L", "HCV": "L", "LCV": "L", "4W_PV": "H", "Tractor": "L"}', '["Energy", "Infotainment", "Motion", "OS"]', '{}', true, '2026-03-17 10:47:58.048368+05:30', '2026-03-17 10:47:58.048368+05:30', '2026-03-17 10:47:58.048368+05:30', false, 'UNVERIFIED', NULL, NULL, '{}', '{}', '[]', '2026-03-17 10:47:58.048368+05:30', '2026-03-17 10:47:58.048368+05:30', 1); ON CONFLICT DO NOTHING;
INSERT INTO public.pestel_factors (id, code, name, category, selection_reasoning, likelihood, likelihood_reasoning, impact, impact_reasoning, origin_date, trend, time_horizon, segment_relevance, affected_pillars, source_ids, is_active, last_refreshed, created_at, updated_at, is_foundational, verification_verdict, verification_source, verification_evidence, financial_context, key_dates, citations, first_seen_date, last_confirmed_date, confirmation_count) VALUES (76, 'e_bus/truck_localisation_deadline_extension_â€”_trac', 'E-bus/truck localisation deadline extension â€” traction motor supply window', 'P', 'As of April 2026, the March 2026 traction motor localisation deadline has lapsed. Industry sources indicate partial compliance â€” major e-bus OEMs (Olectra, TATA, PMI) have achieved 40-60% local content in traction systems, but full localisation remains incomplete. MHI is evaluating a further 12-month extension with penalty provisions. This creates a near-term policy risk for OEMs and a continued import dependency on Chinese motor components, with implications for FAME III disbursement eligibility.', 8, 'Deadline extensions in India''s EV localisation policy have precedent (FAME II phased localisation). The government''s pragmatic approach to avoid supply disruption in the e-bus rollout programme makes further extensions or phased compliance likely. However, full localisation enforcement within 18-24 months is the stated policy direction.', 6, 'India''s e-bus programme targets 10,000+ buses under PM e-Bus Sewa; e-truck electrification is early-stage but growing. Traction motors represent â‚¹3-8 lakh per unit of component value. Bosch''s ability to qualify as a local supplier for this segment could determine its participation in a â‚¹3,000-8,000 Crore addressable market over 5 years.', NULL, 'escalating', 'short', '{"2W": "L", "3W": "L", "HCV": "H", "LCV": "M", "4W_PV": "L", "Tractor": "L"}', '["Compute", "Energy", "Infotainment"]', '{}', true, '2026-04-09 11:49:28.35526+05:30', '2026-03-16 23:47:58.163502+05:30', '2026-03-16 23:47:58.163502+05:30', true, 'UNVERIFIED', NULL, NULL, '{}', '{}', '[]', '2026-03-16 23:47:58.163502+05:30', '2026-04-09 11:49:28.35526+05:30', 1); ON CONFLICT DO NOTHING;
INSERT INTO public.pestel_factors (id, code, name, category, selection_reasoning, likelihood, likelihood_reasoning, impact, impact_reasoning, origin_date, trend, time_horizon, segment_relevance, affected_pillars, source_ids, is_active, last_refreshed, created_at, updated_at, is_foundational, verification_verdict, verification_source, verification_evidence, financial_context, key_dates, citations, first_seen_date, last_confirmed_date, confirmation_count) VALUES (112, 'maruti_gujarat_â‚¹10,189_cr_capacity_expansion_â€”_250', 'Maruti Gujarat â‚¹10,189 Cr Capacity Expansion â€” 250K Unit Phase 1', 'E', 'Maruti Suzuki''s board-approved â‚¹10,189 Cr Gujarat plant investment for 250,000 units Phase 1 (ET Auto, Mar 2026) is the single largest near-term greenfield PV capacity addition in India. As Bosch''s largest 4W PV customer, Maruti''s capacity expansion directly drives demand across Powertrain Solutions, Chassis Systems, Body Electronics, and Safety & Security pillars. The management reshuffle giving IT additional charge signals accelerating software/connected vehicle integration.', 9, 'Board approval is confirmed (ET Auto, Mar 2026) with specific capital quantum of â‚¹10,189 Cr. Maruti''s FY31 target of 35% rail dispatch share and ongoing Manesar rail siding scaling (1 lakh vehicles in 9 months) confirm operational execution capability.', 5, '250,000 additional units at â‚¹15,000-25,000 average Bosch content per vehicle implies â‚¹375-625 Cr incremental annual revenue at full utilisation. The IT/technology portfolio consolidation under one executive signals Maruti''s intent to accelerate connected vehicle and OTA capabilities â€” directly relevant to Bosch''s Software & Services and Infotainment pillars.', NULL, 'escalating', 'medium', '{"2W": "L", "3W": "L", "HCV": "L", "LCV": "L", "4W_PV": "H", "Tractor": "L"}', '["ADAS", "Infotainment", "Motion", "OS"]', '{}', false, '2026-03-26 11:21:49.301521+05:30', '2026-03-26 11:21:49.301521+05:30', '2026-03-26 11:21:49.304861+05:30', false, 'UNVERIFIED', NULL, NULL, '{}', '{}', '[]', '2026-03-26 11:21:49.301521+05:30', '2026-03-26 11:21:49.301521+05:30', 1); ON CONFLICT DO NOTHING;
INSERT INTO public.pestel_factors (id, code, name, category, selection_reasoning, likelihood, likelihood_reasoning, impact, impact_reasoning, origin_date, trend, time_horizon, segment_relevance, affected_pillars, source_ids, is_active, last_refreshed, created_at, updated_at, is_foundational, verification_verdict, verification_source, verification_evidence, financial_context, key_dates, citations, first_seen_date, last_confirmed_date, confirmation_count) VALUES (85, 'new_global_oem_ev_investments_in_india_â€”_multi_oem', 'New global OEM EV investments in India â€” multi-OEM EV platform proliferation', 'E', 'Honda''s â‚¹1,200 Crore Tapukara EV investment, combined with existing commitments from Maruti-Toyota, Hyundai, Tata, and Mahindra, signals a structural shift to multi-OEM EV platform proliferation in India''s 4W PV segment. This creates both opportunity (Bosch EV content across multiple platforms) and complexity (platform-specific engineering, multiple qualification cycles, higher R&D cost allocation per platform).', 8, 'Honda''s investment is confirmed at state government level. The broader trend of global OEM EV commitments to India is corroborated by PLI scheme investments (â‚¹35,657 Crore) and India''s positioning as a global EV manufacturing hub post India-EU FTA. Reversal risk is low given capital already committed.', 6, 'Multi-OEM EV platform proliferation expands Bosch''s total addressable EV content market in India''s 4W PV segment from a single-OEM scenario. If Bosch secures EV powertrain, thermal, and ADAS content across 5-6 OEM platforms at â‚¹40,000-80,000 per vehicle, and EV 4W volumes reach 500,000 units by FY28, the addressable opportunity is â‚¹2,000-4,000 Crore annually â€” a step-change from current EV revenue.', NULL, 'escalating', 'short', '{"2W": "L", "3W": "L", "HCV": "L", "LCV": "L", "4W_PV": "H", "Tractor": "L"}', '["Energy", "Motion", "OS"]', '{}', true, '2026-03-16 23:47:58.163502+05:30', '2026-03-16 23:47:58.163502+05:30', '2026-03-16 23:47:58.163502+05:30', false, 'UNVERIFIED', NULL, NULL, '{}', '{}', '[]', '2026-03-16 23:47:58.163502+05:30', '2026-03-16 23:47:58.163502+05:30', 1); ON CONFLICT DO NOTHING;
INSERT INTO public.pestel_factors (id, code, name, category, selection_reasoning, likelihood, likelihood_reasoning, impact, impact_reasoning, origin_date, trend, time_horizon, segment_relevance, affected_pillars, source_ids, is_active, last_refreshed, created_at, updated_at, is_foundational, verification_verdict, verification_source, verification_evidence, financial_context, key_dates, citations, first_seen_date, last_confirmed_date, confirmation_count) VALUES (105, 'ethanol_blending_e20_â€”_fuel_system_recalibration_a', 'Ethanol Blending E20 â€” Fuel System Recalibration Aftermarket Demand', 'En', 'India''s E20 ethanol blending mandate, accelerated by global oil price surges, creates a large aftermarket recalibration opportunity for Bosch''s fuel injection and engine management systems. The existing fleet of 200M+ ICE vehicles requires fuel system compatibility upgrades, and Bosch''s aftermarket and retrofit pillar is uniquely positioned to address this through its service network and diagnostic tools.', 9, 'E20 mandate is confirmed policy (ET Auto, March 2026 confirms ethanol blending as a ''core pillar of national energy security''). India achieved E12 blending in FY25 and is on track for E20 by FY27. The aftermarket demand is a mathematical certainty as E20 fuel reaches pumps and older vehicles require compatibility checks.', 7, 'India''s vehicle parc exceeds 300M units. Even a 10% aftermarket penetration for fuel system diagnostics and recalibration at â‚¹2,000-5,000 per vehicle represents a â‚¹6,000-15,000 Cr total addressable aftermarket. Bosch''s workshop network (Bosch Car Service) and diagnostic tools are positioned to capture a meaningful share. This is an underappreciated revenue stream in the ethanol transition narrative.', NULL, 'escalating', 'short', '{"2W": "H", "3W": "L", "HCV": "L", "LCV": "M", "4W_PV": "H", "Tractor": "L"}', '["Infotainment", "Motion", "Services"]', '{}', true, '2026-03-17 16:31:52.563836+05:30', '2026-03-17 16:31:52.563836+05:30', '2026-03-17 16:31:52.563836+05:30', true, 'UNVERIFIED', NULL, NULL, '{}', '{}', '[]', '2026-03-17 16:31:52.563836+05:30', '2026-03-17 16:31:52.563836+05:30', 1); ON CONFLICT DO NOTHING;
INSERT INTO public.pestel_factors (id, code, name, category, selection_reasoning, likelihood, likelihood_reasoning, impact, impact_reasoning, origin_date, trend, time_horizon, segment_relevance, affected_pillars, source_ids, is_active, last_refreshed, created_at, updated_at, is_foundational, verification_verdict, verification_source, verification_evidence, financial_context, key_dates, citations, first_seen_date, last_confirmed_date, confirmation_count) VALUES (125, 'euler_motors_â‚¹437.5_cr_raise_â€”_e_cv_startup_scalin', 'Euler Motors â‚¹437.5 Cr Raise â€” e-CV Startup Scaling in LCV/HCV EV', 'E', 'Euler Motors, backed by Hero MotoCorp, is targeting 100% revenue growth over FY25''s â‚¹191 Cr base in the electric commercial vehicle segment. This signals accelerating EV adoption in LCV/small HCV, a segment where Bosch has strong powertrain and fleet telematics offerings. New EV-native OEMs like Euler represent both a customer opportunity and a competitive threat if they verticalise components.', 8, 'Funding is confirmed at â‚¹437.5 Cr with Hero MotoCorp backing providing strategic credibility (ET Auto, March 2026). The e-CV segment has structural demand from last-mile logistics and fleet operators with ESG mandates.', 6, 'Euler''s current scale (â‚¹191 Cr FY25 revenue) is modest relative to Bosch''s India operations, but 100% growth trajectory and institutional backing suggest it could reach 10,000-20,000 units annually by FY27-28. Bosch''s EV powertrain, BMS, and telematics content per e-CV unit is â‚¹50,000-1,50,000 (Estimate based on: EV component content benchmarks). Strategic importance exceeds current revenue.', NULL, 'escalating', 'short', '{"2W": "L", "3W": "M", "HCV": "M", "LCV": "H", "4W_PV": "L", "Tractor": "L"}', '["EV Powertrain", "Infotainment & Connectivity", "Vehicle Diagnostics", "Thermal Management"]', '{}', false, '2026-03-26 11:21:49.30067+05:30', '2026-03-26 11:21:49.30067+05:30', '2026-03-26 11:22:14.095204+05:30', false, 'UNVERIFIED', NULL, NULL, '{}', '{}', '[]', '2026-03-26 11:21:49.30067+05:30', '2026-03-26 11:21:49.30067+05:30', 1); ON CONFLICT DO NOTHING;
INSERT INTO public.pestel_factors (id, code, name, category, selection_reasoning, likelihood, likelihood_reasoning, impact, impact_reasoning, origin_date, trend, time_horizon, segment_relevance, affected_pillars, source_ids, is_active, last_refreshed, created_at, updated_at, is_foundational, verification_verdict, verification_source, verification_evidence, financial_context, key_dates, citations, first_seen_date, last_confirmed_date, confirmation_count) VALUES (4, 'ev_transition_acceleration', 'EV penetration reaches 8% (CY2025) â€” inflection point', 'T', 'CY2025 EV sales data (VAHAN) confirms approximately 2.2-2.4M EV registrations, placing overall penetration at ~7.8-8.2% â€” broadly validating the inflection point thesis. 3W EV penetration crossed 58%, confirming irreversible category shift. 2W EV penetration reached ~6.5%. 4W EV penetration remained modest at ~2.8% due to price gap. As of April 2026, the inflection point is confirmed history; the forward question is whether CY2026 sustains 10%+ penetration amid FAME subsidy uncertainty and charging infrastructure gaps.', 7, 'Score 10: Vahan registration data confirms 2.3M EV units CY2025. Historical fact.', 8, 'Score 9: Single largest structural shift in auto components. Redefines 4/13 Bosch pillars. ICE Powertrain faces terminal decline in 3W, gradual in 2W.', NULL, 'escalating', 'medium', '{"2W": "H", "3W": "H", "HCV": "L", "LCV": "M", "4W_PV": "H", "Tractor": "L"}', '["ECUs", "Energy", "Motion", "OS", "Semiconductors"]', '{3}', true, '2026-04-09 11:49:28.358243+05:30', '2026-03-16 21:29:57.526355+05:30', '2026-03-16 22:48:13.097302+05:30', true, 'UNVERIFIED', NULL, NULL, '{}', '{}', '[]', '2026-03-16 21:29:57.526355+05:30', '2026-04-09 11:49:28.358243+05:30', 1); ON CONFLICT DO NOTHING;
INSERT INTO public.pestel_factors (id, code, name, category, selection_reasoning, likelihood, likelihood_reasoning, impact, impact_reasoning, origin_date, trend, time_horizon, segment_relevance, affected_pillars, source_ids, is_active, last_refreshed, created_at, updated_at, is_foundational, verification_verdict, verification_source, verification_evidence, financial_context, key_dates, citations, first_seen_date, last_confirmed_date, confirmation_count) VALUES (179, 'fy26_record_28m_units_â€”_broad_based_volume_uplift', 'FY26 Record 28M Units â€” Broad-Based Volume Uplift', 'E', 'Total industry sales hitting 28 million units in FY26 with 10.4% domestic growth signals sustained volume demand across all component categories. This directly expands the addressable market for Tier-1 suppliers across powertrain, chassis, body electronics, and safety systems. The record performance validates capacity expansion decisions and de-risks near-term capex commitments.', 9, 'SIAM has confirmed FY26 sales data with domestic sales rising 10.4% to 2.82 crore units. The data is sourced from official SIAM reporting and corroborated by ET Auto on 14 April 2026, making this a verified outcome rather than a forecast.', 8, 'A 10.4% volume uplift across segments translates directly to proportional component offtake increases. At â‚¹6.73 Lakh Crore industry size, each percentage point of growth represents approximately â‚¹6,730 Crore in incremental component demand. The broad-based nature across 2W, 3W, PV, and CV amplifies the effect for diversified Tier-1 suppliers.', NULL, 'escalating', 'immediate', '{"2W": "H", "3W": "H", "HCV": "M", "LCV": "M", "4W_PV": "H", "Tractor": "L"}', '["Motion", "Services", "Infotainment", "ADAS"]', '{}', true, '2026-04-15 14:28:35.234252+05:30', '2026-04-15 14:28:35.234252+05:30', '2026-04-15 14:28:35.234252+05:30', false, 'UNVERIFIED', '', '', '{"market_opportunity": "â‚¹6.73 Lakh Crore total industry; incremental ~â‚¹65,000 Cr from 10.4% growth", "industry_investment": "N/A", "subsidy_or_incentive": "GST 2.0 cuts on small cars (28% to 18%) and EV portfolios (5%) cited as demand catalyst", "government_investment": "N/A", "cost_impact_per_vehicle": "N/A"}', '{"announced": "2026-04", "effective": "2025-04", "completion": "2026-03"}', '[{"url": "https://auto.economictimes.indiatimes.com/news/industry/auto-sales-hit-7-year-high-in-fy26-as-all-segments-fire-siam/130255853", "claim": "Domestic auto sales rise 10.4% to 2.82 crore units in FY26, hitting a 7-year high", "source": "ET Auto, 14 April 2026"}, {"url": "https://auto.economictimes.indiatimes.com/news/industry/auto-sales-hit-7-year-high-in-fy26-as-all-segments-fire-siam/130255853", "claim": "Total industry sales reach 28 million units in FY26, a new benchmark", "source": "ET Auto, 14 April 2026"}]', '2026-04-15 14:28:35.234252+05:30', '2026-04-15 14:28:35.234252+05:30', 1); ON CONFLICT DO NOTHING;
INSERT INTO public.pestel_factors (id, code, name, category, selection_reasoning, likelihood, likelihood_reasoning, impact, impact_reasoning, origin_date, trend, time_horizon, segment_relevance, affected_pillars, source_ids, is_active, last_refreshed, created_at, updated_at, is_foundational, verification_verdict, verification_source, verification_evidence, financial_context, key_dates, citations, first_seen_date, last_confirmed_date, confirmation_count) VALUES (96, 'jlr_cyberattack_â€”_oem_supply_chain_cyber_vulnerabi', 'JLR cyberattack â€” OEM supply chain cyber vulnerability exposed', 'T', 'JLR''s 2025 cyberattack caused a five-week production shutdown and material financial losses for Tata Motors, directly demonstrating that OEM-level cyber incidents cascade into component supplier order disruptions. For Bosch, this validates the commercial urgency of its Safety & Security (cybersecurity) and Software & Services pillars, and creates both a risk (Bosch''s own supply exposure) and an opportunity (selling cybersecurity solutions to OEMs). The incident also accelerates OEM demand for UN R155-compliant embedded security stacks.', 9, 'The JLR attack is a confirmed historical event (2025), and the automotive sector globally saw a 380% rise in cyber incidents between 2021-2024 per Upstream Security. With India''s OEM digital infrastructure maturing rapidly, repeat incidents at other OEMs are highly probable.', 7, 'A five-week OEM shutdown directly halts component offtake â€” for a Tier-1 supplier like Bosch, even a partial JLR-scale event could disrupt â‚¹200-400 Cr in quarterly revenues. More strategically, it creates a validated sales narrative for Bosch''s cybersecurity and V2X security portfolio across all OEM accounts.', NULL, 'escalating', 'immediate', '{"2W": "L", "3W": "L", "HCV": "M", "LCV": "M", "4W_PV": "H", "Tractor": "L"}', '["Safety & Security", "Software & Services", "Vehicle Diagnostics"]', '{}', false, '2026-03-17 16:32:41.583165+05:30', '2026-03-17 16:32:41.583165+05:30', '2026-03-17 16:32:41.583165+05:30', false, 'UNVERIFIED', NULL, NULL, '{}', '{}', '[]', '2026-03-17 16:32:41.583165+05:30', '2026-03-17 16:32:41.583165+05:30', 1); ON CONFLICT DO NOTHING;
INSERT INTO public.pestel_factors (id, code, name, category, selection_reasoning, likelihood, likelihood_reasoning, impact, impact_reasoning, origin_date, trend, time_horizon, segment_relevance, affected_pillars, source_ids, is_active, last_refreshed, created_at, updated_at, is_foundational, verification_verdict, verification_source, verification_evidence, financial_context, key_dates, citations, first_seen_date, last_confirmed_date, confirmation_count) VALUES (141, 'honda_india_2w_ev_facility_2028_â€”_platform_sourcin', 'Honda India 2W EV Facility 2028 â€” Platform Sourcing Decision Window', 'T', 'Honda''s confirmation of a dedicated EV 2-wheeler facility in India by 2028 (beyond existing Rajasthan capacity expansion) creates a defined 24-month window for Bosch to secure platform-level EV powertrain and diagnostics content. Honda''s global scale and India-as-hub strategy means this facility could serve export markets, multiplying the component volume opportunity beyond domestic sales.', 9, 'Honda has publicly confirmed the 2028 EV facility (ET Auto, March 2026) as part of its India-as-global-hub strategy. Honda''s existing India manufacturing footprint (multiple plants) and the competitive pressure from Hero''s EV push make this commitment credible and strategically necessary.', 8, 'Honda''s 2W volumes (~5.2M units in 11 months FY26) make it the second-largest 2W OEM in India. If even 15-20% of production shifts to EV by 2030 (780,000â€“1,040,000 units), Bosch EV powertrain content at â‚¹8,000â€“12,000/unit implies â‚¹625â€“1,250 Cr annual revenue opportunity. Export hub status multiplies this further.', NULL, 'escalating', 'medium', '{"2W": "H", "3W": "L", "HCV": "L", "LCV": "L", "4W_PV": "L", "Tractor": "L"}', '["EV Powertrain", "Vehicle Diagnostics", "Powertrain Solutions", "Manufacturing & Industry 4.0"]', '{}', false, '2026-03-26 11:22:14.095204+05:30', '2026-03-26 11:22:14.095204+05:30', '2026-03-26 11:22:14.095204+05:30', false, 'UNVERIFIED', NULL, NULL, '{}', '{}', '[]', '2026-03-26 11:22:14.095204+05:30', '2026-03-26 11:22:14.095204+05:30', 1); ON CONFLICT DO NOTHING;
INSERT INTO public.pestel_factors (id, code, name, category, selection_reasoning, likelihood, likelihood_reasoning, impact, impact_reasoning, origin_date, trend, time_horizon, segment_relevance, affected_pillars, source_ids, is_active, last_refreshed, created_at, updated_at, is_foundational, verification_verdict, verification_source, verification_evidence, financial_context, key_dates, citations, first_seen_date, last_confirmed_date, confirmation_count) VALUES (180, 'delhi_ice_2w_ban_2028_â€”_regulatory_ev_mandate_esca', 'Delhi ICE 2W Ban 2028 â€” Regulatory EV Mandate Escalation', 'P', 'Delhi''s proposed ban on ICE two-wheelers from 2028 represents the first major city-level ICE prohibition in India, setting a precedent that could cascade to other metros. This directly threatens ICE powertrain component volumes for 2W while accelerating demand for EV powertrain, BMS, and charging infrastructure. SIAM''s public opposition signals industry-government tension that creates policy uncertainty for supplier investment planning.', 7, 'The proposal is at policy discussion stage with SIAM actively pushing back, as reported by ET Auto on 14 April 2026. Delhi has a history of ambitious environmental mandates (CNG transition, odd-even rules) but implementation timelines frequently slip. The 2028 deadline gives 2 years, making partial implementation more likely than full enforcement.', 8, 'Delhi represents approximately 8-10% of India''s 2W retail market. An ICE ban would eliminate ICE powertrain demand in the capital while creating a concentrated EV component demand node. For Tier-1 suppliers with ICE-heavy 2W portfolios, this accelerates the need for EV powertrain transition investment. The precedent effect on Mumbai, Bengaluru, and Pune amplifies strategic significance beyond Delhi''s direct volume.', NULL, 'escalating', 'short', '{"2W": "H", "3W": "M", "HCV": "L", "LCV": "L", "4W_PV": "L", "Tractor": "L"}', '["Motion", "Energy", "Infotainment"]', '{}', true, '2026-04-15 14:28:35.234252+05:30', '2026-04-15 14:28:35.234252+05:30', '2026-04-15 14:28:35.234252+05:30', false, 'UNVERIFIED', '', '', '{"market_opportunity": "Estimate based on: Delhi ~8% of 1.96Cr 2W market = ~1.57L units annually; EV powertrain content ~â‚¹25,000-35,000 per unit = â‚¹3,900-5,500 Cr annual opportunity in Delhi alone", "industry_investment": "N/A", "subsidy_or_incentive": "Delhi EV policy expected to include purchase incentives and charging infrastructure subsidies for 2W EVs", "government_investment": "N/A", "cost_impact_per_vehicle": "ICE-to-EV transition adds â‚¹20,000-40,000 per 2W in powertrain BOM cost"}', '{"announced": "2026-04", "effective": "2028-01", "completion": "2028-12"}', '[{"url": "https://auto.economictimes.indiatimes.com/news/industry/delhi-ev-policy-industry-urges-focus-on-enablers-not-mandates-for-ev-adoption/130259948", "claim": "Delhi is proposing to ban ICE two-wheelers in the national capital from 2028", "source": "ET Auto, 14 April 2026"}, {"url": "https://auto.economictimes.indiatimes.com/news/industry/delhi-ev-policy-industry-urges-focus-on-enablers-not-mandates-for-ev-adoption/130259948", "claim": "SIAM says government roadmaps must be enablers rather than acting as mandates for EV adoption", "source": "ET Auto, 14 April 2026"}]', '2026-04-15 14:28:35.234252+05:30', '2026-04-15 14:28:35.234252+05:30', 1); ON CONFLICT DO NOTHING;
INSERT INTO public.pestel_factors (id, code, name, category, selection_reasoning, likelihood, likelihood_reasoning, impact, impact_reasoning, origin_date, trend, time_horizon, segment_relevance, affected_pillars, source_ids, is_active, last_refreshed, created_at, updated_at, is_foundational, verification_verdict, verification_source, verification_evidence, financial_context, key_dates, citations, first_seen_date, last_confirmed_date, confirmation_count) VALUES (119, 'euler_motors_â‚¹437.5_cr_raise_â€”_e_lcv_segment_accel', 'Euler Motors â‚¹437.5 Cr Raise â€” e-LCV Segment Acceleration', 'E', 'Euler Motors securing â‚¹437.5 Cr with Hero MotoCorp backing, targeting 100% revenue growth over FY25''s â‚¹191 Cr base, signals rapid scaling of the electric LCV segment. This is a direct demand signal for Bosch''s EV powertrain (motors, inverters, BMS), thermal management, and vehicle diagnostics pillars in the LCV segment. Hero''s strategic backing adds OEM ecosystem credibility and distribution reach.', 8, 'Funding is confirmed and closed. Hero MotoCorp''s backing provides both capital credibility and strategic distribution support. The e-CV segment has strong fleet operator demand driven by last-mile logistics economics.', 6, 'Euler''s current scale (â‚¹191 Cr FY25 revenue) is modest relative to total LCV market, but 100% growth trajectory and institutional backing signal it could reach meaningful volume (est. 15,000-20,000 units annually by FY27). For Bosch, this represents a Tier-1 supply opportunity in a nascent but fast-growing segment. Impact constrained by Euler''s current market share.', NULL, 'escalating', 'short', '{"2W": "L", "3W": "L", "HCV": "L", "LCV": "H", "4W_PV": "L", "Tractor": "L"}', '["EV Powertrain", "Thermal Management", "Vehicle Diagnostics", "Energy & Charging"]', '{}', false, '2026-03-26 11:21:49.325434+05:30', '2026-03-26 11:21:49.325434+05:30', '2026-03-26 11:26:33.982723+05:30', false, 'UNVERIFIED', NULL, NULL, '{}', '{}', '[]', '2026-03-26 11:21:49.325434+05:30', '2026-03-26 11:21:49.325434+05:30', 1); ON CONFLICT DO NOTHING;
INSERT INTO public.pestel_factors (id, code, name, category, selection_reasoning, likelihood, likelihood_reasoning, impact, impact_reasoning, origin_date, trend, time_horizon, segment_relevance, affected_pillars, source_ids, is_active, last_refreshed, created_at, updated_at, is_foundational, verification_verdict, verification_source, verification_evidence, financial_context, key_dates, citations, first_seen_date, last_confirmed_date, confirmation_count) VALUES (120, 'direct_to_garage_aftermarket_platforms_â€”_bosch_dis', 'Direct-to-Garage Aftermarket Platforms â€” Bosch Distribution Disruption', 'T', 'Autoverse Mobility''s data-led direct-to-garage model targeting 140,000 garages threatens Bosch''s traditional aftermarket distribution hierarchy by disintermediating established channel partners. The $11B aftermarket (â‚¹1.05L Cr) is a high-margin segment for Bosch. Digital platforms aggregating garage demand create pricing transparency pressure and enable counterfeit/grey market parts to compete more effectively at scale.', 8, 'Autoverse''s model is live and scaling. The 140,000 garage target is ambitious but directionally credible given India''s fragmented aftermarket. Multiple well-funded players (Carz on Road, mCarbon, GoMechanic rebuild) are pursuing similar models, confirming structural disruption is underway.', 7, 'Bosch''s aftermarket pillar contributes an estimated 15-20% of India revenues at above-average margins. Direct-to-garage platforms compress distributor margins and accelerate price discovery, potentially reducing Bosch''s channel pricing power by 5-10%. Conversely, Bosch could partner with such platforms to expand genuine parts reach to previously inaccessible garages.', NULL, 'escalating', 'short', '{"2W": "H", "3W": "M", "HCV": "M", "LCV": "M", "4W_PV": "H", "Tractor": "L"}', '["Aftermarket & Retrofit", "Vehicle Diagnostics", "Software & Services"]', '{}', false, '2026-03-26 11:21:49.325434+05:30', '2026-03-26 11:21:49.325434+05:30', '2026-03-26 11:21:49.325434+05:30', false, 'UNVERIFIED', NULL, NULL, '{}', '{}', '[]', '2026-03-26 11:21:49.325434+05:30', '2026-03-26 11:21:49.325434+05:30', 1); ON CONFLICT DO NOTHING;
INSERT INTO public.pestel_factors (id, code, name, category, selection_reasoning, likelihood, likelihood_reasoning, impact, impact_reasoning, origin_date, trend, time_horizon, segment_relevance, affected_pillars, source_ids, is_active, last_refreshed, created_at, updated_at, is_foundational, verification_verdict, verification_source, verification_evidence, financial_context, key_dates, citations, first_seen_date, last_confirmed_date, confirmation_count) VALUES (144, 'honda_india_2w_ev_facility_confirmed_for_2028', 'Honda India 2W EV Facility Confirmed for 2028', 'T', 'Honda''s confirmation of a dedicated EV two-wheeler manufacturing facility in India by 2028, backed by capacity expansion at existing plants, represents a major new EV platform opportunity for Bosch''s EV Powertrain, BMS, and Vehicle Diagnostics pillars in the world''s largest 2W market. This is distinct from Honda''s existing ICE expansion and signals a structural shift in Honda''s India technology roadmap.', 9, 'Honda has publicly reaffirmed India as a global hub with specific facility timelines (ET Auto, March 2026). The â‚¹1,200 Cr Honda ''0 Alpha'' investment already in existing factors confirms financial commitment. A 2028 facility announcement is a board-level decision, not a speculative roadmap.', 7, 'Honda''s 2W EV platform will require motors, inverters, BMS, and OBD-II-compliant diagnostics â€” all Bosch competencies. With Honda at 5.2M+ units annually, even 10% EV penetration by 2029 represents ~520K EV units requiring new component content. This is a greenfield sourcing opportunity.', NULL, 'escalating', 'medium', '{"2W": "H", "3W": "L", "HCV": "L", "LCV": "L", "4W_PV": "L", "Tractor": "L"}', '["EV Powertrain", "Vehicle Diagnostics", "Thermal Management", "Battery Management"]', '{}', false, '2026-03-26 11:21:49.304861+05:30', '2026-03-26 11:21:49.304861+05:30', '2026-03-26 11:21:49.304861+05:30', false, 'UNVERIFIED', NULL, NULL, '{}', '{}', '[]', '2026-03-26 11:21:49.304861+05:30', '2026-03-26 11:21:49.304861+05:30', 1); ON CONFLICT DO NOTHING;
INSERT INTO public.pestel_factors (id, code, name, category, selection_reasoning, likelihood, likelihood_reasoning, impact, impact_reasoning, origin_date, trend, time_horizon, segment_relevance, affected_pillars, source_ids, is_active, last_refreshed, created_at, updated_at, is_foundational, verification_verdict, verification_source, verification_evidence, financial_context, key_dates, citations, first_seen_date, last_confirmed_date, confirmation_count) VALUES (101, 'maruti_suv_expansion_â€”_7_models_over_5_6_years', 'Maruti SUV Expansion â€” 7 Models Over 5-6 Years', 'E', 'Maruti Suzuki''s SUV market share reaching 19.6% in FY26 and its plan to launch 7 new SUV models over 5-6 years is a major demand signal for Bosch''s higher-content technology pillars. SUVs carry significantly more ADAS, chassis electronics, and thermal management content than entry hatchbacks. As India''s largest OEM by volume, Maruti''s SUV pivot directly shapes Bosch''s India order book trajectory.', 9, 'Maruti''s SUV share gain to 19.6% is confirmed data (ET Auto, March 2026). The 7-model pipeline is a stated corporate commitment backed by Suzuki''s global product roadmap and Maruti''s Manesar/Gujarat capacity expansion. SUVs now constitute over 50% of India PV sales, making this a structural rather than cyclical shift.', 7, 'SUVs carry 40-60% higher electronics and safety content per vehicle vs. entry hatchbacks. If Maruti''s SUV volumes reach 800K-1M units annually by FY30, Bosch''s content opportunity expands by â‚¹1,200-2,000 Cr vs. equivalent hatchback volumes. This also drives ADAS and Bharat NCAP compliance content demand from Bosch''s largest India customer.', NULL, 'escalating', 'short', '{"2W": "L", "3W": "L", "HCV": "L", "LCV": "L", "4W_PV": "H", "Tractor": "L"}', '["Vehicle Motion", "Chassis Systems", "Powertrain Solutions", "Body Electronics", "Thermal Management", "Safety & Security"]', '{}', false, '2026-03-17 16:31:52.563836+05:30', '2026-03-17 16:31:52.563836+05:30', '2026-03-17 16:31:52.563836+05:30', false, 'UNVERIFIED', NULL, NULL, '{}', '{}', '[]', '2026-03-17 16:31:52.563836+05:30', '2026-03-17 16:31:52.563836+05:30', 1); ON CONFLICT DO NOTHING;
INSERT INTO public.pestel_factors (id, code, name, category, selection_reasoning, likelihood, likelihood_reasoning, impact, impact_reasoning, origin_date, trend, time_horizon, segment_relevance, affected_pillars, source_ids, is_active, last_refreshed, created_at, updated_at, is_foundational, verification_verdict, verification_source, verification_evidence, financial_context, key_dates, citations, first_seen_date, last_confirmed_date, confirmation_count) VALUES (182, 'up_labour_unrest_&_minimum_wage_hike_â€”_manufacturi', 'UP Labour Unrest & Minimum Wage Hike â€” Manufacturing Cost Pressure', 'S', 'Violent worker protests in Noida''s industrial belt â€” a major auto component manufacturing hub â€” followed by a state-mandated minimum wage hike represent a direct operating cost increase for Tier-1 suppliers concentrated in the NCR-UP corridor. Beyond the immediate wage impact, the unrest signals latent labour relations risk in a region housing critical component manufacturing clusters for multiple OEMs. This affects Manufacturing & Industry 4.0 investment calculus and supplier margin structures.', 9, 'The UP government has already enacted the minimum wage hike as a direct response to the Noida protests, as confirmed by ET Auto on 14 April 2026. This is a completed regulatory action, not a forecast. The wage increase is effective immediately, making the cost impact certain for suppliers operating in UP.', 6, 'Noida-Greater Noida hosts a significant cluster of auto component suppliers serving Maruti, Honda, Hero, and other OEMs. A minimum wage hike of typically 10-20% for shop-floor workers increases direct labour costs, which represent 8-15% of total manufacturing cost for most component categories. The supply chain stress signal from SIAM President compounds the impact by flagging broader operational vulnerability in H1 FY27.', NULL, 'escalating', 'immediate', '{"2W": "H", "3W": "L", "HCV": "M", "LCV": "M", "4W_PV": "H", "Tractor": "L"}', '["Compute", "Motion", "Infotainment"]', '{}', true, '2026-04-15 14:28:35.234252+05:30', '2026-04-15 14:28:35.234252+05:30', '2026-04-15 14:28:35.234252+05:30', false, 'UNVERIFIED', '', '', '{"market_opportunity": "N/A", "industry_investment": "N/A", "subsidy_or_incentive": "N/A", "government_investment": "N/A", "cost_impact_per_vehicle": "Estimate based on: 10-20% wage hike on 8-15% labour cost base = 0.8-3% total manufacturing cost increase; translates to â‚¹800-4,500 per vehicle depending on segment"}', '{"announced": "2026-04-14", "effective": "2026-04", "completion": ""}', '[{"url": "https://auto.economictimes.indiatimes.com/news/industry/uttar-pradesh-govt-hikes-minimum-wages-across-categories-after-noida-worker-protests-turn-violent/130250735", "claim": "Uttar Pradesh government hikes minimum wages across categories after Noida factory worker protests turned violent", "source": "ET Auto, 14 April 2026"}, {"url": "https://auto.economictimes.indiatimes.com/news/industry/april-to-be-litmus-test-for-indian-auto-industry-as-supply-chain-stress-rises-shailesh-chandra/130259050", "claim": "SIAM President flags labour unrest in UP as a factor that could keep the industry on tenterhooks in H1 FY27", "source": "ET Auto, 14 April 2026"}]', '2026-04-15 14:28:35.234252+05:30', '2026-04-15 14:28:35.234252+05:30', 1); ON CONFLICT DO NOTHING;
INSERT INTO public.pestel_factors (id, code, name, category, selection_reasoning, likelihood, likelihood_reasoning, impact, impact_reasoning, origin_date, trend, time_horizon, segment_relevance, affected_pillars, source_ids, is_active, last_refreshed, created_at, updated_at, is_foundational, verification_verdict, verification_source, verification_evidence, financial_context, key_dates, citations, first_seen_date, last_confirmed_date, confirmation_count) VALUES (183, 'lpg_supply_monitoring_â€”_process_energy_vulnerabili', 'LPG Supply Monitoring â€” Process Energy Vulnerability for Component Makers', 'En', 'The Ministry of Heavy Industries actively monitoring LPG supply for the auto component sector reveals a previously underappreciated energy input risk. LPG is a critical process fuel for heat treatment, forging, casting, and surface finishing operations across the component supply chain. Government engagement with ACMA and the petroleum ministry signals that supply tightness is a live concern, not a hypothetical. This intersects with the West Asia conflict risk already tracked and adds a domestic supply chain dimension.', 6, 'No major disruption has been reported as of 14 April 2026, per ET Auto, but the fact that the Ministry of Heavy Industries is actively monitoring the situation indicates a credible supply risk. West Asia tensions (an existing tracked factor) directly affect LPG import volumes, as India imports approximately 60% of its LPG requirements. The monitoring posture suggests the risk is elevated above normal baseline.', 7, 'LPG supply disruption to auto component manufacturers would halt heat treatment, forging, and casting operations â€” foundational processes for engine components, chassis parts, and structural elements. Even a 2-week disruption in a major cluster (Pune, Chennai, NCR) could create a cascading OEM production stoppage. The government''s proactive monitoring suggests awareness of this systemic vulnerability, which itself is a signal of impact severity.', NULL, 'escalating', 'immediate', '{"2W": "H", "3W": "M", "HCV": "H", "LCV": "M", "4W_PV": "H", "Tractor": "L"}', '["Motion", "Services", "Compute"]', '{}', true, '2026-04-15 14:28:35.234252+05:30', '2026-04-15 14:28:35.234252+05:30', '2026-04-15 14:28:35.234252+05:30', false, 'UNVERIFIED', '', '', '{"market_opportunity": "N/A", "industry_investment": "N/A", "subsidy_or_incentive": "Government coordinating with petroleum ministry to prevent supply disruptions â€” no formal subsidy", "government_investment": "N/A", "cost_impact_per_vehicle": "Estimate based on: LPG price spike of 20-30% would increase energy cost by â‚¹500-1,500 per vehicle for forging/casting-intensive components"}', '{"announced": "2026-04-14", "effective": "2026-04", "completion": ""}', '[{"url": "https://auto.economictimes.indiatimes.com/news/auto-components/centre-monitoring-lpg-supply-for-auto-component-sector-no-major-disruption-reported-so-far/130249680", "claim": "Ministry of Heavy Industries said auto component manufacturers have not reported any major LPG supply shortages so far, but the government remains in touch with ACMA and the petroleum ministry to avoid disruptions", "source": "ET Auto, 14 April 2026"}]', '2026-04-15 14:28:35.234252+05:30', '2026-04-15 14:28:35.234252+05:30', 1); ON CONFLICT DO NOTHING;
INSERT INTO public.pestel_factors (id, code, name, category, selection_reasoning, likelihood, likelihood_reasoning, impact, impact_reasoning, origin_date, trend, time_horizon, segment_relevance, affected_pillars, source_ids, is_active, last_refreshed, created_at, updated_at, is_foundational, verification_verdict, verification_source, verification_evidence, financial_context, key_dates, citations, first_seen_date, last_confirmed_date, confirmation_count) VALUES (19, 'gig_economy_3w_ev_demand', 'Gig economy driving 3W EV fleet electrification', 'S', 'Food delivery and e-commerce gig economy (Swiggy, Zomato, Amazon) is the primary demand driver for 3W EV fleet purchases. 3W EV at 55% penetration (CY2025) â€” highest EV share of any segment. Bosch''s 3W EV Powertrain and BMS market is already at inflection.', 9, 'Score 10: 55% 3W EV share confirmed in Vahan CY2025 data. Structural economic incentive is clear â€” EV TCO is 30-40% lower than CNG for fleet operators.', 4, 'Score 7: Strong for EV Powertrain and BMS in 3W. However, 3W is a lower-value segment. Total revenue impact is meaningful but smaller than 4W PV shifts.', NULL, 'escalating', 'short', '{"2W": "M", "3W": "H", "HCV": "L", "LCV": "M", "4W_PV": "L", "Tractor": "L"}', '["Energy", "Services", "Solutions"]', '{3}', true, '2026-03-16 22:45:46.381831+05:30', '2026-03-16 22:45:46.381831+05:30', '2026-03-16 22:48:13.097302+05:30', true, 'UNVERIFIED', NULL, NULL, '{}', '{}', '[]', '2026-03-16 22:45:46.381831+05:30', '2026-03-16 22:45:46.381831+05:30', 1); ON CONFLICT DO NOTHING;
INSERT INTO public.pestel_factors (id, code, name, category, selection_reasoning, likelihood, likelihood_reasoning, impact, impact_reasoning, origin_date, trend, time_horizon, segment_relevance, affected_pillars, source_ids, is_active, last_refreshed, created_at, updated_at, is_foundational, verification_verdict, verification_source, verification_evidence, financial_context, key_dates, citations, first_seen_date, last_confirmed_date, confirmation_count) VALUES (184, 'nissan_honda_india_partnership_exploration_â€”_oem_c', 'Nissan-Honda India Partnership Exploration â€” OEM Consolidation Signal', 'P', 'Nissan CEO Ivan Espinosa''s public openness to a Honda partnership in India, combined with Nissan''s strategic repositioning of India into a secondary ''extend reach'' bucket, signals potential OEM platform consolidation in the Indian PV market. For Tier-1 suppliers, OEM mergers or platform-sharing arrangements reduce the number of independent sourcing decisions, concentrate purchasing power, and can trigger platform rationalisation that eliminates existing supply relationships. This is strategically significant for suppliers currently serving either brand.', 5, 'Nissan CEO explicitly stated there is ''nothing specific working in this area as yet'' as of 15 April 2026, making this an exploratory signal rather than an imminent event. However, the Honda-Nissan global merger discussions (ongoing in 2025-26) provide a credible structural basis for India-specific collaboration. The probability of a formal India partnership within 24 months is moderate.', 6, 'A Honda-Nissan platform-sharing arrangement in India would affect suppliers to both brands across powertrain, chassis, and electronics pillars. Honda India 2W (largest 2W OEM) and Honda Cars India combined with Nissan''s PV operations represent a significant sourcing node. Platform consolidation typically results in 15-25% supplier base rationalisation, creating both risk (de-selection) and opportunity (higher volume per retained supplier).', NULL, 'new', 'medium', '{"2W": "M", "3W": "L", "HCV": "L", "LCV": "L", "4W_PV": "H", "Tractor": "L"}', '["Motion", "Infotainment", "ADAS"]', '{}', true, '2026-04-15 14:28:35.234252+05:30', '2026-04-15 14:28:35.234252+05:30', '2026-04-15 14:28:35.234252+05:30', false, 'UNVERIFIED', '', '', '{"market_opportunity": "Estimate based on: Honda + Nissan combined India PV volume ~3-4L units annually; component content ~â‚¹1.5-2.5L per vehicle = â‚¹4,500-10,000 Cr combined sourcing base at risk of rationalisation", "industry_investment": "N/A", "subsidy_or_incentive": "N/A", "government_investment": "N/A", "cost_impact_per_vehicle": "N/A"}', '{"announced": "2026-04-15", "effective": "", "completion": ""}', '[{"url": "https://auto.economictimes.indiatimes.com/news/passenger-vehicle/nissan-open-to-honda-tie-up-for-stronger-india-play-bets-on-ai-led-mobility-intelligence-for-global-growth-ceo-ivan-espinosa/130272185", "claim": "Nissan CEO Ivan Espinosa said the company is open to partnering Honda in India, if the need arises, though adding the two companies do not have anything specific working in this area as yet", "source": "ET Auto, 15 April 2026"}, {"url": "https://auto.economictimes.indiatimes.com/news/passenger-vehicle/nissan-zeroes-in-on-china-japan-and-us-as-lead-markets/130254428", "claim": "Nissan has placed India in its ''extend reach and support expansion'' bucket, alongside Europe, Africa, Oceania, Latin America and ASEAN", "source": "ET Auto, 14 April 2026"}]', '2026-04-15 14:28:35.234252+05:30', '2026-04-15 14:28:35.234252+05:30', 1); ON CONFLICT DO NOTHING;
INSERT INTO public.pestel_factors (id, code, name, category, selection_reasoning, likelihood, likelihood_reasoning, impact, impact_reasoning, origin_date, trend, time_horizon, segment_relevance, affected_pillars, source_ids, is_active, last_refreshed, created_at, updated_at, is_foundational, verification_verdict, verification_source, verification_evidence, financial_context, key_dates, citations, first_seen_date, last_confirmed_date, confirmation_count) VALUES (185, 'nissan_india_strategic_downgrade_â€”_oem_volume_risk', 'Nissan India Strategic Downgrade â€” OEM Volume Risk for Incumbent Suppliers', 'P', 'Nissan''s explicit classification of India as a secondary ''extend reach'' market â€” below its core China, Japan, and US priorities â€” signals a structural reduction in Nissan''s India volume ambitions. For Tier-1 suppliers with significant Nissan exposure (Renault-Nissan Alliance sourcing from Chennai cluster), this represents a medium-term volume de-risk event. The strategic downgrade reduces the probability of new Nissan platform launches in India, shrinking the forward order book for incumbent suppliers.', 8, 'Nissan''s market prioritisation is a confirmed strategic position stated by the CEO on 14 April 2026. Nissan''s India sales have been declining for several years, and the strategic framing confirms this is a deliberate choice rather than a temporary setback. The likelihood of Nissan maintaining or growing its India component sourcing is therefore low.', 5, 'Nissan''s India PV volumes are relatively modest (estimated 30,000-50,000 units annually), limiting the absolute component demand impact. However, suppliers with high Nissan concentration in their customer mix face disproportionate revenue risk. The Chennai manufacturing cluster (shared with Renault) is the primary exposure point. The impact is contained relative to the broader market but material for specific supplier relationships.', NULL, 'de-escalating', 'medium', '{"2W": "L", "3W": "L", "HCV": "L", "LCV": "L", "4W_PV": "H", "Tractor": "L"}', '["Motion", "Infotainment", "Compute"]', '{}', true, '2026-04-15 14:28:35.234252+05:30', '2026-04-15 14:28:35.234252+05:30', '2026-04-15 14:28:35.234252+05:30', false, 'UNVERIFIED', '', '', '{"market_opportunity": "N/A", "industry_investment": "N/A", "subsidy_or_incentive": "N/A", "government_investment": "N/A", "cost_impact_per_vehicle": "Estimate based on: Nissan India ~30,000-50,000 units Ã— â‚¹1.5-2L component content = â‚¹450-1,000 Cr annual sourcing at risk if volumes decline further"}', '{"announced": "2026-04-14", "effective": "2026-04", "completion": ""}', '[{"url": "https://auto.economictimes.indiatimes.com/news/passenger-vehicle/nissan-zeroes-in-on-china-japan-and-us-as-lead-markets/130254428", "claim": "Nissan has zeroed in on China, Japan and US as lead markets, placing India in its ''extend reach and support expansion'' bucket alongside Europe, Africa, Oceania, Latin America and ASEAN", "source": "ET Auto, 14 April 2026"}]', '2026-04-15 14:28:35.234252+05:30', '2026-04-15 14:28:35.234252+05:30', 1); ON CONFLICT DO NOTHING;
INSERT INTO public.pestel_factors (id, code, name, category, selection_reasoning, likelihood, likelihood_reasoning, impact, impact_reasoning, origin_date, trend, time_horizon, segment_relevance, affected_pillars, source_ids, is_active, last_refreshed, created_at, updated_at, is_foundational, verification_verdict, verification_source, verification_evidence, financial_context, key_dates, citations, first_seen_date, last_confirmed_date, confirmation_count) VALUES (25, 'sdv_software_defined_vehicle', 'Software-defined vehicle architecture â€” OTA updates standard by 2027', 'T', 'OTA update capability is projected to be in 40% of new 4W by 2027 (McKinsey). SDV architecture requires Bosch to shift from hardware-centric to software + services model â€” both a threat and opportunity for Software & Services pillar.', 7, 'Score 8: OEM platforms (Tata''s ADAS.ai, Mahindra MAIA, Maruti Suzuki Nexa) already SDV-capable. 40% new model penetration by 2027 is achievable based on announced models.', 6, 'Score 8: Software content per vehicle rising from â‚¹29,000 to â‚¹1,00,000 by 2030. If Bosch captures 15% share, that''s â‚¹15,000 revenue uplift per vehicle vs current.', NULL, 'escalating', 'short', '{"2W": "L", "3W": "L", "HCV": "L", "LCV": "L", "4W_PV": "H", "Tractor": "L"}', '["ADAS", "Cloud", "ECUs", "Infotainment", "Motion", "OS", "Semiconductors", "Services"]', '{20}', true, '2026-03-16 22:45:46.381831+05:30', '2026-03-16 22:45:46.381831+05:30', '2026-03-16 22:48:13.097302+05:30', true, 'UNVERIFIED', NULL, NULL, '{}', '{}', '[]', '2026-03-16 22:45:46.381831+05:30', '2026-03-16 22:45:46.381831+05:30', 1); ON CONFLICT DO NOTHING;
INSERT INTO public.pestel_factors (id, code, name, category, selection_reasoning, likelihood, likelihood_reasoning, impact, impact_reasoning, origin_date, trend, time_horizon, segment_relevance, affected_pillars, source_ids, is_active, last_refreshed, created_at, updated_at, is_foundational, verification_verdict, verification_source, verification_evidence, financial_context, key_dates, citations, first_seen_date, last_confirmed_date, confirmation_count) VALUES (31, 'india_carbon_credit_market', 'India Carbon Credit Trading Scheme (CCTS) â€” BEE notification 2025', 'En', 'Bureau of Energy Efficiency notified India''s Carbon Credit Trading Scheme in 2025. Auto OEMs and component manufacturers with high emissions intensity may face carbon credit purchase obligations, adding cost pressure on ICE-heavy manufacturers.', 7, 'Score 7: CCTS notified but implementation framework still being finalised. Trading is not yet live. Score 7 because formal launch in FY2026 is likely.', 5, 'Score 4: Early stage with uncertain pricing. Direct cost impact on Bosch India likely modest (â‚¹50-150 Cr/year). More important as a trajectory signal than current cost driver.', NULL, 'new', 'medium', '{"2W": "L", "3W": "L", "HCV": "H", "LCV": "M", "4W_PV": "M", "Tractor": "M"}', '["Compute", "Motion"]', '{10}', true, '2026-03-16 22:45:46.381831+05:30', '2026-03-16 22:45:46.381831+05:30', '2026-03-16 22:48:13.097302+05:30', false, 'UNVERIFIED', NULL, NULL, '{}', '{}', '[]', '2026-03-16 22:45:46.381831+05:30', '2026-03-16 22:45:46.381831+05:30', 1); ON CONFLICT DO NOTHING;
INSERT INTO public.pestel_factors (id, code, name, category, selection_reasoning, likelihood, likelihood_reasoning, impact, impact_reasoning, origin_date, trend, time_horizon, segment_relevance, affected_pillars, source_ids, is_active, last_refreshed, created_at, updated_at, is_foundational, verification_verdict, verification_source, verification_evidence, financial_context, key_dates, citations, first_seen_date, last_confirmed_date, confirmation_count) VALUES (186, 'india_cost_competitiveness_10_25%_vs_europe/latam_', 'India Cost Competitiveness 10-25% vs Europe/LatAm â€” Export Positioning Advantage', 'E', 'IBEF''s quantification of India''s manufacturing cost advantage at 10-25% below European and Latin American operations provides a durable structural basis for India''s export growth thesis. For Tier-1 suppliers, this cost differential is the primary competitive moat in global sourcing competitions, particularly as OEMs diversify supply chains away from China. This factor directly informs export strategy, FTA utilisation, and global OEM relationship development.', 8, 'The 10-25% cost advantage is a well-documented and structurally supported figure based on labour cost differentials, energy costs, and manufacturing overhead comparisons. India''s labour cost advantage over Europe is structural and unlikely to erode significantly within the 5-year planning horizon, though UP wage hikes (a separate tracked factor) represent a marginal pressure on this differential.', 7, 'The cost advantage directly enables India-based Tier-1 suppliers to win global sourcing mandates that would otherwise go to European, Mexican, or Chinese suppliers. In the context of the India-EU FTA (existing factor) and US tariff reduction to 18% (existing factor), this cost advantage becomes actionable through improved market access. The $70-100B export projection is fundamentally predicated on this cost differential being sustained.', NULL, 'stable', 'medium', '{"2W": "H", "3W": "L", "HCV": "M", "LCV": "M", "4W_PV": "H", "Tractor": "L"}', '["Compute", "Motion", "Energy"]', '{}', true, '2026-04-15 14:28:35.234252+05:30', '2026-04-15 14:28:35.234252+05:30', '2026-04-15 14:28:35.234252+05:30', false, 'UNVERIFIED', '', '', '{"market_opportunity": "Estimate based on: 10-25% cost advantage on $200B industry = $20-50B structural cost saving vs competing geographies, enabling export market capture", "industry_investment": "N/A", "subsidy_or_incentive": "PLI scheme further enhances cost competitiveness for advanced technology components", "government_investment": "N/A", "cost_impact_per_vehicle": "India manufacturing costs 10-25% lower than European and Latin American equivalents per IBEF/McKinsey"}', '{"announced": "2026-04", "effective": "2025-01", "completion": ""}', '[{"url": "", "claim": "A cost-effective manufacturing base in India keeps costs lower by 10-25% relative to operations in Europe and Latin America", "source": "IBEF Auto Components Industry Report, accessed April 2026"}]', '2026-04-15 14:28:35.234252+05:30', '2026-04-15 14:28:35.234252+05:30', 1); ON CONFLICT DO NOTHING;
INSERT INTO public.pestel_factors (id, code, name, category, selection_reasoning, likelihood, likelihood_reasoning, impact, impact_reasoning, origin_date, trend, time_horizon, segment_relevance, affected_pillars, source_ids, is_active, last_refreshed, created_at, updated_at, is_foundational, verification_verdict, verification_source, verification_evidence, financial_context, key_dates, citations, first_seen_date, last_confirmed_date, confirmation_count) VALUES (187, 'nissan_ai_led_mobility_intelligence_â€”_software_def', 'Nissan AI-Led Mobility Intelligence â€” Software-Defined Vehicle Signal', 'T', 'Nissan CEO''s explicit bet on ''AI-led mobility intelligence for global growth'' signals that even secondary-market OEMs are embedding AI/software capability requirements into their global supply chain expectations. For India-based Tier-1 suppliers serving Nissan or competing for global OEM mandates, this reinforces the urgency of software-defined vehicle (SDV) capability development. It directly affects the Software & Services, Infotainment & Connectivity, and Vehicle Motion pillars.', 7, 'Nissan''s AI mobility strategy is a confirmed CEO-level strategic priority as of April 2026. The global SDV trend is well-established across all major OEMs (Toyota, Volkswagen, Hyundai all have active SDV programs). The likelihood of AI/software becoming a standard OEM procurement requirement within 3-5 years is high, regardless of Nissan''s specific India volume trajectory.', 6, 'For India Tier-1 suppliers, the AI/SDV requirement raises the technology bar for global supply mandates. Suppliers lacking software development capability risk exclusion from next-generation platform sourcing. The impact is medium-term and affects primarily the premium and export-oriented supplier segment. Domestic-focused suppliers serving 2W and entry-level 4W are less immediately affected.', NULL, 'escalating', 'medium', '{"2W": "L", "3W": "L", "HCV": "M", "LCV": "L", "4W_PV": "H", "Tractor": "L"}', '["Motion", "OS", "Infotainment"]', '{}', true, '2026-04-15 14:28:35.234252+05:30', '2026-04-15 14:28:35.234252+05:30', '2026-04-15 14:28:35.234252+05:30', false, 'UNVERIFIED', '', '', '{"market_opportunity": "India ADAS market $1.15B (2025) â†’ $3.12B by 2031 at 18.12% CAGR per Mordor Intelligence; software-defined vehicle services represent an additional layer", "industry_investment": "N/A", "subsidy_or_incentive": "N/A", "government_investment": "N/A", "cost_impact_per_vehicle": "Estimate based on: AI/software content addition of â‚¹15,000-50,000 per 4W PV for advanced connectivity and ADAS features"}', '{"announced": "2026-04-15", "effective": "", "completion": ""}', '[{"url": "https://auto.economictimes.indiatimes.com/news/passenger-vehicle/nissan-open-to-honda-tie-up-for-stronger-india-play-bets-on-ai-led-mobility-intelligence-for-global-growth-ceo-ivan-espinosa/130272185", "claim": "Nissan CEO Ivan Espinosa bets on AI-led mobility intelligence for global growth", "source": "ET Auto, 15 April 2026"}]', '2026-04-15 14:28:35.234252+05:30', '2026-04-15 14:28:35.234252+05:30', 1); ON CONFLICT DO NOTHING;
INSERT INTO public.pestel_factors (id, code, name, category, selection_reasoning, likelihood, likelihood_reasoning, impact, impact_reasoning, origin_date, trend, time_horizon, segment_relevance, affected_pillars, source_ids, is_active, last_refreshed, created_at, updated_at, is_foundational, verification_verdict, verification_source, verification_evidence, financial_context, key_dates, citations, first_seen_date, last_confirmed_date, confirmation_count) VALUES (188, 'growing_working_population_&_middle_class_â€”_struct', 'Growing Working Population & Middle Class â€” Structural Demand Foundation', 'S', 'IBEF''s identification of India''s growing working population and expanding middle class as key demand drivers provides the demographic foundation underpinning all vehicle segment growth projections. For Tier-1 suppliers, this structural demand driver de-risks long-cycle capacity investment decisions and supports premium content adoption across segments. The demographic tailwind is particularly relevant for 2W (first vehicle ownership), entry-level 4W PV, and 3W (last-mile mobility) segments.', 9, 'India''s demographic trajectory is well-documented and structurally certain over the 5-10 year planning horizon. The working-age population (15-64 years) is projected to grow through 2040, and middle-class expansion (households earning â‚¹5-30 Lakh annually) is a well-established trend supported by GDP growth of 6.4% in FY25. This is a low-uncertainty, high-confidence structural factor.', 7, 'The demographic tailwind is the primary driver of India''s vehicle market expansion from the current 28M units toward the 50M target by 2030. Each percentage point increase in middle-class household penetration of vehicle ownership translates to approximately 500,000-800,000 incremental vehicle units annually. For component suppliers, this sustained demand growth justifies capacity expansion and technology investment with a longer payback horizon.', NULL, 'stable', 'long', '{"2W": "H", "3W": "H", "HCV": "L", "LCV": "M", "4W_PV": "H", "Tractor": "L"}', '["Motion", "Services", "Infotainment", "ADAS"]', '{}', true, '2026-04-15 14:28:35.234252+05:30', '2026-04-15 14:28:35.234252+05:30', '2026-04-15 14:28:35.234252+05:30', false, 'UNVERIFIED', '', '', '{"market_opportunity": "India vehicle market projected to reach 50M units by 2030 per Automotive Mission Plan 2047; component industry $200B by FY30", "industry_investment": "N/A", "subsidy_or_incentive": "GST rationalisation on small cars and EVs supporting affordability for middle-class buyers", "government_investment": "N/A", "cost_impact_per_vehicle": "N/A"}', '{"announced": "2026-04", "effective": "2025-01", "completion": "2030-12"}', '[{"url": "", "claim": "Growing working population and expanding middle class are expected to remain the key demand drivers for India''s auto component industry", "source": "IBEF Auto Components Industry Report, accessed April 2026"}, {"url": "", "claim": "India is the world''s third-largest automobile market by both value and volume", "source": "IBEF Auto Components Industry Report, accessed April 2026"}]', '2026-04-15 14:28:35.234252+05:30', '2026-04-15 14:28:35.234252+05:30', 1); ON CONFLICT DO NOTHING;
INSERT INTO public.pestel_factors (id, code, name, category, selection_reasoning, likelihood, likelihood_reasoning, impact, impact_reasoning, origin_date, trend, time_horizon, segment_relevance, affected_pillars, source_ids, is_active, last_refreshed, created_at, updated_at, is_foundational, verification_verdict, verification_source, verification_evidence, financial_context, key_dates, citations, first_seen_date, last_confirmed_date, confirmation_count) VALUES (84, 'ethanol_blending_programme_â€”_e20_mandate_driving_f', 'Ethanol blending programme â€” E20 mandate driving fuel system recalibration', 'L', 'India''s mandatory E20 fuel standard (implemented April 2025) requires all new vehicles to be E20-compatible, mandating recalibrated fuel injectors, modified seals, updated ECUs, and revised lambda sensors across ICE powertrains. This creates a mandatory technology refresh cycle for Bosch''s powertrain solutions and aftermarket retrofit pillars, as existing fleet vehicles require compatible components for E20 fuel compatibility.', 9, 'E20 mandate is confirmed policy, already implemented. The government''s ethanol blending programme has achieved 12-15% blending in FY25 and is targeting 20% by FY26. Regulatory compliance is non-negotiable for new vehicle type approvals.', 7, 'Every new ICE vehicle sold in India requires E20-compatible fuel system components â€” a mandatory content upgrade for Bosch''s injectors, pumps, and ECUs. The aftermarket retrofit opportunity for the existing ~300 million vehicle fleet (2W + 4W) is substantial, though retrofit adoption will be gradual. Bosch''s fuel systems business stands to benefit from both OEM supply and aftermarket demand.', NULL, 'escalating', 'immediate', '{"2W": "H", "3W": "M", "HCV": "M", "LCV": "H", "4W_PV": "H", "Tractor": "H"}', '["Infotainment", "Motion", "Services"]', '{}', false, '2026-03-16 23:47:58.163502+05:30', '2026-03-16 23:47:58.163502+05:30', '2026-03-16 23:47:58.163502+05:30', true, 'UNVERIFIED', NULL, NULL, '{}', '{}', '[]', '2026-03-16 23:47:58.163502+05:30', '2026-03-16 23:47:58.163502+05:30', 1); ON CONFLICT DO NOTHING;
INSERT INTO public.pestel_factors (id, code, name, category, selection_reasoning, likelihood, likelihood_reasoning, impact, impact_reasoning, origin_date, trend, time_horizon, segment_relevance, affected_pillars, source_ids, is_active, last_refreshed, created_at, updated_at, is_foundational, verification_verdict, verification_source, verification_evidence, financial_context, key_dates, citations, first_seen_date, last_confirmed_date, confirmation_count) VALUES (140, 'fame_subsidy_extension_sought_for_e_2w/e_3w_â€”_poli', 'FAME Subsidy Extension Sought for e-2W/e-3W â€” Policy Continuity Risk', 'P', 'With only 1 million e-2W sold against a 1.4 million target, the government is seeking Finance Ministry approval to extend subsidies for 2W and 3W EVs. Policy continuity or discontinuity directly determines the pace of EV adoption in segments where Bosch''s EV Powertrain and Energy & Charging pillars have growing exposure. A subsidy gap or delay would slow EV volume ramp, affecting Bosch''s transition revenue planning.', 7, 'The subsidy extension request is confirmed (ET Auto, March 2026), but Finance Ministry approval is not guaranteed given fiscal consolidation pressures. India''s fiscal deficit target of 4.5% GDP for FY26 creates headroom constraints. Historical precedent (FAME II extension) suggests approval is likely but timing is uncertain.', 7, 'The 2W EV segment (currently ~6% penetration on 1.96 Cr units = ~1.18 Lakh EVs) is the highest-volume EV opportunity for Bosch''s EV Powertrain components. A subsidy extension sustaining demand toward the 1.4M target would add ~400,000 incremental EV units, each representing â‚¹8,000â€“15,000 in Bosch EV component content opportunity.', NULL, 'stable', 'immediate', '{"2W": "H", "3W": "H", "HCV": "L", "LCV": "L", "4W_PV": "L", "Tractor": "L"}', '["EV Powertrain", "Energy & Charging", "Vehicle Diagnostics", "Powertrain Solutions"]', '{}', false, '2026-03-26 11:22:14.095204+05:30', '2026-03-26 11:22:14.095204+05:30', '2026-03-26 11:22:14.095204+05:30', true, 'UNVERIFIED', NULL, NULL, '{}', '{}', '[]', '2026-03-26 11:22:14.095204+05:30', '2026-03-26 11:22:14.095204+05:30', 1); ON CONFLICT DO NOTHING;
INSERT INTO public.pestel_factors (id, code, name, category, selection_reasoning, likelihood, likelihood_reasoning, impact, impact_reasoning, origin_date, trend, time_horizon, segment_relevance, affected_pillars, source_ids, is_active, last_refreshed, created_at, updated_at, is_foundational, verification_verdict, verification_source, verification_evidence, financial_context, key_dates, citations, first_seen_date, last_confirmed_date, confirmation_count) VALUES (26, 'hydrogen_fuel_cell_hcv', 'Hydrogen fuel cell pilots in HCV â€” Tata/Ashok Leyland trials 2025', 'T', 'Hydrogen fuel cell trucks are in pilot trials on Mumbai-Pune corridor (Tata Motors/IOCL partnership, 2025). For Bosch, this represents an early-stage opportunity in HCV Thermal Management and Powertrain systems â€” 5-8 year commercialisation horizon.', 6, 'Score 6: Pilots confirmed but commercialisation is highly uncertain. India lacks hydrogen fuelling infrastructure. Technology cost is still 3-4x diesel equivalent.', 3, 'Score 5: Long-horizon opportunity. Relevant for Bosch''s advance engineering teams but not a material revenue driver before 2030-32.', NULL, 'new', 'long', '{"2W": "L", "3W": "L", "HCV": "H", "LCV": "L", "4W_PV": "L", "Tractor": "L"}', '["Energy", "Motion"]', '{19}', true, '2026-03-16 22:45:46.381831+05:30', '2026-03-16 22:45:46.381831+05:30', '2026-03-16 22:48:13.097302+05:30', false, 'UNVERIFIED', NULL, NULL, '{}', '{}', '[]', '2026-03-16 22:45:46.381831+05:30', '2026-03-16 22:45:46.381831+05:30', 1); ON CONFLICT DO NOTHING;
INSERT INTO public.pestel_factors (id, code, name, category, selection_reasoning, likelihood, likelihood_reasoning, impact, impact_reasoning, origin_date, trend, time_horizon, segment_relevance, affected_pillars, source_ids, is_active, last_refreshed, created_at, updated_at, is_foundational, verification_verdict, verification_source, verification_evidence, financial_context, key_dates, citations, first_seen_date, last_confirmed_date, confirmation_count) VALUES (91, 'flex_fuel_engine_mandate_creating_dual_fuel_powert', 'Flex-fuel engine mandate creating dual-fuel powertrain component demand', 'P', 'The ethanol blending programme, now framed as a national energy security imperative (ET Auto, March 2026), is driving government pressure on OEMs to adopt flex-fuel engines capable of running on E20-E85. This creates a specific technical requirement for Bosch''s fuel injection systems, sensors, and ECUs to be compatible with higher ethanol concentrations â€” requiring both new OEM supply and aftermarket retrofit solutions. The 2W segment is particularly exposed as Hero, TVS, and Bajaj are all under government pressure to offer flex-fuel variants.', 7, 'The government has already mandated E20 compatibility for new vehicles from April 2023. The push to E30/E40 flex-fuel is confirmed by NITI Aayog recommendations and the current oil price environment makes acceleration politically attractive. Hero MotoCorp has already launched flex-fuel 2W variants.', 6, 'Bosch''s fuel injection systems for 2W (1.96Cr units) and 3W (7.41L units) require ethanol-compatible materials (seals, injector coatings) and ECU recalibration for flex-fuel operation. This is a mandatory upgrade cycle â€” not optional â€” creating a captive demand event. Estimate: â‚¹500-800 Cr addressable revenue across OEM supply and aftermarket retrofit for ethanol-compatible fuel systems over FY26-28.', NULL, 'escalating', 'short', '{"2W": "H", "3W": "M", "HCV": "L", "LCV": "M", "4W_PV": "H", "Tractor": "L"}', '["Motion", "OS", "Services"]', '{}', true, '2026-03-17 10:47:58.048368+05:30', '2026-03-17 10:47:58.048368+05:30', '2026-03-17 10:47:58.048368+05:30', false, 'UNVERIFIED', NULL, NULL, '{}', '{}', '[]', '2026-03-17 10:47:58.048368+05:30', '2026-03-17 10:47:58.048368+05:30', 1); ON CONFLICT DO NOTHING;
INSERT INTO public.pestel_factors (id, code, name, category, selection_reasoning, likelihood, likelihood_reasoning, impact, impact_reasoning, origin_date, trend, time_horizon, segment_relevance, affected_pillars, source_ids, is_active, last_refreshed, created_at, updated_at, is_foundational, verification_verdict, verification_source, verification_evidence, financial_context, key_dates, citations, first_seen_date, last_confirmed_date, confirmation_count) VALUES (124, 'autoverse_direct_to_garage_model_â€”_aftermarket_dis', 'Autoverse Direct-to-Garage Model â€” Aftermarket Disintermediation Risk', 'E', 'Autoverse Mobility''s data-led direct-to-garage supply chain targeting 140,000 garages threatens Bosch''s traditional aftermarket distribution model. The $11B aftermarket (â‚¹1.05L Cr per ACMA) is a high-margin segment for Bosch''s Aftermarket & Retrofit pillar. Digital-native aggregators bypassing traditional distributors could erode Bosch''s channel pricing power and brand visibility at the point of fitment.', 6, 'The direct-to-garage model is already operational with stated scale targets (ET Auto, March 2026). India''s fragmented 140,000-garage ecosystem is structurally amenable to digital aggregation, as seen in analogous B2B marketplace successes in pharma and FMCG distribution.', 4, 'Bosch''s aftermarket business in India is estimated at â‚¹3,000-4,000 Cr annually (Estimate based on: ACMA â‚¹1.05L Cr total aftermarket, Bosch''s ~3-4% share). Disintermediation could compress margins by 300-500 bps if Bosch cannot establish direct digital relationships with garages. Countervailing opportunity: Bosch could partner with or supply to such platforms.', NULL, 'escalating', 'short', '{"2W": "H", "3W": "M", "HCV": "L", "LCV": "M", "4W_PV": "H", "Tractor": "L"}', '["Infotainment", "OS", "Services"]', '{}', true, '2026-03-26 11:21:49.30067+05:30', '2026-03-26 11:21:49.30067+05:30', '2026-03-26 11:26:33.982723+05:30', false, 'UNVERIFIED', NULL, NULL, '{}', '{}', '[]', '2026-03-26 11:21:49.30067+05:30', '2026-03-26 11:21:49.30067+05:30', 1); ON CONFLICT DO NOTHING;
INSERT INTO public.pestel_factors (id, code, name, category, selection_reasoning, likelihood, likelihood_reasoning, impact, impact_reasoning, origin_date, trend, time_horizon, segment_relevance, affected_pillars, source_ids, is_active, last_refreshed, created_at, updated_at, is_foundational, verification_verdict, verification_source, verification_evidence, financial_context, key_dates, citations, first_seen_date, last_confirmed_date, confirmation_count) VALUES (79, 'renault_duster_relaunch_â€”_mid_suv_segment_volume_r', 'Renault Duster relaunch â€” mid-SUV segment volume recovery signal', 'E', 'Renault''s new-generation Duster relaunch targets the high-growth mid-SUV segment, which carries the highest Bosch content per vehicle (ADAS, advanced braking, infotainment connectivity). While Renault India''s volumes are modest (~50,000-80,000 units annually), the Duster''s positioning in the â‚¹12-18 lakh bracket â€” where ADAS and connected features are increasingly standard â€” makes it a relevant demand signal for Bosch''s Vehicle Motion and Infotainment pillars.', 7, 'Renault''s track record with the original Duster (2012 breakthrough cited by CEO Marc Nassif) provides credibility, but India''s mid-SUV segment is now intensely competitive (Creta, Seltos, Nexon). Volume outcomes are uncertain, though launch is confirmed.', 3, 'Renault India''s scale limits direct revenue impact for Bosch. However, the Duster''s feature set (likely ADAS L1, connected infotainment) contributes to segment-level demand normalisation for these technologies. Bosch''s content per Duster unit is estimated at â‚¹25,000-40,000 across braking, fuel systems, and electronics â€” modest in absolute terms given volume constraints.', NULL, 'stable', 'short', '{"2W": "L", "3W": "L", "HCV": "L", "LCV": "L", "4W_PV": "H", "Tractor": "L"}', '["Infotainment", "Motion"]', '{}', true, '2026-03-16 23:47:58.163502+05:30', '2026-03-16 23:47:58.163502+05:30', '2026-03-16 23:47:58.163502+05:30', false, 'UNVERIFIED', NULL, NULL, '{}', '{}', '[]', '2026-03-16 23:47:58.163502+05:30', '2026-03-16 23:47:58.163502+05:30', 1); ON CONFLICT DO NOTHING;
INSERT INTO public.pestel_factors (id, code, name, category, selection_reasoning, likelihood, likelihood_reasoning, impact, impact_reasoning, origin_date, trend, time_horizon, segment_relevance, affected_pillars, source_ids, is_active, last_refreshed, created_at, updated_at, is_foundational, verification_verdict, verification_source, verification_evidence, financial_context, key_dates, citations, first_seen_date, last_confirmed_date, confirmation_count) VALUES (75, 'jsw_motors_entry_â€”_new_domestic_oem_adds_component', 'JSW Motors entry â€” new domestic OEM adds component demand', 'P', 'JSW Motors hiring a Head of Strategy with Tata/Hyundai/MG pedigree signals serious intent to enter vehicle manufacturing, adding a potential new OEM customer for Bosch''s full technology stack. A new domestic OEM with JSW Group''s capital base (steel, energy, infrastructure) could fast-track localised EV platforms, creating early-stage supply partnership opportunities for Bosch across powertrain, chassis, and ADAS pillars.', 5, 'Talent acquisition is a necessary but not sufficient indicator of production readiness. JSW has announced mobility ambitions but no confirmed vehicle platform or launch timeline. India''s OEM entry barriers remain high; 3-5 year timeline to volume production is realistic, introducing execution risk.', 3, 'If JSW Motors reaches 50,000-100,000 units annually within 5 years (optimistic), Bosch content opportunity at â‚¹20,000-30,000 per vehicle implies â‚¹100-300 Crore incremental revenue. More strategically, early design-in partnerships with a new OEM offer long-term platform lock-in advantages that outweigh near-term revenue.', NULL, 'new', 'medium', '{"2W": "L", "3W": "L", "HCV": "L", "LCV": "L", "4W_PV": "H", "Tractor": "L"}', '["Body & Comfort", "Energy", "Motion", "OS"]', '{}', true, '2026-03-16 23:47:58.163502+05:30', '2026-03-16 23:47:58.163502+05:30', '2026-03-16 23:47:58.163502+05:30', false, 'UNVERIFIED', NULL, NULL, '{}', '{}', '[]', '2026-03-16 23:47:58.163502+05:30', '2026-03-16 23:47:58.163502+05:30', 1); ON CONFLICT DO NOTHING;
INSERT INTO public.pestel_factors (id, code, name, category, selection_reasoning, likelihood, likelihood_reasoning, impact, impact_reasoning, origin_date, trend, time_horizon, segment_relevance, affected_pillars, source_ids, is_active, last_refreshed, created_at, updated_at, is_foundational, verification_verdict, verification_source, verification_evidence, financial_context, key_dates, citations, first_seen_date, last_confirmed_date, confirmation_count) VALUES (189, 'mahindra_south_africa_plant_expansion_â€”_indian_sup', 'Mahindra South Africa Plant Expansion â€” Indian Supplier Export Opportunity', 'E', 'Mahindra''s move to upgrade its South Africa manufacturing plant to sidestep import tariffs and compete with Chinese rivals signals an emerging export-led manufacturing strategy that creates incremental demand for Indian-origin auto components. Tier-1 suppliers already in Mahindra''s supply chain gain a potential export channel to Africa without needing independent market entry. Affects Powertrain Solutions, Chassis Systems, and Body Electronics pillars through export supply chain extension.', 7, 'Mahindra has a confirmed strategic intent to expand in South Africa, driven by competitive pressure from Chinese OEMs (BYD, SAIC) gaining ground in the market. The business case is strengthened by South Africa''s import tariff structure favouring local assembly. Mahindra''s existing South Africa presence (Mahindra South Africa) provides an operational foundation.', 5, 'The incremental component export opportunity from a single plant upgrade is meaningful but not transformative â€” estimated at â‚¹500â€“1,500 Cr in annual component exports at full ramp. However, it establishes a precedent for Indian OEM-led component export corridors into Africa, a market of 1.3B people with growing vehicle demand. The strategic signal value exceeds the immediate financial impact.', NULL, 'new', 'medium', '{"2W": "L", "3W": "L", "HCV": "M", "LCV": "M", "4W_PV": "H", "Tractor": "L"}', '["Motion", "Infotainment", "Compute"]', '{}', true, '2026-04-16 14:28:13.995281+05:30', '2026-04-16 14:28:13.995281+05:30', '2026-04-16 14:28:13.995281+05:30', false, 'UNVERIFIED', '', '', '{"market_opportunity": "Estimate based on: South Africa auto market ~500K units/year; Mahindra targeting affordable vehicle segment; Indian component export opportunity â‚¹500â€“1,500 Cr at full ramp", "industry_investment": "N/A", "subsidy_or_incentive": "India auto component exports benefit from RoDTEP scheme; India-Africa trade frameworks under negotiation", "government_investment": "N/A", "cost_impact_per_vehicle": "N/A"}', '{"announced": "2026-04", "effective": "", "completion": ""}', '[{"url": "https://auto.economictimes.indiatimes.com/news/industry/mahindra-plans-south-africa-plant-upgrade-amid-rising-competition/130284447", "claim": "Mahindra plans South Africa plant upgrade amid rising competition, aiming to capitalise on rising demand for affordable vehicles and sidestep potential import tariffs", "source": "ET Auto, 15 Apr 2026"}, {"url": "https://auto.economictimes.indiatimes.com/news/passenger-vehicle/byd-shuns-price-war-in-south-africa-to-build-ev-brand/130297001", "claim": "BYD sold 589 units in March in South Africa, outperforming established legacy brands like Volvo", "source": "ET Auto, 16 Apr 2026"}]', '2026-04-16 14:28:13.995281+05:30', '2026-04-16 14:28:13.995281+05:30', 1); ON CONFLICT DO NOTHING;
INSERT INTO public.pestel_factors (id, code, name, category, selection_reasoning, likelihood, likelihood_reasoning, impact, impact_reasoning, origin_date, trend, time_horizon, segment_relevance, affected_pillars, source_ids, is_active, last_refreshed, created_at, updated_at, is_foundational, verification_verdict, verification_source, verification_evidence, financial_context, key_dates, citations, first_seen_date, last_confirmed_date, confirmation_count) VALUES (190, 'etauto_tech_awards_2026_â€”_industry_innovation_benc', 'ETAuto Tech Awards 2026 â€” Industry Innovation Benchmarking Signal', 'S', 'The ETAuto Tech Awards 2026 (June 23, Bengaluru) honouring OEMs, Tier-1 suppliers, technology companies, and startups for engineering excellence signals growing industry focus on measurable technology innovation as a competitive differentiator. For Tier-1 suppliers, such platforms create reputational benchmarking pressure and signal which technology domains (ADAS, EV, software) are receiving industry recognition â€” influencing R&D investment prioritisation and talent attraction. Affects Software & Services, Vehicle Motion, and Manufacturing & Industry 4.0 pillars through innovation culture signalling.', 10, 'The awards have been announced with a confirmed date (June 23, 2026) and nominations are open. This is a certain event, not a projection.', 3, 'Industry awards are a soft signal rather than a direct financial driver. Their impact on Tier-1 supplier strategy is indirect â€” through talent attraction, OEM perception, and R&D prioritisation signals. The financial impact is negligible in the short term but contributes to brand equity and innovation culture over the medium term.', NULL, 'new', 'immediate', '{"2W": "M", "3W": "L", "HCV": "L", "LCV": "L", "4W_PV": "M", "Tractor": "L"}', '["Motion", "Energy", "OS", "Compute"]', '{}', true, '2026-04-16 14:28:13.995281+05:30', '2026-04-16 14:28:13.995281+05:30', '2026-04-16 14:28:13.995281+05:30', false, 'UNVERIFIED', '', '', '{"market_opportunity": "N/A", "industry_investment": "N/A", "subsidy_or_incentive": "N/A", "government_investment": "N/A", "cost_impact_per_vehicle": "N/A"}', '{"announced": "2026-04-16", "effective": "2026-06-23", "completion": "2026-06-23"}', '[{"url": "https://auto.economictimes.indiatimes.com/news/auto-technology/etautotech-awards-2026-celebrate-innovation-in-automotive-engineering/130300407", "claim": "ETAuto launches Tech Awards to honour engineering excellence and innovation; awards to be presented at a gala ceremony on June 23 in Bengaluru", "source": "ET Auto, 16 Apr 2026"}, {"url": "https://auto.economictimes.indiatimes.com/news/auto-technology/etautotech-awards-2026-celebrate-innovation-in-automotive-engineering/130300407", "claim": "Awards will honour OEMs, Tier-1 suppliers, technology companies, and startups which have excelled in building technologies and solutions that are driving measurable change across the automotive value chain", "source": "ET Auto, 16 Apr 2026"}]', '2026-04-16 14:28:13.995281+05:30', '2026-04-16 14:28:13.995281+05:30', 1); ON CONFLICT DO NOTHING;
INSERT INTO public.pestel_factors (id, code, name, category, selection_reasoning, likelihood, likelihood_reasoning, impact, impact_reasoning, origin_date, trend, time_horizon, segment_relevance, affected_pillars, source_ids, is_active, last_refreshed, created_at, updated_at, is_foundational, verification_verdict, verification_source, verification_evidence, financial_context, key_dates, citations, first_seen_date, last_confirmed_date, confirmation_count) VALUES (191, 'india_ev_market_$206b_by_2030_â€”_structural_investm', 'India EV Market $206B by 2030 â€” Structural Investment Imperative', 'E', 'The IBEF projection of India''s EV market reaching $206B by 2030 (from a nascent base) is the most consequential long-term structural signal for Tier-1 supplier capital allocation. This projection encompasses vehicles, components, charging infrastructure, and services â€” creating investment imperatives across EV Powertrain, Energy & Charging, Thermal Management, and Software & Services pillars. The scale of this opportunity justifies dedicated technology pillar investment strategies rather than incremental ICE-adjacent moves.', 5, 'The $206B EV market projection by 2030 is ambitious and encompasses the full EV ecosystem (vehicles + components + infrastructure + services). Achieving this requires 10M+ EV annual sales by 2030, which itself is a stretch target. The projection is from IBEF (government-affiliated) and carries policy aspiration rather than market-based forecasting rigour.', 10, 'If the EV market reaches even 50% of the $206B projection ($103B), it would represent a component opportunity larger than India''s entire auto component industry today ($80.2B in FY25). This scale fundamentally justifies Tier-1 suppliers building dedicated EV technology divisions, separate from ICE businesses, with distinct P&L accountability and investment horizons.', NULL, 'escalating', 'long', '{"2W": "H", "3W": "H", "HCV": "M", "LCV": "H", "4W_PV": "H", "Tractor": "L"}', '["Energy", "Motion", "OS", "Compute"]', '{}', true, '2026-04-16 14:28:13.995281+05:30', '2026-04-16 14:28:13.995281+05:30', '2026-04-16 14:28:13.995281+05:30', false, 'UNVERIFIED', '', '', '{"market_opportunity": "US$206B EV market by 2030 per IBEF; encompasses vehicles, components, charging, services", "industry_investment": "N/A", "subsidy_or_incentive": "GST 5% on EVs; FAME III demand incentives; state EV subsidies", "government_investment": "FAME III â‚¹2,671 Cr; PLI Advanced Chemistry Cell â‚¹18,100 Cr", "cost_impact_per_vehicle": "N/A"}', '{"announced": "2026-04", "effective": "2025-01", "completion": "2030-12"}', '[{"url": "", "claim": "The EV market is expected to reach US$206 billion by 2030", "source": "IBEF Auto Sector report, accessed 16 Apr 2026"}, {"url": "", "claim": "By 2030, ten million EVs could be sold each year", "source": "IBEF Auto Sector report, accessed 16 Apr 2026"}]', '2026-04-16 14:28:13.995281+05:30', '2026-04-16 14:28:13.995281+05:30', 1); ON CONFLICT DO NOTHING;
INSERT INTO public.pestel_factors (id, code, name, category, selection_reasoning, likelihood, likelihood_reasoning, impact, impact_reasoning, origin_date, trend, time_horizon, segment_relevance, affected_pillars, source_ids, is_active, last_refreshed, created_at, updated_at, is_foundational, verification_verdict, verification_source, verification_evidence, financial_context, key_dates, citations, first_seen_date, last_confirmed_date, confirmation_count) VALUES (192, 'zf_global_restructuring_â€”_competitive_intensity_sh', 'ZF Global Restructuring â€” Competitive Intensity Shift in India', 'E', 'ZF''s CEO-led transformation programme targeting a leaner, more agile structure by 2028 signals that a top-3 global Tier-1 competitor is repositioning its cost base and technology portfolio. For India-based Tier-1 suppliers, a restructured ZF could emerge as a more aggressive competitor in chassis systems, ADAS, and transmission â€” or alternatively create supply gaps that domestic suppliers can fill if ZF rationalises India operations. The strategic uncertainty warrants monitoring across chassis, ADAS, and powertrain pillars.', 8, 'ZF''s restructuring is confirmed under a new CEO who took charge in October 2025, with a 2028 completion target. Global Tier-1 restructurings of this scale consistently result in India subsidiary rationalisation, JV reviews, and localisation strategy changes â€” all of which have direct competitive implications for domestic Tier-1 suppliers.', 6, 'ZF India supplies chassis, transmission, and ADAS components to major OEMs including Tata, Mahindra, and Maruti. A restructuring-driven capacity or product-line rationalisation could open â‚¹500-1,500 Cr in annual supply opportunities for domestic Tier-1 suppliers, particularly in braking, steering, and ADAS sensor integration. Conversely, a leaner ZF could intensify price competition in premium segments.', NULL, 'new', 'medium', '{"2W": "L", "3W": "L", "HCV": "H", "LCV": "M", "4W_PV": "H", "Tractor": "L"}', '["Compute", "Motion"]', '{}', true, '2026-04-24 16:06:25.016681+05:30', '2026-04-24 16:06:25.016681+05:30', '2026-04-24 16:06:25.016681+05:30', false, 'UNVERIFIED', '', '', '{"market_opportunity": "Estimate based on: ZF India revenue ~â‚¹3,000-4,000 Cr; potential supply displacement opportunity for domestic Tier-1s if ZF rationalises product lines", "industry_investment": "ZF global restructuring â€” specific India capex impact not yet disclosed; global restructuring involves workforce reduction of ~14,000 globally (ZF public statements)", "subsidy_or_incentive": "N/A", "government_investment": "N/A", "cost_impact_per_vehicle": "N/A"}', '{"announced": "2026-04", "effective": "2025-10", "completion": "2028-12"}', '[{"url": "https://auto.economictimes.indiatimes.com/news/auto-technology/mathias-miedreich-steering-zfs-transformative-journey-amidst-challenges/130486990", "claim": "ZF CEO Mathias Miedreich, who took charge last October, is working towards a massive transformational exercise to ensure the German parts supplier sheds needless baggage and emerges a more nimble-footed entity by 2028", "source": "ET Auto, 24 Apr 2026"}]', '2026-04-24 16:06:25.016681+05:30', '2026-04-24 16:06:25.016681+05:30', 1); ON CONFLICT DO NOTHING;
INSERT INTO public.pestel_factors (id, code, name, category, selection_reasoning, likelihood, likelihood_reasoning, impact, impact_reasoning, origin_date, trend, time_horizon, segment_relevance, affected_pillars, source_ids, is_active, last_refreshed, created_at, updated_at, is_foundational, verification_verdict, verification_source, verification_evidence, financial_context, key_dates, citations, first_seen_date, last_confirmed_date, confirmation_count) VALUES (164, 'lightweighting_&_nvh_solutions_demand_â€”_ev_transit', 'Lightweighting & NVH Solutions Demand â€” EV Transition Material Shift', 'T', 'Freudenberg India''s strategic pivot to lightweighting and NVH solutions â€” with automotive at 40% of â‚¹4,420 Cr revenue â€” signals that global Tier-1 suppliers are repositioning their India portfolios around EV-specific material requirements. EVs require different NVH management (absence of ICE masking noise) and lightweighting to offset battery weight, creating new component categories and displacing traditional ICE-era suppliers.', 7, 'Freudenberg''s strategic shift is a confirmed corporate decision reflected in CY25 financials. The NVH and lightweighting requirement for EVs is technically established â€” EV drivetrains expose road and wind noise previously masked by ICE, and battery weight penalties require structural lightweighting. Multiple global OEMs have confirmed these requirements in their India EV programmes.', 6, 'NVH and lightweighting represent a growing content category estimated at â‚¹800-1,200 Cr in India''s auto component market (Estimate based on: Freudenberg''s â‚¹1,768 Cr automotive revenue as a proxy for segment size). For Tier-1 suppliers in traditional sealing and vibration management, this signals both a threat (ICE product obsolescence) and an opportunity (EV-specific NVH solutions at higher content value).', NULL, 'escalating', 'short', '{"2W": "L", "3W": "L", "HCV": "L", "LCV": "M", "4W_PV": "H", "Tractor": "L"}', '["Energy", "ADAS", "Motion"]', '{}', true, '2026-04-01 11:05:44.591993+05:30', '2026-04-01 11:05:44.591993+05:30', '2026-04-01 11:05:44.591993+05:30', false, 'UNVERIFIED', NULL, NULL, '{}', '{}', '[]', '2026-04-01 11:05:44.591993+05:30', '2026-04-01 11:05:44.591993+05:30', 1); ON CONFLICT DO NOTHING;
INSERT INTO public.pestel_factors (id, code, name, category, selection_reasoning, likelihood, likelihood_reasoning, impact, impact_reasoning, origin_date, trend, time_horizon, segment_relevance, affected_pillars, source_ids, is_active, last_refreshed, created_at, updated_at, is_foundational, verification_verdict, verification_source, verification_evidence, financial_context, key_dates, citations, first_seen_date, last_confirmed_date, confirmation_count) VALUES (163, 'ather_el_platform_sub_â‚¹1l_scooter_â€”_mass_market_ev', 'Ather EL Platform Sub-â‚¹1L Scooter â€” Mass-Market EV Price Compression', 'E', 'Ather''s new EL platform scooter, priced above â‚¹1L but targeting psychological price accessibility, signals intensifying price competition in the e-2W segment. For Tier-1 suppliers, this creates margin compression pressure as OEMs demand lower component costs to hit mass-market price points. The platform approach also signals standardisation of EV powertrain architecture, which could reduce per-unit content value.', 6, 'Ather''s CBO has publicly confirmed the EL platform launch timeline as ''next few months'' from March 2026, making this a near-certain near-term event. The â‚¹1L price floor is explicitly stated, and the competitive pressure on component pricing is a logical consequence of OEM margin management at this price point.', 5, 'Price compression in e-2W components could reduce motor, controller, and BMS content value by 10-15% per unit as OEMs target sub-â‚¹1L price points. However, volume uplift from mass-market adoption partially offsets per-unit margin erosion. The net effect on Tier-1 revenue depends on volume elasticity, which is positive given 2W EV penetration is still only ~6%.', NULL, 'escalating', 'short', '{"2W": "H", "3W": "L", "HCV": "L", "LCV": "L", "4W_PV": "L", "Tractor": "L"}', '["Energy", "OS"]', '{}', true, '2026-04-01 11:05:44.591993+05:30', '2026-04-01 11:05:44.591993+05:30', '2026-04-01 11:05:44.591993+05:30', false, 'UNVERIFIED', NULL, NULL, '{}', '{}', '[]', '2026-04-01 11:05:44.591993+05:30', '2026-04-01 11:05:44.591993+05:30', 1); ON CONFLICT DO NOTHING;
INSERT INTO public.pestel_factors (id, code, name, category, selection_reasoning, likelihood, likelihood_reasoning, impact, impact_reasoning, origin_date, trend, time_horizon, segment_relevance, affected_pillars, source_ids, is_active, last_refreshed, created_at, updated_at, is_foundational, verification_verdict, verification_source, verification_evidence, financial_context, key_dates, citations, first_seen_date, last_confirmed_date, confirmation_count) VALUES (165, 'fuel_shortage_fear_driven_ev_demand_â€”_demand_volat', 'Fuel Shortage Fear-Driven EV Demand â€” Demand Volatility Risk', 'S', 'The March 2026 EV sales spike â€” particularly the 36% monthly surge in e-2W â€” was partially driven by consumer fear of fuel shortages linked to West Asia conflict, not purely by structural preference or economics. For Tier-1 suppliers, this introduces demand volatility risk: if geopolitical tensions ease and fuel prices stabilise, the spike-driven demand may not sustain, creating inventory and capacity planning challenges.', 5, 'ET Auto explicitly attributes part of the March surge to ''fuel shortage fears,'' distinguishing it from the underlying 20.5% full-year growth trend. Consumer sentiment-driven demand spikes are historically transient; the West Asia conflict trajectory is uncertain, making the sustainability of this demand driver unpredictable.', 4, 'If 20-30% of the March EV sales spike was sentiment-driven rather than structural, the April-May 2026 demand could normalise downward, creating a short-term inventory overhang for EV component suppliers. The impact is moderated by the underlying 20.5% full-year growth trend, which confirms structural demand exists independent of the fear-driven spike.', NULL, 'new', 'immediate', '{"2W": "H", "3W": "M", "HCV": "L", "LCV": "L", "4W_PV": "M", "Tractor": "L"}', '["Energy"]', '{}', true, '2026-04-01 11:05:44.591993+05:30', '2026-04-01 11:05:44.591993+05:30', '2026-04-01 11:05:44.591993+05:30', false, 'UNVERIFIED', NULL, NULL, '{}', '{}', '[]', '2026-04-01 11:05:44.591993+05:30', '2026-04-01 11:05:44.591993+05:30', 1); ON CONFLICT DO NOTHING;
INSERT INTO public.pestel_factors (id, code, name, category, selection_reasoning, likelihood, likelihood_reasoning, impact, impact_reasoning, origin_date, trend, time_horizon, segment_relevance, affected_pillars, source_ids, is_active, last_refreshed, created_at, updated_at, is_foundational, verification_verdict, verification_source, verification_evidence, financial_context, key_dates, citations, first_seen_date, last_confirmed_date, confirmation_count) VALUES (162, 'fy26_best_ever_auto_industry_performance_â€”_gst_cut', 'FY26 Best-Ever Auto Industry Performance â€” GST Cut & Monsoon Tailwind', 'E', 'FY26 registered India''s best-ever fiscal performance across vehicle categories, driven by GST rate cuts and a good monsoon fuelling H2 rebound. This broad-based volume surge creates a high-watermark demand baseline for Tier-1 suppliers entering FY27, but also raises the risk of demand normalisation or correction. The GST cut mechanism signals government willingness to use fiscal tools to sustain auto sector growth.', 8, 'ET Auto''s FY26 review is a verified post-period assessment, not a forecast. The GST cut and monsoon tailwind are documented policy and weather events. The ''best-ever'' characterisation is corroborated by tractor (+22-24%), 4W EV (+82%), and 2W EV (+20.5%) data points from the same scan.', 5, 'A best-ever FY26 creates a high base for FY27 comparisons and may pull forward demand that would otherwise occur in FY27, creating a potential volume air pocket. For Tier-1 suppliers, this means FY26 capacity utilisation was likely at peak, but FY27 planning must account for normalisation risk. The GST cut precedent also signals that future policy support is available if demand softens.', NULL, 'stable', 'immediate', '{"2W": "M", "3W": "M", "HCV": "H", "LCV": "H", "4W_PV": "H", "Tractor": "M"}', '["Infotainment", "Motion", "Services"]', '{}', true, '2026-04-01 11:05:44.591993+05:30', '2026-04-01 11:05:44.591993+05:30', '2026-04-01 11:05:44.591993+05:30', false, 'UNVERIFIED', NULL, NULL, '{}', '{}', '[]', '2026-04-01 11:05:44.591993+05:30', '2026-04-01 11:05:44.591993+05:30', 1); ON CONFLICT DO NOTHING;
INSERT INTO public.pestel_factors (id, code, name, category, selection_reasoning, likelihood, likelihood_reasoning, impact, impact_reasoning, origin_date, trend, time_horizon, segment_relevance, affected_pillars, source_ids, is_active, last_refreshed, created_at, updated_at, is_foundational, verification_verdict, verification_source, verification_evidence, financial_context, key_dates, citations, first_seen_date, last_confirmed_date, confirmation_count) VALUES (118, 'fame_subsidy_extension_sought_â€”_2w/3w_ev_demand_br', 'FAME Subsidy Extension Sought â€” 2W/3W EV Demand Bridge', 'P', 'The government''s request to the Finance Ministry to extend EV subsidies for 2W and 3W â€” with only 1M of 1.4M target units sold â€” signals policy intent to sustain EV demand momentum. Continuation of subsidies directly supports volume growth in the two segments where Bosch has highest EV component opportunity (3W at 55% EV penetration, 2W transitioning). Uncertainty around approval timing creates near-term demand volatility.', 7, 'The formal Finance Ministry approval request has been filed, and political commitment to EV transition remains strong. However, fiscal consolidation pressures and the shortfall against targets (71% achievement) introduce approval risk and potential scheme redesign.', 7, 'FAME subsidies have been the primary demand driver for e-2W and e-3W. A lapse would reduce EV volumes by an estimated 20-30% in the near term based on historical subsidy-removal sensitivity, directly impacting Bosch''s EV powertrain and BMS pipeline for these segments.', NULL, 'stable', 'immediate', '{"2W": "H", "3W": "H", "HCV": "L", "LCV": "L", "4W_PV": "L", "Tractor": "L"}', '["EV Powertrain", "Chassis Systems", "Energy & Charging", "Aftermarket & Retrofit"]', '{}', false, '2026-03-26 11:21:49.325434+05:30', '2026-03-26 11:21:49.325434+05:30', '2026-03-26 11:21:49.325434+05:30', true, 'UNVERIFIED', NULL, NULL, '{}', '{}', '[]', '2026-03-26 11:21:49.325434+05:30', '2026-03-26 11:21:49.325434+05:30', 1); ON CONFLICT DO NOTHING;
INSERT INTO public.pestel_factors (id, code, name, category, selection_reasoning, likelihood, likelihood_reasoning, impact, impact_reasoning, origin_date, trend, time_horizon, segment_relevance, affected_pillars, source_ids, is_active, last_refreshed, created_at, updated_at, is_foundational, verification_verdict, verification_source, verification_evidence, financial_context, key_dates, citations, first_seen_date, last_confirmed_date, confirmation_count) VALUES (155, 'fame_subsidy_extension_sought_â€”_e_2w/3w_demand_flo', 'FAME Subsidy Extension Sought â€” e-2W/3W Demand Floor at Risk', 'P', 'The Finance Ministry is being petitioned to extend FAME subsidies for 2W and 3W EVs, with only 1M of 1.4M target units sold. A lapse in subsidies would sharply reduce e-2W/3W demand, directly impacting Bosch''s EV powertrain, BMS, and thermal management sales to OEMs like Ola Electric, TVS, and Bajaj. Subsidy continuity is a binary demand driver for this segment.', 6, 'The petition is pending Finance Ministry approval â€” outcome uncertain. Historical precedent (FAME I to FAME II transition) saw gaps that dampened demand. FAME III (â‚¹2,671 Cr for charging) is already approved, but 2W/3W vehicle subsidies are a separate budget line under political negotiation.', 7, 'e-2W currently at ~6% penetration (1.96 Cr units base = ~1.18L EV units). Subsidy lapse could reduce e-2W growth rate by 30-40% in the transition year (estimate based on: FAME II demand elasticity data). For Bosch, this affects EV powertrain content pipeline for 2W/3W OEM customers. 3W EV at 55% penetration is more resilient but 2W is highly subsidy-sensitive.', NULL, 'stable', 'immediate', '{"2W": "H", "3W": "H", "HCV": "L", "LCV": "L", "4W_PV": "L", "Tractor": "L"}', '["EV Powertrain", "Thermal Management", "Energy & Charging"]', '{}', false, '2026-03-26 11:26:33.982723+05:30', '2026-03-26 11:26:33.982723+05:30', '2026-03-26 11:26:33.982723+05:30', true, 'UNVERIFIED', NULL, NULL, '{}', '{}', '[]', '2026-03-26 11:26:33.982723+05:30', '2026-03-26 11:26:33.982723+05:30', 1); ON CONFLICT DO NOTHING;
INSERT INTO public.pestel_factors (id, code, name, category, selection_reasoning, likelihood, likelihood_reasoning, impact, impact_reasoning, origin_date, trend, time_horizon, segment_relevance, affected_pillars, source_ids, is_active, last_refreshed, created_at, updated_at, is_foundational, verification_verdict, verification_source, verification_evidence, financial_context, key_dates, citations, first_seen_date, last_confirmed_date, confirmation_count) VALUES (83, 'e_bus/truck_localisation_policy_â€”_mandatory_local_', 'E-bus/truck localisation policy â€” mandatory local traction motor sourcing', 'L', 'The government''s localisation mandate for traction motors in e-buses and e-trucks (with deadline extended but not withdrawn) creates a regulatory compliance requirement that will force Bosch to either establish local traction motor manufacturing in India or risk exclusion from government-tendered EV commercial vehicle programmes. This is a make-or-break policy for Bosch''s HCV/LCV EV powertrain market access.', 8, 'The policy exists and has been enforced (deadline was set, then extended â€” not cancelled). Government''s PM e-Bus Sewa programme creates strong political will to enforce localisation. A 12-24 month compliance window is the most probable outcome based on precedent from FAME II localisation enforcement.', 7, 'India''s e-bus market (10,000+ units under PM e-Bus Sewa) and nascent e-truck segment represent a combined traction motor market of â‚¹3,000-10,000 Crore over 5 years. Bosch''s inability to qualify as a local supplier would cede this market to domestic players (Tata, Olectra supply chains) or Chinese component manufacturers. Local manufacturing investment of â‚¹500-1,000 Crore would be required to compete.', NULL, 'escalating', 'short', '{"2W": "L", "3W": "L", "HCV": "H", "LCV": "H", "4W_PV": "L", "Tractor": "L"}', '["Energy", "Compute", "Energy"]', '{}', false, '2026-03-16 23:47:58.163502+05:30', '2026-03-16 23:47:58.163502+05:30', '2026-03-16 23:47:58.163502+05:30', true, 'UNVERIFIED', NULL, NULL, '{}', '{}', '[]', '2026-03-16 23:47:58.163502+05:30', '2026-03-16 23:47:58.163502+05:30', 1); ON CONFLICT DO NOTHING;
INSERT INTO public.pestel_factors (id, code, name, category, selection_reasoning, likelihood, likelihood_reasoning, impact, impact_reasoning, origin_date, trend, time_horizon, segment_relevance, affected_pillars, source_ids, is_active, last_refreshed, created_at, updated_at, is_foundational, verification_verdict, verification_source, verification_evidence, financial_context, key_dates, citations, first_seen_date, last_confirmed_date, confirmation_count) VALUES (77, 'global_oil_price_surge_driving_ethanol_blending_â€”_', 'Global oil price surge driving ethanol blending â€” flex-fuel powertrain demand', 'En', 'As of April 2026, Brent crude is trading in the $72-80/bbl range â€” elevated versus 2020-21 lows but not at crisis-surge levels. The ethanol blending programme''s strategic rationale remains intact (energy security, farmer income support) but the ''oil price surge'' as an acute accelerant is less compelling than in 2022-23. The E20 mandate is now implemented on its own policy timeline regardless of oil price movements. Flex-fuel powertrain demand from Maruti, Toyota, and TVS remains a valid medium-term trend driven by regulatory mandate rather than oil price emergency.', 7, 'ET Auto (March 2026) confirms ethanol blending as a ''core pillar of national energy security.'' India''s E20 mandate is already implemented; government has committed to 20% blending by 2025-26. Oil price volatility (geopolitical factors in 2025-26) makes this policy more entrenched, not less.', 7, 'Flex-fuel and E20-compatible engines require recalibrated fuel injectors, lambda sensors, and engine management systems â€” Bosch''s core ICE portfolio. India''s 2W segment (1.96 Crore units) and 4W PV segment (4.7M units FY26) are primary beneficiaries. This extends Bosch''s ICE powertrain revenue runway by an estimated 3-5 years beyond what a pure EV transition scenario would imply, protecting a significant portion of its â‚¹8,000+ Crore India revenue base.', NULL, 'escalating', 'short', '{"2W": "H", "3W": "M", "HCV": "L", "LCV": "M", "4W_PV": "H", "Tractor": "H"}', '["Infotainment", "Motion", "Services"]', '{}', false, '2026-04-09 11:49:28.361005+05:30', '2026-03-16 23:47:58.163502+05:30', '2026-03-16 23:47:58.163502+05:30', true, 'UNVERIFIED', NULL, NULL, '{}', '{}', '[]', '2026-03-16 23:47:58.163502+05:30', '2026-04-09 11:49:28.361005+05:30', 1); ON CONFLICT DO NOTHING;
INSERT INTO public.pestel_factors (id, code, name, category, selection_reasoning, likelihood, likelihood_reasoning, impact, impact_reasoning, origin_date, trend, time_horizon, segment_relevance, affected_pillars, source_ids, is_active, last_refreshed, created_at, updated_at, is_foundational, verification_verdict, verification_source, verification_evidence, financial_context, key_dates, citations, first_seen_date, last_confirmed_date, confirmation_count) VALUES (193, 'mahindra_r&d_intensification_â€”_1,334_patents_fy26', 'Mahindra R&D Intensification â€” 1,334 Patents FY26', 'T', 'Mahindra''s patent portfolio reaching 1,334 in FY26 â€” with 60% automotive and 40% farm equipment â€” signals a strategic shift toward proprietary technology development that reduces dependence on Tier-1 supplier-owned IP. As OEMs build internal technology moats, Tier-1 suppliers face increasing pressure to demonstrate differentiated IP rather than commodity manufacturing. This affects ADAS, EV powertrain, software, and tractor technology pillars where Mahindra is most active.', 9, 'The patent count is a disclosed, verifiable FY26 figure from Mahindra''s own communications. The trend of OEM in-house R&D intensification is well-established globally and Mahindra''s trajectory (from ~800 patents in FY23 to 1,334 in FY26) confirms acceleration. This is a confirmed, ongoing trend rather than a forecast.', 6, 'OEM IP accumulation in automotive (60% of 1,334 patents) and farm equipment (40%) directly pressures Tier-1 suppliers'' technology differentiation strategy. Suppliers risk commoditisation in areas where Mahindra develops proprietary solutions â€” particularly EV powertrain, ADAS, and precision agriculture. However, Mahindra''s scale still requires Tier-1 manufacturing partnerships, limiting the near-term displacement risk.', NULL, 'escalating', 'medium', '{"2W": "L", "3W": "L", "HCV": "M", "LCV": "M", "4W_PV": "H", "Tractor": "H"}', '["Compute", "Energy", "OS", "Motion"]', '{}', true, '2026-04-24 16:06:25.016681+05:30', '2026-04-24 16:06:25.016681+05:30', '2026-04-24 16:06:25.016681+05:30', false, 'UNVERIFIED', '', '', '{"market_opportunity": "N/A", "industry_investment": "Mahindra R&D spend estimated at â‚¹2,500-3,000 Cr annually (Estimate based on: ~3-4% of revenue, consistent with disclosed R&D intensity)", "subsidy_or_incentive": "PLI scheme R&D incentives available for EV-related patents", "government_investment": "N/A", "cost_impact_per_vehicle": "N/A"}', '{"announced": "2026-04", "effective": "2025-04", "completion": ""}', '[{"url": "https://auto.economictimes.indiatimes.com/news/passenger-vehicle/mahindra-mahindra-boosts-patent-portfolio-to-1334-in-fy26-a-significant-rd-investment/130466456", "claim": "Mahindra & Mahindra patent count rises to 1,334 in FY26 in major R&D push", "source": "ET Auto, 23 Apr 2026"}, {"url": "https://auto.economictimes.indiatimes.com/news/passenger-vehicle/mahindra-mahindra-boosts-patent-portfolio-to-1334-in-fy26-a-significant-rd-investment/130466456", "claim": "Of the total granted patents, 60 per cent relate to the automotive business, while 40 per cent are linked to the farm business", "source": "ET Auto, 23 Apr 2026"}]', '2026-04-24 16:06:25.016681+05:30', '2026-04-24 16:06:25.016681+05:30', 1); ON CONFLICT DO NOTHING;
INSERT INTO public.pestel_factors (id, code, name, category, selection_reasoning, likelihood, likelihood_reasoning, impact, impact_reasoning, origin_date, trend, time_horizon, segment_relevance, affected_pillars, source_ids, is_active, last_refreshed, created_at, updated_at, is_foundational, verification_verdict, verification_source, verification_evidence, financial_context, key_dates, citations, first_seen_date, last_confirmed_date, confirmation_count) VALUES (199, 'indian_oem_brand_globalisation_â€”_tier_1_export_pul', 'Indian OEM Brand Globalisation â€” Tier-1 Export Pull Effect', 'E', 'Eight Indian automotive brands â€” including Mahindra (25th globally), Royal Enfield, Tata Motors, Bajaj Auto, Hero, TVS, and Ashok Leyland â€” appearing in Brand Finance''s global top 100 signals that Indian OEMs are building genuine global brand equity, not just volume. This directly translates into export-linked component demand as these OEMs expand international production and sourcing, creating a structural pull for India-based Tier-1 suppliers to follow their OEM customers into global markets.', 8, 'Brand Finance rankings are independently verified and the multi-OEM breadth (8 brands across 2W, 4W PV, and CV segments) confirms this is a systemic trend rather than a single-OEM outlier. Mahindra''s global SUV expansion and Bajaj/TVS export strategies provide concrete commercial evidence supporting the brand data.', 6, 'Global brand strength enables Indian OEMs to command premium pricing internationally, which in turn supports higher-specification component sourcing from domestic Tier-1 suppliers. India auto component exports already stand at $22.9B (FY2025, ACMA); OEM brand globalisation could accelerate this toward the $30B+ range by FY28 (estimate), with safety, electronics, and powertrain components as primary beneficiaries.', NULL, 'escalating', 'medium', '{"2W": "H", "3W": "L", "HCV": "M", "LCV": "M", "4W_PV": "H", "Tractor": "L"}', '["Infotainment", "Motion", "Services", "ADAS"]', '{}', false, '2026-04-27 16:36:33.619882+05:30', '2026-04-27 16:36:33.619882+05:30', '2026-04-27 16:36:33.619882+05:30', false, 'UNVERIFIED', '', '', '{"market_opportunity": "India auto component exports $22.9B (FY2025); potential $30â€“35B by FY28 (Estimate based on OEM export trajectory)", "industry_investment": "Mahindra South Africa plant, Bajaj export network, TVS global expansion â€” combined estimated â‚¹5,000â€“8,000 Cr (Estimate)", "subsidy_or_incentive": "PLI Auto export incentives; Production Linked Incentive for advanced auto components", "government_investment": "N/A", "cost_impact_per_vehicle": "N/A"}', '{"announced": "2026-04", "effective": "2026-04", "completion": "2030-03"}', '[{"url": "https://auto.economictimes.indiatimes.com/news/industry/mahindras-rise-to-25th-among-global-automakers-india-dominates-brand-finance-top-100/130509945", "claim": "Royal Enfield, Tata Motors, Mahindra among 8 Indian firms in Brand Finance''s global top 100 list; Mahindra rises to 25th among global automakers", "source": "ET Auto, 25 Apr 2026"}, {"claim": "India auto component exports reached $22.9B in FY2025, up 8% YoY", "source": "ACMA FY2025 Annual Report"}]', '2026-04-27 16:36:33.619882+05:30', '2026-04-27 16:36:33.619882+05:30', 1); ON CONFLICT DO NOTHING;
INSERT INTO public.pestel_factors (id, code, name, category, selection_reasoning, likelihood, likelihood_reasoning, impact, impact_reasoning, origin_date, trend, time_horizon, segment_relevance, affected_pillars, source_ids, is_active, last_refreshed, created_at, updated_at, is_foundational, verification_verdict, verification_source, verification_evidence, financial_context, key_dates, citations, first_seen_date, last_confirmed_date, confirmation_count) VALUES (200, 'mercedes_cla_bev_â‚¹55l_â€”_premium_bev_demand_inflect', 'Mercedes CLA BEV â‚¹55L â€” Premium BEV Demand Inflection in 4W PV', 'E', 'Mercedes-Benz India''s CLA BEV selling out through August 2026 at â‚¹55 lakh, with 60% first-time luxury buyers under 35, signals a structural demand inflection in premium BEV â€” not a niche experiment. This validates a high-willingness-to-pay BEV customer segment in India and creates demand for premium EV powertrain, thermal management, ADAS, and infotainment components at specifications well above mass-market EV platforms.', 9, 'Sold-out order books through August 2026 are a confirmed commercial fact reported by ET Auto, not a projection. The 60% first-time luxury buyer statistic indicates demand is coming from a new, expanding cohort rather than conquest from existing luxury ICE buyers, suggesting durable demand expansion.', 6, 'While absolute volumes are modest (estimated 2,000â€“4,000 units annually for CLA BEV in India), the strategic significance lies in validating premium BEV price points and accelerating OEM confidence in India''s BEV market. This pulls forward investment in high-specification EV component supply chains. Per-vehicle electronics and EV powertrain BOM at this segment is estimated â‚¹3.5â€“5L, creating disproportionate revenue per unit for Tier-1 suppliers.', NULL, 'escalating', 'short', '{"2W": "L", "3W": "L", "HCV": "L", "LCV": "L", "4W_PV": "H", "Tractor": "L"}', '["Infotainment", "Energy", "Motion", "ADAS"]', '{}', false, '2026-04-27 16:36:33.619882+05:30', '2026-04-27 16:36:33.619882+05:30', '2026-04-27 16:36:33.619882+05:30', false, 'UNVERIFIED', '', '', '{"market_opportunity": "Premium BEV segment (â‚¹40L+) estimated â‚¹2,000â€“3,500 Cr by FY27 (Estimate based on 4,000â€“7,000 units at â‚¹50â€“70L ASP)", "industry_investment": "Mercedes-Benz India CLA BEV localisation investment â€” undisclosed", "subsidy_or_incentive": "Reduced import duty on CBU EVs (15% vs 100% standard) for OEMs committing to local manufacturing", "government_investment": "N/A", "cost_impact_per_vehicle": "EV powertrain + ADAS BOM at premium segment estimated â‚¹3.5â€“5L per vehicle (Estimate)"}', '{"announced": "2026-04", "effective": "2026-04", "completion": "2026-08"}', '[{"url": "https://auto.economictimes.indiatimes.com/news/passenger-vehicle/mercedes-benz-india-launches-all-electric-cla-bev-targeting-young-luxury-car-buyers/130498660", "claim": "Mercedes-Benz India CLA BEV priced at â‚¹55 lakh; initial India allocations completely sold out till August 2026; almost 60% of early CLA EV customers are first-time luxury car buyers", "source": "ET Auto, 24 Apr 2026"}]', '2026-04-27 16:36:33.619882+05:30', '2026-04-27 16:36:33.619882+05:30', 1); ON CONFLICT DO NOTHING;
INSERT INTO public.pestel_factors (id, code, name, category, selection_reasoning, likelihood, likelihood_reasoning, impact, impact_reasoning, origin_date, trend, time_horizon, segment_relevance, affected_pillars, source_ids, is_active, last_refreshed, created_at, updated_at, is_foundational, verification_verdict, verification_source, verification_evidence, financial_context, key_dates, citations, first_seen_date, last_confirmed_date, confirmation_count) VALUES (201, 'delhi_ev_policy_2026_â€”_battery_lifecycle_&_chargin', 'Delhi EV Policy 2026 â€” Battery Lifecycle & Charging Infrastructure Mandate', 'P', 'Delhi''s draft EV Policy 2026, which introduces structured battery lifecycle management mechanisms and integrates EV policy with solar policy and residential/public charging infrastructure, creates regulatory demand for battery management systems, second-life battery solutions, and EVSE components. As India''s largest urban EV market, Delhi policy frameworks typically precede national adoption, making this a leading indicator for Tier-1 BMS and EVSE suppliers.', 8, 'The stakeholder consultation stage reported by ET Auto indicates the policy is in active formulation with Transport Minister-level engagement, not merely a concept paper. Delhi''s track record of implementing EV mandates (ICE 2W ban 2028 already tracked) supports high likelihood of formal policy enactment within 12 months.', 6, 'Battery lifecycle management mandates create demand for second-life BMS, battery health monitoring, and recycling-linked diagnostics components. Delhi''s 4W EV fleet (estimated 80,000â€“100,000 units by end-2026) and 3W EV dominance (55% share nationally) make this a material demand signal. If replicated nationally, the battery lifecycle management market could reach â‚¹2,000â€“4,000 Cr by FY28 (estimate).', NULL, 'new', 'short', '{"2W": "M", "3W": "H", "HCV": "L", "LCV": "M", "4W_PV": "H", "Tractor": "L"}', '["Infotainment", "Energy", "OS"]', '{}', false, '2026-04-27 16:36:33.619882+05:30', '2026-04-27 16:36:33.619882+05:30', '2026-04-27 16:36:33.619882+05:30', false, 'UNVERIFIED', '', '', '{"market_opportunity": "Battery lifecycle management + EVSE market in Delhi estimated â‚¹500â€“1,000 Cr by FY27; national replication â‚¹2,000â€“4,000 Cr by FY28 (Estimate)", "industry_investment": "N/A", "subsidy_or_incentive": "Delhi EV Policy 2026 expected to include purchase incentives, charging infrastructure subsidies, and battery lifecycle compliance mandates", "government_investment": "Delhi EV Policy 2026 budget allocation â€” undisclosed at consultation stage", "cost_impact_per_vehicle": "Battery lifecycle compliance systems estimated â‚¹3,000â€“8,000 per EV (Estimate)"}', '{"announced": "2026-04", "effective": "2026-12", "completion": "2027-12"}', '[{"url": "https://auto.economictimes.indiatimes.com/news/auto-technology/delhi-government-pursues-battery-lifecycle-management-under-ev-policy-2026/130509495", "claim": "Delhi government pursues battery lifecycle management under EV Policy 2026; stakeholder consultation included suggestions to integrate EV policy with Delhi''s Solar Policy and strengthen residential and public charging infrastructure", "source": "ET Auto, 25 Apr 2026"}]', '2026-04-27 16:36:33.619882+05:30', '2026-04-27 16:36:33.619882+05:30', 1); ON CONFLICT DO NOTHING;
INSERT INTO public.pestel_factors (id, code, name, category, selection_reasoning, likelihood, likelihood_reasoning, impact, impact_reasoning, origin_date, trend, time_horizon, segment_relevance, affected_pillars, source_ids, is_active, last_refreshed, created_at, updated_at, is_foundational, verification_verdict, verification_source, verification_evidence, financial_context, key_dates, citations, first_seen_date, last_confirmed_date, confirmation_count) VALUES (202, 'catl_shenxing_3_â€”_6.5_minute_fast_charge_battery_â€”', 'CATL Shenxing 3 â€” 6.5-Minute Fast Charge Battery â€” India BMS & Thermal Disruption Risk', 'T', 'CATL''s Shenxing 3 battery achieving 10%â€“98% charge in 6.5 minutes at normal temperatures represents a step-change in EV charging technology that will cascade into India''s EV ecosystem within 2â€“3 years. For Tier-1 suppliers, this creates urgent demand for next-generation battery management systems (BMS) capable of handling extreme charge rates, advanced thermal management to prevent cell degradation, and upgraded EVSE infrastructure â€” all while threatening existing BMS and thermal management product roadmaps.', 7, 'CATL''s Shenxing 3 is a confirmed product launch, not a concept. However, India-specific adoption depends on OEM platform decisions, battery import/localisation economics, and EVSE infrastructure readiness for ultra-fast charging. A 2â€“3 year lag before meaningful India penetration is realistic, moderating immediate likelihood.', 8, 'Ultra-fast charging fundamentally alters the BMS architecture (higher C-rate management, cell balancing at extreme speeds), thermal management requirements (active liquid cooling becomes mandatory), and EVSE specifications (350kW+ DC fast chargers). Existing BMS and thermal management product lines designed for 30â€“60 minute charging cycles face obsolescence risk. The India EVSE market is projected to grow significantly under FAME III; ultra-fast charging infrastructure could require â‚¹500â€“1,000 Cr in upgraded equipment (estimate).', NULL, 'new', 'medium', '{"2W": "M", "3W": "L", "HCV": "M", "LCV": "M", "4W_PV": "H", "Tractor": "L"}', '["Energy", "OS"]', '{}', false, '2026-04-27 16:36:33.619882+05:30', '2026-04-27 16:36:33.619882+05:30', '2026-04-27 16:36:33.619882+05:30', false, 'UNVERIFIED', '', '', '{"market_opportunity": "Next-gen BMS and thermal management for ultra-fast charging in India estimated â‚¹1,500â€“3,000 Cr by FY29 (Estimate)", "industry_investment": "CATL global R&D investment in Shenxing 3 â€” undisclosed; India EVSE upgrade capex estimated â‚¹500â€“1,000 Cr by FY28 (Estimate)", "subsidy_or_incentive": "PLI for Advanced Chemistry Cell (ACC) batteries â€” â‚¹18,100 Cr approved; ultra-fast cell chemistry may qualify", "government_investment": "FAME III â‚¹2,671 Cr for EV charging â€” existing; ultra-fast charging may require additional allocation", "cost_impact_per_vehicle": "Advanced BMS + active thermal management for ultra-fast charging adds estimated â‚¹15,000â€“25,000 per EV vs standard BMS (Estimate)"}', '{"announced": "2026-04", "effective": "2026-04", "completion": "2029-12"}', '[{"url": "https://www.team-bhp.com/forum/electric-cars/307769-catl-launches-new-ev-battery-can-charge-10-98-6-5-minutes-new", "claim": "CATL launches Shenxing 3 battery that can charge from 10% to 98% in 6.5 minutes under normal temperatures", "source": "Team-BHP Auto News, 27 Apr 2026"}]', '2026-04-27 16:36:33.619882+05:30', '2026-04-27 16:36:33.619882+05:30', 1); ON CONFLICT DO NOTHING;
INSERT INTO public.pestel_factors (id, code, name, category, selection_reasoning, likelihood, likelihood_reasoning, impact, impact_reasoning, origin_date, trend, time_horizon, segment_relevance, affected_pillars, source_ids, is_active, last_refreshed, created_at, updated_at, is_foundational, verification_verdict, verification_source, verification_evidence, financial_context, key_dates, citations, first_seen_date, last_confirmed_date, confirmation_count) VALUES (203, '2w_motorsport_&_tech_integration_trend_â€”_premium_h', '2W Motorsport & Tech Integration Trend â€” Premium Helmet & Safety Accessory Premiumisation', 'S', 'Studds'' pivot to experience-led helmet design with tech integration (connectivity, sensors) and motorsport brand-building via SMK in Moto4 racing reflects a broader premiumisation trend in 2W safety accessories. This creates demand for electronics integration in helmets (sensors, connectivity modules) and signals rising consumer willingness to pay for safety-tech products in the 2W segment â€” a direct opportunity for Tier-1 suppliers in body electronics and safety systems.', 6, 'The Studds strategy is confirmed but represents a niche segment within the broader 2W market of 1.96 crore units. Consumer adoption of tech-integrated helmets at premium price points in India''s price-sensitive 2W market will be gradual, limiting near-term volume impact. The motorsport push is a 2â€“3 year brand-building exercise.', 4, 'The direct component opportunity is modest â€” tech-integrated helmets represent a small fraction of total 2W safety accessory spend. However, the strategic signal is meaningful: as 2W premiumisation accelerates (Royal Enfield, TVS Apache, Bajaj Pulsar 400 segment growth), demand for integrated safety electronics in the 2W ecosystem will expand. The addressable market for smart helmet electronics in India is estimated at â‚¹200â€“500 Cr by FY28 (estimate).', NULL, 'new', 'medium', '{"2W": "H", "3W": "L", "HCV": "L", "LCV": "L", "4W_PV": "L", "Tractor": "L"}', '["Infotainment", "Services", "ADAS"]', '{}', false, '2026-04-27 16:36:33.619882+05:30', '2026-04-27 16:36:33.619882+05:30', '2026-04-27 16:36:33.619882+05:30', false, 'UNVERIFIED', '', '', '{"market_opportunity": "Smart helmet and 2W safety electronics market in India estimated â‚¹200â€“500 Cr by FY28 (Estimate)", "industry_investment": "Studds motorsport and tech integration investment â€” undisclosed; estimated â‚¹50â€“100 Cr over 3 years (Estimate)", "subsidy_or_incentive": "N/A", "government_investment": "N/A", "cost_impact_per_vehicle": "Tech-integrated helmet adds â‚¹2,000â€“8,000 per unit vs standard helmet (Estimate)"}', '{"announced": "2026-04", "effective": "2026-04", "completion": "2028-12"}', '[{"url": "https://auto.economictimes.indiatimes.com/news/industry/studds-accessories-reimagines-helmet-design-with-focus-on-rider-experience-and-technology/130527865", "claim": "Studds shifts focus to experience-led helmet design and tech integration; firm increasing involvement in motorsports through SMK brand in Moto4 racing in Latin America, plans to move into higher categories over next 2â€“3 years", "source": "ET Auto, 26 Apr 2026"}, {"url": "https://www.team-bhp.com/forum/indian-motorsport/307770-fmsci-homologates-tvs-ntorq-150-motorsport-use-new-post.html", "claim": "FMSCI homologates TVS NTorq 150 for motorsport use in India", "source": "Team-BHP Auto News, 27 Apr 2026"}]', '2026-04-27 16:36:33.619882+05:30', '2026-04-27 16:36:33.619882+05:30', 1); ON CONFLICT DO NOTHING;
INSERT INTO public.pestel_factors (id, code, name, category, selection_reasoning, likelihood, likelihood_reasoning, impact, impact_reasoning, origin_date, trend, time_horizon, segment_relevance, affected_pillars, source_ids, is_active, last_refreshed, created_at, updated_at, is_foundational, verification_verdict, verification_source, verification_evidence, financial_context, key_dates, citations, first_seen_date, last_confirmed_date, confirmation_count) VALUES (204, 'tvs_jupiter_90_lakh_units_â€”_ice_scooter_volume_res', 'TVS Jupiter 90 Lakh Units â€” ICE Scooter Volume Resilience Signal', 'E', 'TVS Jupiter crossing 90 lakh cumulative domestic sales since 2013 confirms that the mass-market ICE scooter segment retains substantial volume momentum despite EV penetration growth. For Tier-1 suppliers, this validates continued investment in ICE 2W powertrain, body electronics, and OBD-II compliance components for the scooter sub-segment, which represents a significant portion of the 1.96 crore 2W market.', 9, 'The 90 lakh milestone is a confirmed sales achievement, not a projection. TVS Jupiter''s consistent volume trajectory and its position as TVS''s highest-volume scooter provide strong evidence of sustained ICE scooter demand in the â‚¹70,000â€“90,000 price band where EV alternatives remain price-disadvantaged.', 5, 'The signal reinforces that ICE 2W component demand will not collapse in the near term, providing revenue visibility for suppliers serving this segment. However, the strategic implication is primarily defensive â€” it confirms existing demand rather than creating new opportunity. The 2W ICE component market is estimated at â‚¹25,000â€“35,000 Cr annually (estimate based on 1.96 crore units Ã— â‚¹12,000â€“18,000 average ICE component content).', NULL, 'stable', 'short', '{"2W": "H", "3W": "L", "HCV": "L", "LCV": "L", "4W_PV": "L", "Tractor": "L"}', '["Infotainment", "Motion", "Services"]', '{}', false, '2026-04-27 16:36:33.619882+05:30', '2026-04-27 16:36:33.619882+05:30', '2026-04-27 16:36:33.619882+05:30', false, 'UNVERIFIED', '', '', '{"market_opportunity": "ICE 2W component market estimated â‚¹25,000â€“35,000 Cr annually (Estimate based on 1.96 crore units)", "industry_investment": "TVS Motor Company 2W capacity expansion â€” estimated â‚¹1,000â€“1,500 Cr annually (Estimate)", "subsidy_or_incentive": "N/A", "government_investment": "N/A", "cost_impact_per_vehicle": "N/A"}', '{"announced": "2026-04", "effective": "2026-04", "completion": ""}', '[{"url": "https://www.team-bhp.com/forum/motorbikes/307778-tvs-jupiter-crosses-90-lakh-domestic-sales-new-post.html", "claim": "TVS Jupiter crosses 90 lakh domestic sales since its launch in 2013; Jupiter is the most popular scooter in TVS''s lineup", "source": "Team-BHP Auto News, 27 Apr 2026"}, {"claim": "2-Wheeler segment FY25 units: 1.96 Crore, YoY growth +9%", "source": "SIAM FY2025 verified data"}]', '2026-04-27 16:36:33.619882+05:30', '2026-04-27 16:36:33.619882+05:30', 1); ON CONFLICT DO NOTHING;
INSERT INTO public.pestel_factors (id, code, name, category, selection_reasoning, likelihood, likelihood_reasoning, impact, impact_reasoning, origin_date, trend, time_horizon, segment_relevance, affected_pillars, source_ids, is_active, last_refreshed, created_at, updated_at, is_foundational, verification_verdict, verification_source, verification_evidence, financial_context, key_dates, citations, first_seen_date, last_confirmed_date, confirmation_count) VALUES (205, 'gadkari_public_transport_fossil_fuel_exit_â€”_alt_fu', 'Gadkari Public Transport Fossil Fuel Exit â€” Alt-Fuel Bus Mandate Signal', 'P', 'The Union Minister''s declaration that petrol and diesel have no future in India''s public transport â€” urging rapid adoption of hydrogen, ethanol, CNG, and electric mobility â€” constitutes a high-credibility policy signal that will shape HCV and LCV bus procurement mandates. This directly impacts powertrain solutions, thermal management, energy & charging, and safety pillars for bus-segment suppliers. Given Gadkari''s track record of converting ministerial statements into regulatory action (AEBS, AEB mandates), Tier-1 suppliers must treat this as a leading indicator of forthcoming procurement policy.', 8, 'Gadkari has a demonstrated history of translating public statements into enforceable mandates â€” AEBS for HCV and AEB for 4W PV both followed similar ministerial declarations. State transport undertakings (STUs) are already procuring e-buses under FAME III, and the Centre''s PM e-Bus Sewa scheme has committed to 10,000 electric buses. The multi-fuel framing (hydrogen, ethanol, CNG, EV) reduces the risk of a single-technology policy failure.', 8, 'India''s public bus fleet exceeds 1.5 million units; even a 20% electrification/alt-fuel conversion over five years represents 300,000 units requiring entirely new powertrain, thermal, and charging infrastructure. For Tier-1 suppliers, this opens a multi-pillar opportunity estimated at â‚¹15,000â€“20,000 Cr in addressable component content over FY27â€“FY31. ICE powertrain suppliers to the bus segment face accelerated obsolescence risk.', NULL, 'escalating', 'medium', '{"2W": "L", "3W": "M", "HCV": "H", "LCV": "H", "4W_PV": "L", "Tractor": "L"}', '["Infotainment", "Energy", "Motion", "ADAS"]', '{}', false, '2026-04-29 10:51:11.144112+05:30', '2026-04-29 10:51:11.144112+05:30', '2026-04-29 10:51:11.144112+05:30', false, 'UNVERIFIED', '', '', '{"market_opportunity": "Estimate based on: 300,000 alt-fuel bus conversions Ã— â‚¹5â€“7L incremental component content = â‚¹15,000â€“21,000 Cr over FY27â€“31", "industry_investment": "N/A", "subsidy_or_incentive": "FAME III subsidies for electric buses; potential CNG/hydrogen procurement mandates for STUs", "government_investment": "â‚¹2,671 Cr (FAME III EV charging); PM e-Bus Sewa 10,000 buses", "cost_impact_per_vehicle": "Estimate based on: EV powertrain adds â‚¹8â€“12L per bus vs ICE baseline"}', '{"announced": "2026-04", "effective": "", "completion": "2030-12"}', '[{"url": "https://auto.economictimes.indiatimes.com/news/commercial-vehicle/nitin-gadkari-declares-no-future-for-petrol-and-diesel-in-indian-public-transport/130545542", "claim": "Union Minister Nitin Gadkari urged bus makers and operators to rapidly shift towards alternative fuels such as hydrogen, ethanol, CNG and electric mobility, declaring no future for petrol and diesel in India''s public transport", "source": "ET Auto, 28 Apr 2026"}]', '2026-04-29 10:51:11.144112+05:30', '2026-04-29 10:51:11.144112+05:30', 1); ON CONFLICT DO NOTHING;
INSERT INTO public.pestel_factors (id, code, name, category, selection_reasoning, likelihood, likelihood_reasoning, impact, impact_reasoning, origin_date, trend, time_horizon, segment_relevance, affected_pillars, source_ids, is_active, last_refreshed, created_at, updated_at, is_foundational, verification_verdict, verification_source, verification_evidence, financial_context, key_dates, citations, first_seen_date, last_confirmed_date, confirmation_count) VALUES (206, 'saic_jsw_china_ev_technology_entry_â€”_competitive_d', 'SAIC-JSW China EV Technology Entry â€” Competitive Disruption in 4W PV', 'E', 'SAIC Motor''s global EV expansion strategy, channelled through JSW Group in India, introduces Chinese EV technology platforms and supply chain preferences into the Indian 4W PV market. JSW Motors'' planned PHEV debut and company-owned experience centres signal a serious market entry, not a token presence. This creates both a threat (SAIC''s established Chinese Tier-1 supply chain may bypass Indian suppliers) and an opportunity (JSW''s India manufacturing ambitions require local component sourcing for PLI and FTA compliance). The combined SAIC-JSW entity represents a new OEM demand node that Tier-1 suppliers must qualify for.', 8, 'JSW Motors has confirmed plans for company-owned experience centres ahead of its first vehicle launch, reported as an upscale PHEV. SAIC''s global EV strategy is well-funded and India is explicitly identified as a target market. JSW Group''s industrial scale and financial resources reduce execution risk significantly.', 7, 'A new OEM entering the 4W PV segment with PHEV technology creates demand for hybrid powertrain components, battery management systems, and infotainment platforms. However, SAIC''s preference for Chinese Tier-1 suppliers (CATL for batteries, Huawei for infotainment) poses a localisation risk. If JSW-SAIC sources 40â€“50% of components from China (minimum for FTA rules of origin), the incremental opportunity for Indian Tier-1 suppliers is â‚¹3,000â€“5,000 Cr over FY27â€“FY30.', NULL, 'escalating', 'short', '{"2W": "L", "3W": "L", "HCV": "L", "LCV": "L", "4W_PV": "H", "Tractor": "L"}', '["Energy", "Motion", "Infotainment", "OS"]', '{}', false, '2026-04-29 10:51:11.144112+05:30', '2026-04-29 10:51:11.144112+05:30', '2026-04-29 10:51:11.144112+05:30', false, 'UNVERIFIED', '', '', '{"market_opportunity": "Estimate based on: New OEM entry targeting premium PHEV segment; â‚¹3,000â€“5,000 Cr component opportunity for Indian Tier-1s over FY27â€“30 if localisation targets met", "industry_investment": "N/A â€” JSW Motors capex not yet publicly disclosed; JSW Group has significant balance sheet capacity", "subsidy_or_incentive": "PLI scheme available if JSW-SAIC meets revenue/asset thresholds; India-EU FTA may incentivise India-manufactured exports", "government_investment": "N/A", "cost_impact_per_vehicle": "N/A"}', '{"announced": "2026-04", "effective": "", "completion": "2030-12"}', '[{"url": "https://auto.economictimes.indiatimes.com/news/passenger-vehicle/jsw-motors-to-launch-company-owned-experience-centres-ahead-of-first-vehicle-release/130547965", "claim": "JSW Motors plans company-owned experience centres ahead of first vehicle launch; debut product expected to be an upscale plug-in hybrid model", "source": "ET Auto, 27 Apr 2026"}, {"url": "https://auto.economictimes.indiatimes.com/news/passenger-vehicle/saic-motors-global-ev-strategy-leading-the-charge-in-emerging-markets/130574176", "claim": "SAIC Motor is preparing to reach out to consumers in domestic and overseas markets between now and 2030; JSW Group is poised to take the India growth story forward", "source": "ET Auto, 28 Apr 2026"}]', '2026-04-29 10:51:11.144112+05:30', '2026-04-29 10:51:11.144112+05:30', 1); ON CONFLICT DO NOTHING;
INSERT INTO public.pestel_factors (id, code, name, category, selection_reasoning, likelihood, likelihood_reasoning, impact, impact_reasoning, origin_date, trend, time_horizon, segment_relevance, affected_pillars, source_ids, is_active, last_refreshed, created_at, updated_at, is_foundational, verification_verdict, verification_source, verification_evidence, financial_context, key_dates, citations, first_seen_date, last_confirmed_date, confirmation_count) VALUES (207, 'renault_chennai_global_hub_â€”_export_oriented_compo', 'Renault Chennai Global Hub â€” Export-Oriented Component Sourcing Scale-Up', 'E', 'Renault''s renewed strategic focus on Chennai as a nerve centre for its global strategy â€” representing a turning point in its 15-year India journey â€” signals a potential large-scale export-oriented manufacturing ramp that would significantly expand component sourcing from Indian Tier-1 suppliers. Unlike domestic-focused OEM expansions, a global hub strategy implies compliance with international quality standards (Euro 7, global NCAP), creating demand for higher-specification components across powertrain, safety, and electronics pillars. This is a distinct factor from the existing ''Renault Duster relaunch'' entry, which focuses on domestic volume recovery.', 7, 'Renault''s Chennai plant has existing infrastructure and the OEM has explicitly signalled a strategic pivot. However, Renault''s India history includes significant setbacks (Zoe EV withdrawal, Captur failure), and global hub status requires sustained investment and product pipeline commitment. The 7-score reflects genuine strategic intent tempered by execution uncertainty.', 7, 'A Renault global hub at Chennai could generate 200,000â€“400,000 units of export-oriented production annually, with component sourcing of â‚¹15,000â€“25,000 Cr per year at full scale. For Tier-1 suppliers, this represents qualification opportunities for global supply chains with Euro 7 and global NCAP-compliant specifications, which also upgrades their capability for other export mandates.', NULL, 'escalating', 'medium', '{"2W": "L", "3W": "L", "HCV": "L", "LCV": "M", "4W_PV": "H", "Tractor": "L"}', '["Compute", "ADAS", "Motion", "Infotainment"]', '{}', false, '2026-04-29 10:51:11.144112+05:30', '2026-04-29 10:51:11.144112+05:30', '2026-04-29 10:51:11.144112+05:30', false, 'UNVERIFIED', '', '', '{"market_opportunity": "Estimate based on: 300,000 units/year export production Ã— â‚¹6L avg component content = â‚¹18,000 Cr annual component sourcing opportunity", "industry_investment": "N/A â€” Renault India capex not yet publicly disclosed for this strategic pivot", "subsidy_or_incentive": "India-EU FTA enabling tariff-free exports to EU; PLI scheme for export-oriented auto manufacturing", "government_investment": "N/A", "cost_impact_per_vehicle": "N/A"}', '{"announced": "2026-04", "effective": "", "completion": "2030-12"}', '[{"url": "https://auto.economictimes.indiatimes.com/news/passenger-vehicle/chennai-key-hub-for-renaults-global-strategy-and-future-growth/130542341", "claim": "Chennai emerges as nerve centre of Renault''s global strategy, representing a turning point in Renault''s 15-year-old India journey", "source": "ET Auto, 27 Apr 2026"}]', '2026-04-29 10:51:11.144112+05:30', '2026-04-29 10:51:11.144112+05:30', 1); ON CONFLICT DO NOTHING;
INSERT INTO public.pestel_factors (id, code, name, category, selection_reasoning, likelihood, likelihood_reasoning, impact, impact_reasoning, origin_date, trend, time_horizon, segment_relevance, affected_pillars, source_ids, is_active, last_refreshed, created_at, updated_at, is_foundational, verification_verdict, verification_source, verification_evidence, financial_context, key_dates, citations, first_seen_date, last_confirmed_date, confirmation_count) VALUES (208, 'maruti_production_capacity_constraint_â€”_190,000_pe', 'Maruti Production Capacity Constraint â€” 190,000 Pending Orders Signal', 'E', 'Maruti''s 190,000 pending customer orders at FY26 year-end â€” with sales restricted by production capacity limitations â€” signals that demand is outpacing supply, creating a structural case for accelerated capacity expansion and, critically, for Tier-1 suppliers to pre-invest in capacity to avoid becoming the bottleneck. This is a distinct signal from the â‚¹14,000 Cr capex announcement: the pending orders quantify the demand gap and create urgency for supplier capacity alignment. Tier-1 suppliers that cannot scale with Maruti''s expansion risk losing preferred supplier status.', 9, 'The 190,000 pending orders is a reported, auditable figure from Maruti''s Q4 FY26 results. The capacity constraint is confirmed by management commentary. With â‚¹14,000 Cr capex committed for FY27, capacity expansion is underway, and supplier ramp-up requirements will follow within 12â€“18 months.', 6, '190,000 pending orders at an average revenue of ~â‚¹10L per vehicle represents â‚¹19,000 Cr in deferred revenue for Maruti â€” and proportional deferred component revenue for Tier-1 suppliers. The capacity constraint signal justifies pre-emptive supplier capex investment. However, the impact is bounded by Maruti''s single-OEM concentration risk for suppliers heavily dependent on this customer.', NULL, 'escalating', 'immediate', '{"2W": "L", "3W": "L", "HCV": "L", "LCV": "M", "4W_PV": "H", "Tractor": "L"}', '["Compute", "ADAS", "Motion", "Infotainment"]', '{}', false, '2026-04-29 10:51:11.144112+05:30', '2026-04-29 10:51:11.144112+05:30', '2026-04-29 10:51:11.144112+05:30', false, 'UNVERIFIED', '', '', '{"market_opportunity": "Estimate based on: 190,000 pending orders Ã— â‚¹10L avg vehicle price = â‚¹19,000 Cr deferred revenue; proportional component opportunity ~â‚¹5,700â€“7,600 Cr (30â€“40% component content ratio)", "industry_investment": "â‚¹14,000 Cr (Maruti FY27 capex to address capacity constraint)", "subsidy_or_incentive": "N/A", "government_investment": "N/A", "cost_impact_per_vehicle": "N/A"}', '{"announced": "2026-04", "effective": "", "completion": "2027-03"}', '[{"url": "https://auto.economictimes.indiatimes.com/news/passenger-vehicle/maruti-suzuki-reports-record-q4-revenue-of-500787-crore-despite-profit-decline/130577388", "claim": "Maruti achieved record volumes of 2.4 million units in FY26, with sales getting restricted by a limitation in production capacity leading to 190,000 pending customer orders by end of financial year", "source": "ET Auto, 28 Apr 2026"}]', '2026-04-29 10:51:11.144112+05:30', '2026-04-29 10:51:11.144112+05:30', 1); ON CONFLICT DO NOTHING;
INSERT INTO public.pestel_factors (id, code, name, category, selection_reasoning, likelihood, likelihood_reasoning, impact, impact_reasoning, origin_date, trend, time_horizon, segment_relevance, affected_pillars, source_ids, is_active, last_refreshed, created_at, updated_at, is_foundational, verification_verdict, verification_source, verification_evidence, financial_context, key_dates, citations, first_seen_date, last_confirmed_date, confirmation_count) VALUES (209, 'mhi_e_bus/e_truck_private_financing_mechanism_push', 'MHI E-Bus/E-Truck Private Financing Mechanism Push', 'P', 'The Ministry of Heavy Industries convening a high-level meeting on financing mechanisms for electric buses and trucks signals imminent policy action to de-risk private sector EV commercial vehicle adoption. This directly accelerates demand for EV powertrain, battery thermal management, and energy/charging infrastructure components across HCV and LCV segments. The ministerial-level attention suggests regulatory or financial instruments (guarantees, concessional lending) are being structured, creating a near-term procurement pipeline.', 8, 'A secretary-level meeting chaired by Kamran Rizvi with explicit financing agenda indicates advanced policy deliberation, not exploratory discussion. Gadkari''s concurrent declaration that petrol/diesel have no future in public transport reinforces political will. Likelihood of at least a pilot financing scheme being announced within 12 months is high.', 8, 'India''s e-bus and e-truck market is nascent; financing barriers are the primary adoption constraint. A structured government-backed financing mechanism could unlock 50,000â€“100,000 electric commercial vehicle units annually by FY28, representing a â‚¹15,000â€“25,000 Cr addressable component market for EV powertrain, BMS, and thermal systems. Tier-1 suppliers with CV EV powertrain readiness stand to capture significant first-mover content.', NULL, 'escalating', 'short', '{"2W": "L", "3W": "M", "HCV": "H", "LCV": "H", "4W_PV": "L", "Tractor": "L"}', '["Energy", "Infotainment"]', '{}', false, '2026-04-30 10:51:12.089668+05:30', '2026-04-30 10:51:12.089668+05:30', '2026-04-30 10:51:12.089668+05:30', false, 'UNVERIFIED', '', '', '{"market_opportunity": "Estimate based on: 50,000â€“100,000 e-CV units Ã— â‚¹25â€“50L EV component content per vehicle = â‚¹12,500â€“50,000 Cr cumulative by FY28", "industry_investment": "N/A", "subsidy_or_incentive": "Concessional financing / credit guarantee mechanism under MHI deliberation for private e-bus and e-truck buyers", "government_investment": "N/A (financing mechanism under discussion; no outlay announced yet)", "cost_impact_per_vehicle": "N/A"}', '{"announced": "2026-04", "effective": "", "completion": ""}', '[{"url": "https://auto.economictimes.indiatimes.com/news/commercial-vehicle/government-pushes-for-e-buses-and-e-trucks-financing-to-enhance-private-sector-adoption/130621437", "claim": "Ministry of Heavy Industries held a high-level meeting chaired by Secretary Kamran Rizvi to discuss financing mechanisms for accelerating adoption of electric buses and trucks in the private sector", "source": "ET Auto, 30 April 2026"}, {"url": "https://auto.economictimes.indiatimes.com/news/commercial-vehicle/nitin-gadkari-declares-no-future-for-petrol-and-diesel-in-indian-public-transport/130545542", "claim": "Nitin Gadkari declared petrol and diesel have no future in India''s public transport, urging bus makers to shift to hydrogen, ethanol, CNG and electric mobility", "source": "ET Auto, 28 April 2026"}]', '2026-04-30 10:51:12.089668+05:30', '2026-04-30 10:51:12.089668+05:30', 1); ON CONFLICT DO NOTHING;
INSERT INTO public.pestel_factors (id, code, name, category, selection_reasoning, likelihood, likelihood_reasoning, impact, impact_reasoning, origin_date, trend, time_horizon, segment_relevance, affected_pillars, source_ids, is_active, last_refreshed, created_at, updated_at, is_foundational, verification_verdict, verification_source, verification_evidence, financial_context, key_dates, citations, first_seen_date, last_confirmed_date, confirmation_count) VALUES (210, 'tata_motors_record_patent_filings_fy26_â€”_cv_ip_int', 'Tata Motors Record Patent Filings FY26 â€” CV IP Intensification', 'T', 'Tata Motors achieving record patent filings in FY26, with the largest single-year application count from its commercial vehicle division, signals a structural shift toward proprietary technology development in HCV/LCV segments. For Tier-1 suppliers, OEM IP intensification in CV technology (likely covering EV drivetrains, ADAS for trucks, connected fleet systems) creates dual risk: incumbent suppliers may find their technology solutions pre-empted by OEM-owned IP, while also signalling growing OEM appetite for co-development partnerships with suppliers who can contribute complementary IP.', 9, 'This is a confirmed, reported fact â€” Tata Motors has publicly disclosed record patent filings in FY26. The trend of Indian OEM IP intensification is corroborated by Mahindra''s 1,334 patents in FY26 (existing factor). The CV division focus is particularly significant given the AEBS mandate, e-bus/truck push, and hydrogen trials.', 6, 'OEM IP intensification in CV technology could displace â‚¹2,000â€“5,000 Cr of annual Tier-1 technology content if OEMs vertically integrate key systems (e.g., AEBS algorithms, fleet telematics platforms, EV battery management). However, the more likely near-term impact is increased co-development pressure on suppliers to contribute IP rather than supply commodity components, raising R&D cost requirements for Tier-1 CV suppliers by an estimated 15â€“25%.', NULL, 'escalating', 'medium', '{"2W": "L", "3W": "M", "HCV": "H", "LCV": "H", "4W_PV": "L", "Tractor": "L"}', '["Energy", "Motion", "Infotainment", "OS"]', '{}', false, '2026-04-30 10:51:12.089668+05:30', '2026-04-30 10:51:12.089668+05:30', '2026-04-30 10:51:12.089668+05:30', false, 'UNVERIFIED', '', '', '{"market_opportunity": "N/A", "industry_investment": "N/A", "subsidy_or_incentive": "N/A", "government_investment": "N/A", "cost_impact_per_vehicle": "Estimate based on: Tier-1 R&D cost increase of 15â€“25% for CV-focused suppliers to maintain co-development relevance vs. OEM IP expansion"}', '{"announced": "2026-04", "effective": "", "completion": ""}', '[{"url": "https://auto.economictimes.indiatimes.com/news/commercial-vehicle/tata-motors-achieves-record-patent-filings-in-fy26/130599644", "claim": "Tata Motors achieved record patent filings in FY26, representing the largest number of patent applications made by the company''s commercial vehicle division in a single financial year", "source": "ET Auto, 29 April 2026"}]', '2026-04-30 10:51:12.089668+05:30', '2026-04-30 10:51:12.089668+05:30', 1); ON CONFLICT DO NOTHING;
INSERT INTO public.pestel_factors (id, code, name, category, selection_reasoning, likelihood, likelihood_reasoning, impact, impact_reasoning, origin_date, trend, time_horizon, segment_relevance, affected_pillars, source_ids, is_active, last_refreshed, created_at, updated_at, is_foundational, verification_verdict, verification_source, verification_evidence, financial_context, key_dates, citations, first_seen_date, last_confirmed_date, confirmation_count) VALUES (211, 'saic_jsw_china_ev_platform_entry_â€”_chinese_technol', 'SAIC-JSW China EV Platform Entry â€” Chinese Technology Localisation Pressure', 'T', 'SAIC Motor''s global EV expansion strategy, with JSW Group positioned to take the India growth story forward, signals the entry of Chinese EV platform technology into India''s mainstream market. SAIC brings vertically integrated EV component ecosystems (battery, motor, inverter, BMS) that could either displace Indian Tier-1 suppliers or create localisation partnership opportunities. The JSW industrial group''s manufacturing capabilities add credibility to a serious localisation play, unlike pure import models.', 7, 'SAIC already has an established India presence through the Hector SUV (MG Motor). JSW Group''s backing provides financial and manufacturing infrastructure. However, geopolitical scrutiny of Chinese automotive investments in India (FDI restrictions requiring government approval for China-origin investments) introduces regulatory uncertainty that moderates the likelihood of rapid scale-up.', 7, 'If SAIC-JSW localises EV components in India, it could introduce Chinese-specification battery systems, motors, and inverters at 20â€“30% lower cost than current Indian Tier-1 pricing, compressing margins across the EV powertrain supply chain. Conversely, JSW''s localisation mandate could create â‚¹3,000â€“8,000 Cr in new Tier-1 supply opportunities for suppliers willing to co-develop with Chinese technology partners. The net impact depends on the localisation depth and FDI approval trajectory.', NULL, 'escalating', 'medium', '{"2W": "L", "3W": "L", "HCV": "L", "LCV": "L", "4W_PV": "H", "Tractor": "L"}', '["Compute", "Energy", "Infotainment"]', '{}', false, '2026-04-30 10:51:12.089668+05:30', '2026-04-30 10:51:12.089668+05:30', '2026-04-30 10:51:12.089668+05:30', false, 'UNVERIFIED', '', '', '{"market_opportunity": "Estimate based on: SAIC-JSW targeting 50,000â€“100,000 EV units by FY28 Ã— â‚¹8â€“12L localised component content per vehicle = â‚¹4,000â€“12,000 Cr supplier opportunity", "industry_investment": "N/A", "subsidy_or_incentive": "N/A", "government_investment": "N/A", "cost_impact_per_vehicle": "Estimate based on: Chinese EV platform components priced 20â€“30% below current Indian Tier-1 equivalents, implying â‚¹1.5â€“3L cost pressure per EV BOM"}', '{"announced": "2026-04", "effective": "", "completion": "2030-12"}', '[{"url": "https://auto.economictimes.indiatimes.com/news/passenger-vehicle/saic-motors-global-ev-strategy-leading-the-charge-in-emerging-markets/130574176", "claim": "SAIC Motor is preparing to reach out to consumers in domestic and overseas markets between now and 2030; it entered India with the Hector SUV and JSW Group is poised to take the growth story forward", "source": "ET Auto, 28 April 2026"}]', '2026-04-30 10:51:12.089668+05:30', '2026-04-30 10:51:12.089668+05:30', 1); ON CONFLICT DO NOTHING;
INSERT INTO public.pestel_factors (id, code, name, category, selection_reasoning, likelihood, likelihood_reasoning, impact, impact_reasoning, origin_date, trend, time_horizon, segment_relevance, affected_pillars, source_ids, is_active, last_refreshed, created_at, updated_at, is_foundational, verification_verdict, verification_source, verification_evidence, financial_context, key_dates, citations, first_seen_date, last_confirmed_date, confirmation_count) VALUES (212, 'yamaha_vehicle_leasing_arm_leadership_change_â€”_mob', 'Yamaha Vehicle Leasing Arm Leadership Change â€” Mobility-as-a-Service 2W Signal', 'S', 'The appointment of a banking professional with both business development and risk management expertise as MD of Yamaha''s vehicle leasing arm in India signals that Japanese 2W OEMs are institutionalising mobility-as-a-service (MaaS) and subscription/leasing models as a mainstream distribution channel. For Tier-1 suppliers, fleet-leased 2W vehicles have different component lifecycle, telematics, and diagnostic requirements compared to retail-sold units â€” creating demand for connected diagnostics, fleet management, and OTA-capable components even in the 2W segment.', 7, 'The appointment is confirmed and operational. Yamaha''s commitment to a dedicated leasing entity with professional leadership indicates a multi-year strategic bet, not an experiment. The gig economy''s demand for 2W fleet vehicles (delivery, ride-hailing) provides the demand foundation for this model to scale.', 4, 'The 2W leasing market is nascent in India, currently representing <2% of 2W sales. However, if fleet leasing reaches 5â€“8% of the 1.96 Crore annual 2W market by FY28, it creates a 10â€“16 Lakh unit fleet requiring telematics, remote diagnostics, and connected services â€” a â‚¹500â€“1,200 Cr incremental component opportunity. The impact is moderate given the long adoption timeline.', NULL, 'new', 'medium', '{"2W": "H", "3W": "M", "HCV": "L", "LCV": "L", "4W_PV": "L", "Tractor": "L"}', '["OS", "Infotainment", "Services"]', '{}', false, '2026-04-30 10:51:12.089668+05:30', '2026-04-30 10:51:12.089668+05:30', '2026-04-30 10:51:12.089668+05:30', false, 'UNVERIFIED', '', '', '{"market_opportunity": "Estimate based on: 10â€“16L fleet 2W units Ã— â‚¹3,000â€“8,000 telematics/diagnostics content per unit = â‚¹300â€“1,280 Cr by FY28", "industry_investment": "N/A", "subsidy_or_incentive": "N/A", "government_investment": "N/A", "cost_impact_per_vehicle": "Estimate based on: â‚¹3,000â€“8,000 incremental connected component content per fleet-leased 2W vs. retail unit"}', '{"announced": "2026-04", "effective": "2026-04", "completion": ""}', '[{"url": "https://auto.economictimes.indiatimes.com/news/industry/masaharu-kobayashi-to-take-over-as-new-md-of-yamahas-vehicle-leasing-arm-in-india/130601252", "claim": "Masaharu Kobayashi, having experienced both business development and risk management sides of banking, is set to take over as new MD of Yamaha''s vehicle leasing arm in India (MBSI)", "source": "ET Auto, 29 April 2026"}]', '2026-04-30 10:51:12.089668+05:30', '2026-04-30 10:51:12.089668+05:30', 1); ON CONFLICT DO NOTHING;
INSERT INTO public.pestel_factors (id, code, name, category, selection_reasoning, likelihood, likelihood_reasoning, impact, impact_reasoning, origin_date, trend, time_horizon, segment_relevance, affected_pillars, source_ids, is_active, last_refreshed, created_at, updated_at, is_foundational, verification_verdict, verification_source, verification_evidence, financial_context, key_dates, citations, first_seen_date, last_confirmed_date, confirmation_count) VALUES (213, 'hero_motocorp_&_greaves_cotton_cto_appointments_â€”_', 'Hero MotoCorp & Greaves Cotton CTO Appointments â€” 2W R&D Intensification', 'T', 'Simultaneous senior technology leadership appointments at Hero MotoCorp (Sachin Agrawal as CTO with 29 years of automotive R&D experience) and Greaves Cotton (Vinay Pawar as Group CTO with expertise in automotive electronics and connected mobility) signal accelerating technology transformation across both ICE-dominant and EV-focused 2W OEMs. For Tier-1 suppliers, this translates into faster technology procurement cycles, higher engineering content expectations, and potential shifts in supplier qualification criteria toward software and electronics competence.', 9, 'Both appointments are confirmed and effective, not speculative. Hero MotoCorp''s R&D transformation across India and Germany innovation centres and Greaves Cotton''s connected mobility focus are publicly stated strategic priorities, making technology procurement acceleration a near-certain consequence.', 6, 'Hero MotoCorp is the world''s largest 2W manufacturer by volume, and its technology direction sets procurement benchmarks for the entire 2W supplier ecosystem. Greaves Cotton''s EV and connected mobility focus affects the 3W and light EV segment supply chain. However, the impact is medium-term as new CTO strategies typically take 12-24 months to translate into supplier RFQs.', NULL, 'escalating', 'short', '{"2W": "H", "3W": "M", "HCV": "L", "LCV": "L", "4W_PV": "L", "Tractor": "L"}', '["Infotainment", "Motion", "OS", "Energy"]', '{}', false, '2026-05-05 10:20:34.765811+05:30', '2026-05-05 10:20:34.765811+05:30', '2026-05-05 10:20:34.765811+05:30', false, 'UNVERIFIED', '', '', '{"market_opportunity": "Estimate â‚¹3,500â€“5,000 Cr incremental electronics and software content opportunity in 2W segment by FY28 as OEMs upgrade technology stacks", "industry_investment": "N/A", "subsidy_or_incentive": "N/A", "government_investment": "N/A", "cost_impact_per_vehicle": "N/A"}', '{"announced": "2026-05", "effective": "2026-05", "completion": ""}', '[{"url": "https://auto.economictimes.indiatimes.com/news/two-wheelers/hero-motocorp-appoints-sachin-agrawal-as-chief-technology-officer/130765269", "claim": "Sachin Agrawal appointed as Hero MotoCorp CTO, bringing over 29 years of experience in automotive R&D and technology leadership, to spearhead R&D transformation across innovation centres in India and Germany", "source": "ET Auto, 04 May 2026"}, {"url": "https://auto.economictimes.indiatimes.com/news/auto-technology/greaves-cotton-appoints-vinay-pawar-as-group-cto/130803814", "claim": "Greaves Cotton appointed Vinay Pawar as Group CTO, bringing nearly three decades of experience in automotive electronics, industrial automation, and connected mobility", "source": "ET Auto, 04 May 2026"}]', '2026-05-05 10:20:34.765811+05:30', '2026-05-05 10:20:34.765811+05:30', 1); ON CONFLICT DO NOTHING;
INSERT INTO public.pestel_factors (id, code, name, category, selection_reasoning, likelihood, likelihood_reasoning, impact, impact_reasoning, origin_date, trend, time_horizon, segment_relevance, affected_pillars, source_ids, is_active, last_refreshed, created_at, updated_at, is_foundational, verification_verdict, verification_source, verification_evidence, financial_context, key_dates, citations, first_seen_date, last_confirmed_date, confirmation_count) VALUES (214, 'tata_mahindra_pv_market_share_surge_â€”_domestic_oem', 'Tata-Mahindra PV Market Share Surge â€” Domestic OEM Content Localisation Acceleration', 'E', 'Tata Motors and Mahindra gaining market share over Hyundai in CY2026 represents a structural shift in India''s PV OEM hierarchy with direct implications for Tier-1 supplier wallet share. Domestic OEMs typically carry higher localisation ratios (60-70% vs 40-55% for Korean/Japanese OEMs), meaning their volume growth disproportionately benefits India-based Tier-1 suppliers. This shift also accelerates EV content demand given Tata and Mahindra''s aggressive EV portfolios.', 8, 'The market share shift is already underway in CY2026 per ET Auto reporting, not a projection. Mahindra''s 1,334 patents in FY26 and Tata''s EV portfolio expansion provide structural competitive advantages that are unlikely to reverse quickly.', 7, 'Every percentage point of PV market share shift from Hyundai to Tata/Mahindra represents approximately 43,000 units annually (at 4.3M total PV market), with higher localisation content per vehicle. For Tier-1 suppliers, this could mean â‚¹500-800 Cr incremental annual revenue opportunity per 1% share shift, given higher domestic OEM localisation ratios.', NULL, 'escalating', 'short', '{"2W": "L", "3W": "L", "HCV": "L", "LCV": "M", "4W_PV": "H", "Tractor": "L"}', '["Infotainment", "Motion", "Energy"]', '{}', false, '2026-05-05 10:20:34.765811+05:30', '2026-05-05 10:20:34.765811+05:30', '2026-05-05 10:20:34.765811+05:30', false, 'UNVERIFIED', '', '', '{"market_opportunity": "Estimate â‚¹2,000â€“3,500 Cr incremental Tier-1 revenue opportunity from 2-3% domestic OEM share gain over FY26-27", "industry_investment": "Mahindra R&D: 1,334 patents filed FY26 (IBEF/ET Auto); Tata Motors EV portfolio expansion ongoing", "subsidy_or_incentive": "PLI scheme benefits domestic OEM-aligned suppliers; FAME III for EV models", "government_investment": "N/A", "cost_impact_per_vehicle": "N/A"}', '{"announced": "2026-05", "effective": "2026-01", "completion": ""}', '[{"url": "https://auto.economictimes.indiatimes.com/news/passenger-vehicle/hyundai-faces-stiff-competition-from-tata-motors-and-mahindra-in-2026-vehicle-sales/130743361", "claim": "Tata Motors and Mahindra are racing ahead of Hyundai in calendar 2026 vehicle sales, with homegrown carmakers maintaining a healthy lead through expanded portfolios", "source": "ET Auto, 04 May 2026"}]', '2026-05-05 10:20:34.765811+05:30', '2026-05-05 10:20:34.765811+05:30', 1); ON CONFLICT DO NOTHING;
INSERT INTO public.pestel_factors (id, code, name, category, selection_reasoning, likelihood, likelihood_reasoning, impact, impact_reasoning, origin_date, trend, time_horizon, segment_relevance, affected_pillars, source_ids, is_active, last_refreshed, created_at, updated_at, is_foundational, verification_verdict, verification_source, verification_evidence, financial_context, key_dates, citations, first_seen_date, last_confirmed_date, confirmation_count) VALUES (215, 'bajaj_auto_40%_export_growth_â€”_2w/cv_export_platfo', 'Bajaj Auto 40% Export Growth â€” 2W/CV Export Platform Demand Surge', 'E', 'Bajaj Auto''s 40% YoY total sales growth in April 2026, driven sharply by exports across both two-wheelers and commercial vehicles, signals India''s strengthening position as a global 2W and 3W export hub. For Tier-1 suppliers, this creates volume uplift and export-grade quality requirements, while also validating the India Cost Competitiveness advantage (10-25% vs Europe/LatAm) in a post-US tariff reduction environment. The 13% domestic April growth adds further volume confidence.', 9, 'Bajaj''s April 2026 sales data is confirmed at 5,13,792 total units (+40% YoY), making this a realised outcome rather than a forecast. Export demand from Africa, ASEAN, and Latin America for Indian 2W/3W has been structurally growing, supported by the US tariff reduction to 18% (Feb 2026) improving competitiveness.', 7, 'Bajaj Auto is India''s largest 2W/3W exporter; a sustained 40% export growth trajectory would require Tier-1 suppliers to scale capacity and meet export-grade specifications. This creates â‚¹1,500-2,500 Cr incremental component demand annually if sustained at even 20% growth. It also pressures suppliers to achieve IATF 16949 and export market regulatory compliance.', NULL, 'escalating', 'immediate', '{"2W": "H", "3W": "H", "HCV": "L", "LCV": "L", "4W_PV": "L", "Tractor": "L"}', '["Compute", "Infotainment", "Motion", "Energy"]', '{}', false, '2026-05-05 10:20:34.765811+05:30', '2026-05-05 10:20:34.765811+05:30', '2026-05-05 10:20:34.765811+05:30', false, 'UNVERIFIED', '', '', '{"market_opportunity": "India auto component exports $22.9B FY25 (ACMA); projected $70-100B by FY30 (McKinsey)", "industry_investment": "N/A", "subsidy_or_incentive": "US tariff reduced to 18% (Feb 2026) improving export economics; PLI scheme for auto components", "government_investment": "N/A", "cost_impact_per_vehicle": "N/A"}', '{"announced": "2026-05", "effective": "2026-04", "completion": ""}', '[{"url": "https://auto.economictimes.indiatimes.com/news/industry/bajaj-auto-reports-13-increase-in-april-2026-sales-driven-by-strong-export-demand/130755050", "claim": "Bajaj Auto reported total sales of 5,13,792 units in April 2026, registering a 40% year-on-year growth driven by a sharp rise in exports across both two-wheelers and commercial vehicles", "source": "ET Auto, 04 May 2026"}, {"url": "", "claim": "India''s auto component exports are projected to reach US$ 70-100 billion by FY30, driven by rising demand for EV technologies and global supply chain diversification", "source": "McKinsey report cited by IBEF Auto Sector, accessed 2026-05-05"}]', '2026-05-05 10:20:34.765811+05:30', '2026-05-05 10:20:34.765811+05:30', 1); ON CONFLICT DO NOTHING;
INSERT INTO public.pestel_factors (id, code, name, category, selection_reasoning, likelihood, likelihood_reasoning, impact, impact_reasoning, origin_date, trend, time_horizon, segment_relevance, affected_pillars, source_ids, is_active, last_refreshed, created_at, updated_at, is_foundational, verification_verdict, verification_source, verification_evidence, financial_context, key_dates, citations, first_seen_date, last_confirmed_date, confirmation_count) VALUES (216, '4w_ev_premiumisation_â€”_mass_market_ev_adoption_del', '4W EV Premiumisation â€” Mass-Market EV Adoption Delay Risk', 'S', 'The observed trend of EV adoption concentrating in the premium (above â‚¹10 lakh) segment while sub-â‚¹10 lakh car share declines signals a bifurcation in the 4W EV market. For Tier-1 suppliers, this means high-value ADAS, infotainment, and thermal management content per unit in the premium EV segment, but delayed volume scale for mass-market EV component standardisation. Luxury EV demand also drives different supplier qualification requirements versus mass-market.', 8, 'The premiumisation trend is confirmed by ET Auto''s May 2026 reporting and is consistent with the existing ''Premiumisation trend â€” Tier 2/3 city middle class upgrading'' factor. Battery pack prices at $110/kWh still make sub-â‚¹10L EVs margin-negative without subsidy, structurally sustaining this bifurcation through FY27.', 6, 'Premium EV concentration means higher per-unit content value (ADAS, thermal management, infotainment worth â‚¹80,000-1,50,000 per vehicle) but limits total addressable volume for mass-market component standardisation. This creates a two-speed supplier strategy requirement â€” premium-spec for current EV volumes, cost-optimised for future mass-market entry â€” increasing R&D and tooling complexity.', NULL, 'escalating', 'short', '{"2W": "L", "3W": "L", "HCV": "L", "LCV": "L", "4W_PV": "H", "Tractor": "L"}', '["Infotainment", "Motion", "ADAS", "Energy"]', '{}', false, '2026-05-05 10:20:34.765811+05:30', '2026-05-05 10:20:34.765811+05:30', '2026-05-05 10:20:34.765811+05:30', false, 'UNVERIFIED', '', '', '{"market_opportunity": "India 4W EV market: ~3% penetration (Vahan 2025); luxury EV segment growing strongly per ET Auto May 2026", "industry_investment": "N/A", "subsidy_or_incentive": "FAME III / PM E-DRIVE applicable primarily to commercial and 2W/3W EVs, not luxury 4W", "government_investment": "N/A", "cost_impact_per_vehicle": "Premium EV electronics content â‚¹80,000â€“1,50,000 per vehicle vs â‚¹25,000â€“40,000 for equivalent ICE"}', '{"announced": "2026-05", "effective": "2025-01", "completion": ""}', '[{"url": "https://auto.economictimes.indiatimes.com/news/passenger-vehicle/evs-moving-at-faster-speed-in-premium-lane/130743482", "claim": "The share of cars below â‚¹10 lakh has decreased while luxury EV demand is strong, suggesting the EV market is expanding upwards and potentially limiting mass adoption", "source": "ET Auto, 04 May 2026"}, {"url": "", "claim": "EV sales CY2025: 2.3 million units, approximately 8% of total; 4W EV share approximately 3%", "source": "Vahan Dashboard, cited in Industry Baseline FY2025"}]', '2026-05-05 10:20:34.765811+05:30', '2026-05-05 10:20:34.765811+05:30', 1); ON CONFLICT DO NOTHING;
INSERT INTO public.pestel_factors (id, code, name, category, selection_reasoning, likelihood, likelihood_reasoning, impact, impact_reasoning, origin_date, trend, time_horizon, segment_relevance, affected_pillars, source_ids, is_active, last_refreshed, created_at, updated_at, is_foundational, verification_verdict, verification_source, verification_evidence, financial_context, key_dates, citations, first_seen_date, last_confirmed_date, confirmation_count) VALUES (217, 'hsn_classification_ambiguity_â€”_battery_storage_sec', 'HSN Classification Ambiguity â€” Battery Storage Sector Cost Escalation', 'L', 'The HSN classification confusion for battery storage components raises direct compliance and cost risks for Tier-1 suppliers manufacturing or integrating battery packs, BMS, and energy storage systems. Unclear customs duty treatment and the absence of an approved manufacturer list create procurement uncertainty for EV powertrain and energy/charging pillar suppliers. The industry''s demand for tighter local content norms also signals potential localisation mandates that could affect import-dependent battery component supply chains.', 8, 'The HSN muddle is a current, active regulatory issue reported in May 2026, with industry formally seeking resolution. India''s GST and customs classification disputes have historically taken 12-24 months to resolve through CBIC circulars, making near-term cost uncertainty highly probable.', 6, 'Misclassification risks retrospective duty demands and compliance costs for battery storage suppliers. For Tier-1 EV powertrain suppliers, this could add 5-12% cost uncertainty on battery pack imports or sub-components pending HSN clarification. The 12-year project life context for storage projects amplifies long-term financial exposure.', NULL, 'new', 'immediate', '{"2W": "M", "3W": "M", "HCV": "M", "LCV": "M", "4W_PV": "M", "Tractor": "L"}', '["Energy"]', '{}', false, '2026-05-05 10:20:34.765811+05:30', '2026-05-05 10:20:34.765811+05:30', '2026-05-05 10:20:34.765811+05:30', false, 'UNVERIFIED', '', '', '{"market_opportunity": "India EV market $206B by 2030 (IBEF); battery storage sector directly linked", "industry_investment": "N/A", "subsidy_or_incentive": "Customs duty deferment under warehouse rules sought for 12-year storage project life; outcome pending", "government_investment": "N/A", "cost_impact_per_vehicle": "Estimate 5-12% cost uncertainty on battery pack sub-components pending HSN resolution"}', '{"announced": "2026-05", "effective": "2026-05", "completion": ""}', '[{"url": "https://auto.economictimes.indiatimes.com/news/auto-components/hsn-classification-muddle-raises-costs-for-battery-storage-sector/130744028", "claim": "The battery storage industry has sought separate HSN codes, an approved manufacturer list, tighter local content norms, and clarity on customs duty deferment under warehouse rules for the 12-year life of storage projects", "source": "ET Auto, 04 May 2026"}]', '2026-05-05 10:20:34.765811+05:30', '2026-05-05 10:20:34.765811+05:30', 1); ON CONFLICT DO NOTHING;
INSERT INTO public.pestel_factors (id, code, name, category, selection_reasoning, likelihood, likelihood_reasoning, impact, impact_reasoning, origin_date, trend, time_horizon, segment_relevance, affected_pillars, source_ids, is_active, last_refreshed, created_at, updated_at, is_foundational, verification_verdict, verification_source, verification_evidence, financial_context, key_dates, citations, first_seen_date, last_confirmed_date, confirmation_count) VALUES (218, 'end_of_life_vehicle_rule_4(6)_â€”_â‚¹25,000_cr_auto_in', 'End-of-Life Vehicle Rule 4(6) â€” â‚¹25,000 Cr Auto Industry Liability Risk', 'L', 'The â‚¹25,000 Cr potential financial impact on OEMs from Rule 4(6) of the end-of-life vehicle regulations represents a significant balance sheet risk that will cascade to supplier payment terms, capex prioritisation, and component specification changes. OEMs facing large contingent liabilities typically defer supplier development programmes, renegotiate payment cycles, and accelerate scrappage-linked aftermarket demand. The â‚¹14,623 Cr 4W impact and â‚¹9,650 Cr 2W/3W impact create differentiated pressure across segments.', 7, 'The rule exists and auditors have already flagged its implications, making the liability real rather than speculative. However, industry lobbying for rule amendment is active, and the government has historically provided relief on such provisions â€” reducing the probability of full â‚¹25,000 Cr crystallisation.', 8, 'A â‚¹25,000 Cr OEM-level liability directly constrains OEM capex and supplier development budgets. For Tier-1 suppliers, this translates into delayed new model programme investments, extended payment cycles, and potential demand volatility as OEMs manage cash flows. Simultaneously, accelerated scrappage creates aftermarket and retrofit component demand â€” a dual-effect factor.', NULL, 'new', 'immediate', '{"2W": "H", "3W": "H", "HCV": "M", "LCV": "M", "4W_PV": "H", "Tractor": "L"}', '["Services", "Motion", "Compute"]', '{}', 