INSERT INTO public.technologies (id, code, name, pillar, market_data, total_market_fy25_cr, total_market_fy30_cr, cagr, maturity, confidence, includes, source_ids, analysis_reasoning, is_active, last_refreshed, created_at, updated_at, source_note) VALUES (56, 'pressure_sensors_fluid', 'Fluid Pressure & Temperature Sensors', 'Actuators', '{"2W": {"cagr": 7.0, "fy25": 30, "fy30": 42}, "3W": 0, "HCV": {"cagr": 1.4, "fy25": 280, "fy30": 300}, "LCV": 76, "4W_PV": {"cagr": 2.0, "fy25": 380, "fy30": 420}, "Tractor": 160}', 820, 900, 1.9, 'mature', 'medium', 'Fuel rail pressure sensor, MAP sensor, coolant temperature sensor, oil pressure switch, brake fluid pressure sensor', '{1}', 'Core powertrain and chassis sensing â€” in every vehicle. Flat growth as ICE declines offset by EV TMS pressure sensing growth. Stable, high-volume business for Bosch India.', true, '2026-03-16 22:45:46.459223+05:30', '2026-03-16 22:45:46.459223+05:30', '2026-03-16 22:48:13.128634+05:30', 'Derived from MarketsandMarkets'); ON CONFLICT DO NOTHING;
