INSERT INTO public.technologies (id, code, name, pillar, market_data, total_market_fy25_cr, total_market_fy30_cr, cagr, maturity, confidence, includes, source_ids, analysis_reasoning, is_active, last_refreshed, created_at, updated_at, source_note) VALUES (57, 'ev_current_voltage_sensors', 'EV High-Voltage Current & Isolation Sensors', 'Semiconductors', '{"2W": {"cagr": 31.9, "fy25": 60, "fy30": 240}, "3W": {"cagr": 20.1, "fy25": 40, "fy30": 100}, "HCV": {"cagr": 34.1, "fy25": 14, "fy30": 61}, "LCV": 30, "4W_PV": {"cagr": 37.1, "fy25": 120, "fy30": 580}, "Tractor": 0}', 250, 1080, 34, 'growth', 'medium', 'Hall-effect HV current sensor, isolation monitoring (IMD), HV voltage transducer, SoC signal conditioning', '{1}', 'Every EV requires HV sensing for BMS, charger, and inverter. Critical safety function â€” isolation monitoring prevents electrocution. Growing directly with EV volumes. Bosch MEMS HV sensor entering India market 2026.', true, '2026-03-16 22:45:46.459223+05:30', '2026-03-16 22:45:46.459223+05:30', '2026-03-16 22:48:13.128634+05:30', 'Derived from MarketsandMarkets'); ON CONFLICT DO NOTHING;
