INSERT INTO public.technologies (id, code, name, pillar, market_data, total_market_fy25_cr, total_market_fy30_cr, cagr, maturity, confidence, includes, source_ids, analysis_reasoning, is_active, last_refreshed, created_at, updated_at, source_note) VALUES (22, 'battery_swapping_2w3w', 'Battery Swapping Networks (2W/3W)', 'Energy', '{"2W": {"cagr": 33.4, "fy25": 380, "fy30": 1600}, "3W": {"cagr": 25.3, "fy25": 220, "fy30": 680}, "HCV": 0, "LCV": 0, "4W_PV": 0, "Tractor": 0}', 600, 2280, 30.6, 'growth', 'medium', 'Swappable battery pack (standard form factor), swap station kiosk, BMS with SoH reporting, fleet management API', '{1}', 'Battery swapping is the dominant 2W/3W EV energy model in India (Gogoro, Sun Mobility, Ola). Government battery standardisation committee report 2025 recommends interoperability standard â€” Bosch BMS positioned as neutral supplier.', true, '2026-03-16 22:45:46.459223+05:30', '2026-03-16 22:45:46.459223+05:30', '2026-03-16 22:48:13.128634+05:30', 'Derived from Frost & Sullivan India'); ON CONFLICT DO NOTHING;
INSERT INTO public.technologies (id, code, name, pillar, market_data, total_market_fy25_cr, total_market_fy30_cr, cagr, maturity, confidence, includes, source_ids, analysis_reasoning, is_active, last_refreshed, created_at, updated_at, source_note) VALUES (4, 'dc_fast_charging', 'DC Fast Charging Infrastructure (â‰¥50kW)', 'Energy', '{"2W": 0, "3W": 0, "HCV": {"cagr": 49.6, "fy25": 60, "fy30": 450}, "LCV": 40, "4W_PV": {"cagr": 43.8, "fy25": 340, "fy30": 2100}, "Tractor": 0}', 440, 2830, 45, 'emerging', 'medium', 'Power electronics module, CCS2/CHAdeMO connectors, liquid cooling, OCPP 2.0 backend, payment gateway, grid interface', '{1}', 'India: ~12,000 DC chargers (2025) vs 100,000 target by 2030. FAME III funding 10,000 units. Highest CAGR in Bosch''s portfolio. Oil companies (HPCL, BPCL) deploying at scale from 2026.', true, '2026-03-16 21:29:57.576497+05:30', '2026-03-16 21:29:57.576497+05:30', '2026-03-16 22:48:13.128634+05:30', 'Derived from Frost & Sullivan India'); ON CONFLICT DO NOTHING;
