-- ============================================================
-- MIGRATION 011: Import local curated data (exported 2026-05-09)
-- Contains: 165 PESTEL factors, 73 techs, 72 competitors,
--           582 pillar shares, 1781 tech shares, 1460 OEM rows,
--           540 score history points, 20 sources
-- All INSERTs use ON CONFLICT DO NOTHING — safe to re-run.
-- ============================================================

-- Disable triggers to speed up bulk insert
SET session_replication_role = replica;
-- Clear any partial data inserted by seed scripts so this exact dataset loads cleanly
TRUNCATE TABLE oem_sourcing, competitor_tech_shares, competitor_pillar_shares, 
               pestel_score_history, competitors, technologies, pestel_factors, sources
               RESTART IDENTITY CASCADE;
-- Re-enable triggers
SET session_replication_role = DEFAULT;